import React, { useState, useEffect, useRef } from 'react';
import { useAuth, getBannerUrl } from '../hooks/useStore';
import { useNavigate, Link } from 'react-router-dom';
import UserAvatar from '../components/UserAvatar';
import { WalletIcon, CheckIcon } from '../components/Icons';
import PaymentMethodsModal from '../components/PaymentMethodsModal';

const SettingsPage: React.FC = () => {
  const { currentUser, changePassword, updateProfile } = useAuth();
  const navigate = useNavigate();

  // Modals State
  const [showPaymentModal, setShowPaymentModal] = useState(false);

  // State for password change
  const [oldPassword, setOldPassword] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [passwordMessage, setPasswordMessage] = useState({ type: '', text: '' });

  // State for profile settings
  const [iconUrl, setIconUrl] = useState('');
  const [bannerUrl, setBannerUrl] = useState('');
  const [bio, setBio] = useState('');
  const [profileMessage, setProfileMessage] = useState({ type: '', text: '' });
  const iconInputRef = useRef<HTMLInputElement>(null);
  const bannerInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (!currentUser) {
      navigate('/');
    } else {
        setIconUrl(currentUser.iconUrl || '');
        setBannerUrl(currentUser.bannerUrl || '');
        setBio(currentUser.bio || '');
    }
  }, [currentUser, navigate]);

  const handlePasswordSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setPasswordMessage({ type: '', text: '' });

    if (newPassword !== confirmPassword) {
      setPasswordMessage({ type: 'error', text: 'New passwords do not match.' });
      return;
    }

    if (newPassword.length < 6) {
      setPasswordMessage({ type: 'error', text: 'New password must be at least 6 characters long.' });
      return;
    }

    const result = changePassword(oldPassword, newPassword);
    setPasswordMessage({ type: result.success ? 'success' : 'error', text: result.message });
    if (result.success) {
      setOldPassword('');
      setNewPassword('');
      setConfirmPassword('');
    }
  };

   const handleProfileSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setProfileMessage({ type: '', text: '' });
    const result = updateProfile({ iconUrl, bannerUrl, bio });
    setProfileMessage({ type: result.success ? 'success' : 'error', text: result.message });
    setTimeout(() => setProfileMessage({ type: '', text: '' }), 4000);
  };

  const fileToDataUrl = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = () => resolve(reader.result as string);
        reader.onerror = reject;
        reader.readAsDataURL(file);
    });
  };

  const handleIconUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (!file.type.startsWith('image/')) {
        setProfileMessage({ type: 'error', text: 'Please select a valid image file.' });
        return;
      }
      try {
        const dataUrl = await fileToDataUrl(file);
        setIconUrl(dataUrl);
        setProfileMessage({ type: '', text: '' });
      } catch (error) {
        setProfileMessage({ type: 'error', text: 'Failed to read image file.' });
      }
    }
  };

  const handleBannerUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (!file.type.startsWith('image/')) {
        setProfileMessage({ type: 'error', text: 'Please select a valid image file.' });
        return;
      }
      try {
        const dataUrl = await fileToDataUrl(file);
        setBannerUrl(dataUrl);
        setProfileMessage({ type: '', text: '' });
      } catch (error) {
        setProfileMessage({ type: 'error', text: 'Failed to read image file.' });
      }
    }
  };

  if (!currentUser) {
      return null;
  }

  const previewBannerSrc = getBannerUrl({ id: currentUser.id, bannerUrl: bannerUrl });

  return (
    <div className="max-w-2xl mx-auto space-y-8 pb-12">
      <h1 className="text-2xl font-bold text-gray-900 pb-2 border-b border-gray-200">User Settings</h1>

      {/* Profile Settings Section */}
      <div className="bg-white p-6 rounded-md border border-gray-200">
        <h2 className="text-xl font-semibold text-gray-800 mb-4">Profile Settings</h2>
        <form onSubmit={handleProfileSubmit} className="space-y-4">
             {profileMessage.text && (
                <p className={`p-3 rounded-md text-sm ${profileMessage.type === 'success' ? 'bg-green-50 border border-green-200 text-green-700' : 'bg-red-50 border border-red-200 text-red-700'}`}>
                {profileMessage.text}
                </p>
            )}
            <div className="flex items-center gap-4">
                <UserAvatar user={{...currentUser, iconUrl}} className="w-16 h-16"/>
                <div className="flex-1">
                    <label className="block text-gray-600 mb-2 text-sm" htmlFor="icon-upload">Profile Icon</label>
                     <div className="flex items-center gap-2">
                        <button type="button" onClick={() => iconInputRef.current?.click()} className="px-4 py-2 text-sm font-semibold bg-gray-200 text-gray-700 rounded-full hover:bg-gray-300 transition-colors">
                        Upload Image
                        </button>
                        {iconUrl && <button type="button" onClick={() => setIconUrl('')} className="text-sm text-red-500 hover:underline">Remove</button>}
                    </div>
                    <input
                        type="file"
                        id="icon-upload"
                        ref={iconInputRef}
                        onChange={handleIconUpload}
                        accept="image/*"
                        className="hidden"
                    />
                </div>
            </div>
             <div>
                <label className="block text-gray-600 mb-2 text-sm" htmlFor="banner-upload">Banner Image</label>
                <div 
                    className="h-24 w-full rounded-md bg-gray-100 bg-cover bg-center mb-2"
                    style={{ backgroundImage: `url(${previewBannerSrc})` }}
                >
                    {!bannerUrl && <div className="flex items-center justify-center h-full text-sm text-white/80 bg-black/20 font-bold">Banner Preview</div>}
                </div>
                <div className="flex items-center gap-2">
                    <button type="button" onClick={() => bannerInputRef.current?.click()} className="px-4 py-2 text-sm font-semibold bg-gray-200 text-gray-700 rounded-full hover:bg-gray-300 transition-colors">
                        Upload Image
                    </button>
                    {bannerUrl && <button type="button" onClick={() => setBannerUrl('')} className="text-sm text-red-500 hover:underline">Remove</button>}
                </div>
                <input
                    type="file"
                    id="banner-upload"
                    ref={bannerInputRef}
                    onChange={handleBannerUpload}
                    accept="image/*"
                    className="hidden"
                />
            </div>
            <div>
                <label className="block text-gray-600 mb-2 text-sm" htmlFor="bio">Bio</label>
                <textarea
                    id="bio"
                    value={bio}
                    onChange={(e) => setBio(e.target.value)}
                    className="w-full bg-gray-50 border border-gray-300 rounded-md p-3 text-gray-900 focus:outline-none focus:ring-2 focus:ring-primary min-h-[100px] resize-y"
                    placeholder="Tell us a little about yourself..."
                    maxLength={300}
                />
                <p className="text-xs text-gray-500 mt-1 text-right">{bio.length}/300</p>
            </div>

            <div className="flex justify-end pt-4">
                <button type="submit" className="bg-primary text-white font-bold py-2 px-6 rounded-full hover:opacity-90 transition-opacity">
                    Save Profile
                </button>
            </div>
        </form>
      </div>

      {/* Wallet Management Section (Kopeki) */}
       <div className="bg-white p-8 rounded-md border border-gray-200 text-center relative overflow-hidden">
        <div className="flex items-center justify-between mb-8">
            <div className="flex items-center gap-3">
                <WalletIcon className="w-8 h-8 text-primary"/>
                <h2 className="text-2xl font-bold text-gray-900">Kopeki</h2>
            </div>
            <Link to="/settings/transactions" className="text-sm font-semibold text-primary hover:underline">
                View History
            </Link>
        </div>

        <div className="mb-10">
            <p className="text-sm text-gray-500 uppercase tracking-wide font-semibold mb-1">Current Balance</p>
            <div className="text-6xl font-extrabold text-gray-900 mb-2">
                {currentUser.kopeki.toLocaleString()}
            </div>
            <div className="inline-block bg-yellow-100 text-yellow-800 text-xs px-2 py-1 rounded font-bold">KOPEKI</div>
        </div>

        <div className="space-y-4 max-w-md mx-auto relative z-10">
             <Link 
                to="/wallet/deposit"
                className="w-full flex items-center justify-center gap-2 bg-green-500 hover:bg-green-600 text-white font-bold text-xl py-4 rounded-xl shadow-lg hover:shadow-xl transition-all active:scale-[0.98]"
             >
                 <span>Deposit Funds</span>
             </Link>
             <Link 
                to="/wallet/withdraw"
                className="w-full flex items-center justify-center gap-2 bg-gray-100 hover:bg-gray-200 text-gray-700 font-bold text-xl py-4 rounded-xl border border-gray-200 transition-all active:scale-[0.98]"
             >
                 <span>Withdraw Funds</span>
             </Link>
        </div>

        <div className="mt-8 pt-6 border-t border-gray-100 flex justify-center gap-6 text-sm">
             <button 
                onClick={() => setShowPaymentModal(true)}
                className="text-gray-500 hover:text-gray-800 font-medium"
             >
                 Manage Cards ({currentUser.savedCards?.length || 0})
             </button>
        </div>
      </div>

      <div className="bg-white p-6 rounded-md border border-gray-200">
        <h2 className="text-xl font-semibold text-gray-800 mb-4">Change Password</h2>
        <form onSubmit={handlePasswordSubmit} className="space-y-4">
          {passwordMessage.text && (
            <p className={`p-3 rounded-md text-sm ${passwordMessage.type === 'success' ? 'bg-green-50 border border-green-200 text-green-700' : 'bg-red-50 border border-red-200 text-red-700'}`}>
              {passwordMessage.text}
            </p>
          )}
          <div>
            <label className="block text-gray-600 mb-2" htmlFor="old-password">Old Password</label>
            <input
              type="password"
              id="old-password"
              value={oldPassword}
              onChange={(e) => setOldPassword(e.target.value)}
              className="w-full bg-gray-50 border border-gray-300 rounded-md p-3 text-gray-900 focus:outline-none focus:ring-2 focus:ring-primary"
              required
            />
          </div>
          <div>
            <label className="block text-gray-600 mb-2" htmlFor="new-password">New Password</label>
            <input
              type="password"
              id="new-password"
              value={newPassword}
              onChange={(e) => setNewPassword(e.target.value)}
              className="w-full bg-gray-50 border border-gray-300 rounded-md p-3 text-gray-900 focus:outline-none focus:ring-2 focus:ring-primary"
              required
            />
          </div>
          <div>
            <label className="block text-gray-600 mb-2" htmlFor="confirm-password">Confirm New Password</label>
            <input
              type="password"
              id="confirm-password"
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
              className="w-full bg-gray-50 border border-gray-300 rounded-md p-3 text-gray-900 focus:outline-none focus:ring-2 focus:ring-primary"
              required
            />
          </div>
          <div className="flex justify-end">
            <button type="submit" className="bg-primary text-white font-bold py-2 px-6 rounded-full hover:opacity-90 transition-opacity">
              Save Changes
            </button>
          </div>
        </form>
      </div>

      {showPaymentModal && <PaymentMethodsModal onClose={() => setShowPaymentModal(false)} />}
    </div>
  );
};

export default SettingsPage;

import React, { useState, useEffect, useRef } from 'react';
import { useAuth } from '../hooks/useStore';
import { CloseIcon, TrashIcon, LockIcon } from './Icons';

interface PaymentMethodsModalProps {
  onClose: () => void;
}

const PaymentMethodsModal: React.FC<PaymentMethodsModalProps> = ({ onClose }) => {
  const { currentUser, addCreditCard, removeCreditCard } = useAuth();
  const [stripe, setStripe] = useState<any>(null);
  const [elements, setElements] = useState<any>(null);
  const [cardElement, setCardElement] = useState<any>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });

  const cardContainerRef = useRef<HTMLDivElement>(null);

  // Initialize Stripe
  useEffect(() => {
    if ((window as any).Stripe) {
      // In a real app, use process.env.STRIPE_PUBLIC_KEY
      const stripeInstance = (window as any).Stripe('pk_test_51PqultFakeKey123456789');
      setStripe(stripeInstance);

      const elementsInstance = stripeInstance.elements({
        fonts: [{ cssSrc: 'https://fonts.googleapis.com/css?family=Inter' }]
      });
      setElements(elementsInstance);

      const card = elementsInstance.create('card', {
        style: {
          base: {
            color: '#1f2937',
            fontFamily: '"Inter", sans-serif',
            fontSmoothing: 'antialiased',
            fontSize: '16px',
            '::placeholder': { color: '#9ca3af' },
          },
          invalid: {
            color: '#ef4444',
            iconColor: '#ef4444',
          },
        },
      });

      setCardElement(card);
    }
  }, []);

  // Mount Card Element
  useEffect(() => {
    if (cardElement && cardContainerRef.current) {
        cardElement.mount(cardContainerRef.current);
    }
    return () => {
        if (cardElement) cardElement.unmount();
    };
  }, [cardElement]);

  const handleAddCard = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!stripe || !cardElement) return;

    setIsProcessing(true);
    setMessage({ type: '', text: '' });

    // In a real implementation, we would create a SetupIntent on the server first.
    // Here we simulate the Stripe PaymentMethod creation.
    const { paymentMethod, error } = await stripe.createPaymentMethod({
      type: 'card',
      card: cardElement,
      billing_details: {
          name: currentUser?.username,
      }
    });

    if (error) {
      setMessage({ type: 'error', text: error.message });
      setIsProcessing(false);
    } else {
      // Save sanitized details to our store
      const result = addCreditCard({
        last4: paymentMethod.card.last4,
        expiry: `${paymentMethod.card.exp_month}/${paymentMethod.card.exp_year.toString().slice(-2)}`,
        brand: paymentMethod.card.brand.charAt(0).toUpperCase() + paymentMethod.card.brand.slice(1)
      });

      setMessage({ type: 'success', text: 'Card securely added via Stripe!' });
      cardElement.clear();
      setIsProcessing(false);

      setTimeout(() => setMessage({ type: '', text: '' }), 3000);
    }
  };

  if (!currentUser) return null;

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-lg p-6 md:p-8 w-full max-w-md relative border border-gray-200 max-h-[90vh] overflow-y-auto shadow-2xl">
        <button onClick={onClose} className="absolute top-4 right-4 text-gray-400 hover:text-gray-700 transition-colors">
          <CloseIcon className="w-6 h-6" />
        </button>

        <h2 className="text-2xl font-bold text-gray-900 mb-6">Payment Methods</h2>

        <div className="mb-8 space-y-3">
            <h3 className="text-xs font-bold text-gray-500 uppercase tracking-wider">Saved Cards</h3>
            {currentUser.savedCards && currentUser.savedCards.length > 0 ? (
                currentUser.savedCards.map(card => (
                    <div key={card.id} className="flex justify-between items-center p-4 bg-gray-50 rounded-xl border border-gray-200 hover:border-gray-300 transition-colors">
                        <div className="flex items-center gap-4">
                            <div className="bg-white border border-gray-200 rounded-md px-2 py-1 shadow-sm">
                                <span className="text-[10px] font-black italic text-blue-800">{card.brand.toUpperCase()}</span>
                            </div>
                            <div>
                                <div className="text-sm font-bold text-gray-800">•••• {card.last4}</div>
                                <div className="text-[10px] text-gray-500 font-semibold uppercase tracking-tighter">Expires {card.expiry}</div>
                            </div>
                        </div>
                        <button onClick={() => removeCreditCard(card.id)} className="text-gray-400 hover:text-red-500 p-2 rounded-full hover:bg-red-50 transition-all">
                            <TrashIcon className="w-5 h-5"/>
                        </button>
                    </div>
                ))
            ) : (
                <div className="text-center py-6 border-2 border-dashed border-gray-100 rounded-xl">
                    <p className="text-sm text-gray-400 italic">No saved cards yet.</p>
                </div>
            )}
        </div>

        <form onSubmit={handleAddCard} className="border-t border-gray-100 pt-6">
             <div className="flex items-center justify-between mb-4">
                <h3 className="text-sm font-bold text-gray-800">Add New Card</h3>
                <div className="flex items-center gap-1 text-[10px] font-bold text-green-600 bg-green-50 px-2 py-0.5 rounded border border-green-100">
                    <LockIcon className="w-3 h-3" />
                    <span>STRIPE SECURE</span>
                </div>
             </div>

             {message.text && (
                <div className={`mb-4 p-3 rounded-lg text-sm font-medium ${message.type === 'success' ? 'bg-green-50 text-green-700 border border-green-200' : 'bg-red-50 text-red-700 border border-red-200'}`}>
                    {message.text}
                </div>
             )}

             <div className="space-y-4">
                  <div className="bg-gray-50 border border-gray-300 rounded-lg p-4 focus-within:ring-2 focus-within:ring-primary focus-within:border-primary transition-all">
                      <div ref={cardContainerRef} id="stripe-card-element">
                          {/* Stripe Element will be inserted here */}
                          {!stripe && <div className="h-5 bg-gray-200 animate-pulse rounded w-full"></div>}
                      </div>
                  </div>

                  <p className="text-[10px] text-gray-400 leading-relaxed">
                      Your card details are encrypted and sent directly to Stripe. We do not store your full card number or CVC on our servers.
                  </p>

                  <button 
                    type="submit" 
                    disabled={isProcessing || !stripe}
                    className="w-full bg-gray-900 text-white font-bold py-3 px-6 rounded-xl hover:bg-black transition-all shadow-lg active:scale-[0.98] disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                  >
                      {isProcessing ? (
                          <>
                            <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                            <span>Processing...</span>
                          </>
                      ) : (
                          <span>Save Card Securely</span>
                      )}
                  </button>
             </div>
        </form>
      </div>
    </div>
  );
};

export default PaymentMethodsModal;

import React, { useState, useEffect } from 'react';
import { useAuth } from '../hooks/useStore';
import { useNavigate, Link } from 'react-router-dom';
import { MastercardIcon, CheckIcon, WalletIcon } from '../components/Icons';
import PaymentMethodsModal from '../components/PaymentMethodsModal';

const DepositPage: React.FC = () => {
  const { currentUser, buyKopeki } = useAuth();
  const navigate = useNavigate();

  const [selectedCardId, setSelectedCardId] = useState('');
  const [amountKopeki, setAmountKopeki] = useState('');
  const [showPaymentMethodsModal, setShowPaymentMethodsModal] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });
  const [isProcessing, setIsProcessing] = useState(false);

  useEffect(() => {
      if (!currentUser) {
          navigate('/');
          return;
      }
      if (currentUser.savedCards && currentUser.savedCards.length > 0) {
          setSelectedCardId(currentUser.savedCards[0].id);
      }
  }, [currentUser, navigate]);

  const selectedCard = currentUser?.savedCards?.find(c => c.id === selectedCardId);

  const handleAmountPreset = (amount: number) => {
      setAmountKopeki(amount.toString());
  };

  const handleDeposit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedCardId) {
        setMessage({ type: 'error', text: 'Please select a payment method.' });
        return;
    }

    const kopeki = parseInt(amountKopeki, 10);
    if (isNaN(kopeki) || kopeki <= 0) {
        setMessage({ type: 'error', text: 'Please enter a valid positive integer.' });
        return;
    }

    setIsProcessing(true);

    // Calculate EUR for display message
    const eurCost = kopeki / 10000;

    setTimeout(() => {
        const result = buyKopeki(kopeki);
        setIsProcessing(false);
        if (result.success) {
            setMessage({ type: 'success', text: `Successfully deposited ${kopeki.toLocaleString()} Kopeki (€${eurCost.toFixed(2)})` });
            setAmountKopeki('');
            setTimeout(() => navigate('/settings'), 2000);
        } else {
            setMessage({ type: 'error', text: result.message });
        }
    }, 1000); // Simulate network delay
  };

  if (!currentUser) return null;

  return (
    <div className="container mx-auto p-4 md:p-6 max-w-5xl">
      <Link to="/settings" className="text-gray-500 hover:text-gray-900 mb-6 inline-block font-medium">&larr; Back to Wallet</Link>

      <div className="flex flex-col md:flex-row gap-6">
        {/* Left Column - Payment Method */}
        <div className="w-full md:w-1/3 space-y-4">
            <div className="bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden">
                <div className="bg-gray-100 px-4 py-3 border-b border-gray-200 flex justify-between items-center">
                    <h2 className="font-bold text-gray-800">Metodo di pagamento</h2>
                    <button 
                        type="button" 
                        onClick={() => setShowPaymentMethodsModal(true)} 
                        className="text-primary text-sm font-semibold hover:underline"
                    >
                        + Aggiungi Metodo
                    </button>
                </div>

                <div className="p-6 flex flex-col items-center">
                    {selectedCard ? (
                        <div className="relative w-full aspect-[1.586] bg-gray-900 rounded-xl p-5 text-white shadow-lg mb-6">
                             <div className="absolute top-4 right-4 opacity-50">
                                <div className="w-8 h-5 border border-gray-500 rounded flex items-center justify-center">
                                    <div className="w-6 h-3 border border-gray-500 rounded-sm"></div>
                                </div>
                             </div>

                             <div className="h-full flex flex-col justify-between">
                                 <MastercardIcon className="w-12 h-12 mt-2" />
                                 <div>
                                     <div className="text-lg tracking-widest font-mono mb-1">
                                         **** **** **** {selectedCard.last4}
                                     </div>
                                     <div className="text-xs text-gray-400">
                                         Scad. {selectedCard.expiry}
                                     </div>
                                 </div>
                             </div>

                             <div className="absolute -top-2 -right-2 bg-white rounded-full p-1 shadow-sm border border-gray-200">
                                 <div className="bg-gray-200 rounded-full p-0.5">
                                    <div className="w-4 h-4 rounded-full bg-white flex items-center justify-center">
                                        <span className="text-gray-400 text-xs">...</span>
                                    </div>
                                 </div>
                             </div>
                        </div>
                    ) : (
                         <div className="w-full aspect-[1.586] bg-gray-100 rounded-xl border-2 border-dashed border-gray-300 flex flex-col items-center justify-center text-gray-500 mb-6">
                             <p className="text-sm font-medium">No card selected</p>
                             <button onClick={() => setShowPaymentMethodsModal(true)} className="text-primary text-sm underline mt-1">Add Card</button>
                         </div>
                    )}

                    <div className="w-full bg-white border border-gray-200 rounded-lg overflow-hidden">
                        <div className="px-4 py-3 bg-gray-50 border-b border-gray-200 flex justify-between items-center cursor-pointer">
                            <span className="font-semibold text-gray-700 text-sm">I miei metodi di pagamento</span>
                            <span className="text-gray-400">^</span>
                        </div>
                        <div className="max-h-40 overflow-y-auto">
                             {currentUser.savedCards && currentUser.savedCards.length > 0 ? (
                                 currentUser.savedCards.map(card => (
                                     <button 
                                        key={card.id}
                                        onClick={() => setSelectedCardId(card.id)}
