interface CreateBoardModalProps {
  onClose: () => void;
}

const CreateBoardModal: React.FC<CreateBoardModalProps> = ({ onClose }) => {
  const navigate = useNavigate();
  const { createBoard } = useData();
  const [step, setStep] = useState(1);
  const [error, setError] = useState('');
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [iconUrl, setIconUrl] = useState('');
  const [bannerUrl, setBannerUrl] = useState('');
  const [accessType, setAccessType] = useState<'public' | 'password' | 'invite'>('public');
  const [password, setPassword] = useState('');
  const [allowAnonymousComments, setAllowAnonymousComments] = useState(true);
  const [allowAnonymousPosts, setAllowAnonymousPosts] = useState(true);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const { success, message } = createBoard(name.trim(), description.trim(), allowAnonymousComments, allowAnonymousPosts, accessType === 'password' ? password : undefined, accessType === 'invite', iconUrl, bannerUrl);
    if (success) {
      navigate(`/b/${name.trim()}`);
      onClose();
    } else setError(message);
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
      <div className="bg-white rounded-lg p-8 w-full max-w-md relative border border-gray-200">
