        <h2 className="text-2xl font-bold text-gray-900 text-center mb-1">Create Board</h2>
        <form onSubmit={step === 3 ? handleSubmit : (e) => { e.preventDefault(); setStep(s => s + 1); }}>
            {step === 1 && <div className="space-y-4"><input type="text" value={name} onChange={e => setName(e.target.value)} className="w-full border p-3 rounded" placeholder="Board Name" required /></div>}
            {step === 2 && <div className="space-y-4"><textarea value={description} onChange={e => setDescription(e.target.value)} className="w-full border p-3 rounded" placeholder="Description" /></div>}
            {step === 3 && (
                <div className="space-y-4">
                    <select value={accessType} onChange={e => setAccessType(e.target.value as any)} className="w-full border p-3 rounded">
                        <option value="public">Public</option>
                        <option value="password">Password</option>
                        <option value="invite">Invite Only</option>
                    </select>
                </div>
            )}
            <div className="flex justify-between mt-6">
                {step > 1 && <button type="button" onClick={() => setStep(s => s - 1)} className="text-gray-500">Back</button>}
                <button type="submit" className="bg-primary text-white font-bold py-2 px-6 rounded-full ml-auto">{step === 3 ? 'Create' : 'Next'}</button>
            </div>
        </form>
      </div>
    </div>
  );
};

