import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import type { ProfilePost } from '../types';
import { useAuth, useData, getFlagUrl, timeAgo } from '../hooks/useStore';
import { CommentIcon, ThumbsDownIcon, HeartIcon, ReportIcon, GiftIcon, WalletIcon } from './Icons';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import rehypeRaw from 'rehype-raw';
import UserAvatar from './UserAvatar';
import ReportModal from './ReportModal';
import PostMedia from './PostMedia';
import AwardModal from './AwardModal';
import { AVAILABLE_AWARDS } from './Awards';
import AuthModal from './AuthModal';

interface ProfilePostCardProps {
  post: ProfilePost;
  isFullView?: boolean;
}

const ProfilePostCard: React.FC<ProfilePostCardProps> = ({ post, isFullView = false }) => {
  const { getUserById, currentUser } = useAuth();
  // Fixed missing awards and unlockProfilePost from useData
  const { comments, deleteProfilePost, votes, castVote, awards, unlockProfilePost } = useData();
  const [isReportModalOpen, setReportModalOpen] = useState(false);
  const [isAwardModalOpen, setAwardModalOpen] = useState(false);
  const [isAuthModalOpen, setAuthModalOpen] = useState(false);
  const [unlockError, setUnlockError] = useState('');

  const author = getUserById(post.authorId);
  const commentCount = comments.filter(c => c.postId === post.id).length;
  const canModerate = currentUser && currentUser.id === post.authorId;
  const entityVotes = votes.filter((v) => v.entityId === post.id);
  const score = entityVotes.reduce((acc, vote) => acc + (vote.type === 'up' ? 1 : -1), 0);
  const userVote = currentUser ? entityVotes.find((v) => v.userId === currentUser.id) : undefined;

  const postAwards = awards.filter(a => a.entityId === post.id);
  const groupedAwards = postAwards.reduce((acc, award) => { acc[award.typeId] = (acc[award.typeId] || 0) + 1; return acc; }, {} as Record<string, number>);
  // Fixed ProfilePost property access for price and unlockedUserIds
  const isLocked = !!(post.price && post.price > 0 && currentUser?.id !== post.authorId && !post.unlockedUserIds?.includes(currentUser?.id || ''));

  const handleVote = (type: 'up' | 'down') => { if (currentUser) castVote(post.id, type); else setAuthModalOpen(true); };
  const handleDelete = () => { if (window.confirm('Delete this?')) deleteProfilePost(post.id); };
  const handleUnlock = () => {
      if (!currentUser) return setAuthModalOpen(true);
      const result = unlockProfilePost(post.id);
      if (!result.success) { setUnlockError(result.message); setTimeout(() => setUnlockError(''), 3000); }
  }

  const postLink = author ? `/u/${author.username}/post/${post.id}` : '#';

  return (
    <article className="bg-white border border-gray-200 rounded-md hover:border-gray-300 transition-colors duration-200">
      <div className="p-3 overflow-hidden relative">
         <div className="absolute top-2 right-2 flex items-center gap-1 z-10">
            <button onClick={() => setReportModalOpen(true)} className="p-1 rounded-sm text-gray-400 hover:text-yellow-500"><ReportIcon className="w-4 h-4" /></button>
            {!isLocked && <button onClick={() => handleVote('down')} className={`p-1 rounded-sm transition-colors ${userVote?.type === 'down' ? 'text-blue-600 bg-blue-50' : 'text-gray-400 hover:text-blue-500 hover:bg-blue-50'}`}><ThumbsDownIcon className="w-4 h-4" /></button>}
         </div>

        <div className="flex items-center text-sm text-gray-500 mb-2 pr-8">
          {author?.countryCode && <img src={getFlagUrl(author.countryCode)} alt={author.countryCode} className="w-5 h-auto rounded-sm shadow-sm mr-2" />}
          <UserAvatar user={author} className="w-5 h-5 mr-2" />
          <span>Posted by {author ? <Link to={`/u/${author.username}`} className="hover:underline text-gray-800 font-bold">u/{author.username}</Link> : 'u/unknown'}</span>
          <span className="mx-1">•</span>
          <span>{timeAgo(post.createdAt)}</span>
          {/* Fixed price access */}
          {post.price && post.price > 0 && <span className="ml-2 bg-yellow-100 text-yellow-800 text-xs px-2 py-0.5 rounded-full font-bold flex items-center gap-1"><WalletIcon className="w-3 h-3" />{post.price} K</span>}
        </div>

        {Object.keys(groupedAwards).length > 0 && (
            <div className="flex flex-wrap gap-1 mb-2">
                {Object.entries(groupedAwards).map(([awardId, count]) => {
                    const awardDef = AVAILABLE_AWARDS.find(a => a.id === awardId); if (!awardDef) return null;
                    return <div key={awardId} className="flex items-center bg-gray-100 rounded-full px-2 py-0.5 border border-gray-200" title={awardDef.label}><div className={`w-4 h-4 mr-1 ${awardDef.color}`}><awardDef.icon /></div>{(count as number) > 1 && <span className="text-xs font-bold text-gray-600">{count as number}</span>}</div>;
                })}
            </div>
        )}

        <Link to={postLink}><h2 className="text-xl font-semibold text-gray-800 mb-1 hover:text-primary transition-colors pr-8">{post.title}</h2></Link>

        {isLocked ? (
             <div className="mt-4 p-8 bg-gray-100 rounded-lg border border-gray-200 flex flex-col items-center justify-center text-center relative overflow-hidden">
                 <div className="absolute inset-0 bg-gradient-to-br from-yellow-50 to-orange-50 opacity-50"></div>
                 <div className="relative z-10">
                     <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center mx-auto mb-4 shadow-sm text-yellow-500"><svg xmlns="http://www.w3.org/2000/svg" className="w-8 h-8" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect x="3" y="11" width="18" height="11" rx="2" ry="2"></rect><path d="M7 11V7a5 5 0 0 1 10 0v4"></path></svg></div>
                     <h3 className="text-lg font-bold text-gray-800 mb-1">Exclusive Content</h3>
                     <p className="text-gray-600 mb-4 text-sm">Unlock this post to see the full content and media.</p>
                     {/* Fixed price access */}
                     <button onClick={handleUnlock} className="bg-yellow-500 hover:bg-yellow-600 text-white font-bold py-2 px-6 rounded-full shadow-md flex items-center gap-2 transition-transform active:scale-95 mx-auto"><span>Unlock for {post.price} K</span></button>
                     {unlockError && <p className="text-red-500 text-xs mt-2 font-semibold">{unlockError}</p>}
                     {!currentUser && <p className="text-xs text-gray-500 mt-3">You must be logged in to unlock.</p>}
                 </div>
             </div>
        ) : (
            <>
                <div className={`mt-1 prose max-w-none prose-p:my-2 ${!isFullView ? 'max-h-32 overflow-hidden mask-gradient' : ''}`}>
                    <ReactMarkdown remarkPlugins={[remarkGfm]} rehypePlugins={[rehypeRaw]}>{post.content}</ReactMarkdown>
                </div>
                {post.media && post.media.length > 0 && <PostMedia media={post.media} postLink={!isFullView ? postLink : undefined} />}
            </>
        )}

        {!isLocked && (
            <div className="mt-3 flex items-center gap-4">
                <div className="flex items-center gap-1.5">
                <button 
                    onClick={() => handleVote('up')} 
                    className={`p-1 rounded-sm transition-colors ${userVote?.type === 'up' ? 'text-red-600 bg-red-50' : 'text-gray-500 hover:text-red-600 hover:bg-red-50'}`}
                >
                    <HeartIcon className={`w-4 h-4 ${userVote?.type === 'up' ? 'fill-current' : ''}`} />
                </button>
                <span className={`text-sm font-semibold ${userVote?.type === 'up' ? 'text-red-600' : 'text-gray-600'}`}>{score}</span>
            </div>
            <Link to={postLink} className="flex items-center gap-2 text-gray-500 hover:bg-gray-100 px-3 py-1 rounded-md text-sm font-semibold w-fit">
                <CommentIcon className="w-4 h-4" /><span>{commentCount} Comments</span>
            </Link>
            {currentUser && author && currentUser.id !== author.id && (
                <button onClick={() => setAwardModalOpen(true)} className="flex items-center gap-2 text-gray-500 hover:bg-gray-100 hover:text-yellow-600 px-3 py-1 rounded-md text-sm font-semibold w-fit transition-colors"><GiftIcon className="w-4 h-4" /><span className="hidden sm:inline">Award</span></button>
            )}
            {canModerate && <Link to={`${postLink}/edit`} className="text-sm font-semibold text-blue-500 hover:bg-blue-50 px-3 py-1 rounded-md">Edit</Link>}
            {canModerate && <button onClick={handleDelete} className="text-sm font-semibold text-red-500 hover:bg-red-50 px-3 py-1 rounded-md">Delete</button>}
            </div>
        )}
      </div>
      {isReportModalOpen && <ReportModal entityId={post.id} entityType="post" onClose={() => setReportModalOpen(false)} />}
      {isAwardModalOpen && post.authorId && <AwardModal entityId={post.id} entityType="post" receiverId={post.authorId} onClose={() => setAwardModalOpen(false)} />}
      {isAuthModalOpen && <AuthModal onClose={() => setAuthModalOpen(false)} />}
       <style>{`.mask-gradient { mask-image: linear-gradient(to bottom, black 60%, transparent 100%); -webkit-mask-image: linear-gradient(to bottom, black 60%, transparent 100%); }`}</style>
    </article>
  );
};

export default ProfilePostCard;

import React, { useMemo } from 'react';
import type { Message as MessageType, User } from '../types';
import UserAvatar from './UserAvatar';
import PostMedia from './PostMedia';
import { WalletIcon, LockIcon, CheckIcon, CloseIcon } from './Icons';
import { mockDecrypt, useData } from '../hooks/useStore';

interface MessageProps {
    message: MessageType;
    author: User | undefined;
    isCurrentUser: boolean;
}

const Message: React.FC<MessageProps> = ({ message, author, isCurrentUser }) => {
    const { respondToBoardInvite } = useData();
    const alignment = isCurrentUser ? 'justify-end' : 'justify-start';
    const isNotification = message.type === 'notification';
    const bubbleColor = isNotification 
        ? 'bg-blue-50 border border-blue-200 text-blue-900' 
        : isCurrentUser 
            ? 'bg-primary text-white' 
            : 'bg-gray-200 text-gray-800';

    const hasMedia = message.media && message.media.length > 0;
    // Fixed kopekiAmount access
    const hasKopeki = !!(message.kopekiAmount && message.kopekiAmount > 0);
    const isInvite = message.type === 'board_invite';

    const displayContent = useMemo(() => {
        if (message.isEncrypted && message.content) {
            return mockDecrypt(message.content);
        }
        return message.content;
    }, [message.content, message.isEncrypted]);

    const handleAccept = () => {
        if (!isCurrentUser) { 
            respondToBoardInvite(message.id, 'accept');
        }
    };

    const handleReject = () => {
        if (!isCurrentUser) {
            respondToBoardInvite(message.id, 'reject');
        }
    };

    return (
        <div className={`flex items-end gap-2 ${alignment}`}>
            {!isCurrentUser && !isNotification && <UserAvatar user={author} className="w-6 h-6 mb-1" />}
            <div className={`rounded-lg max-w-sm md:max-w-md overflow-hidden ${bubbleColor} ${hasMedia || isInvite ? 'p-1' : 'px-3 py-2'} ${isNotification ? 'w-full max-w-none text-center text-sm py-1' : ''}`}>

                {/* Notification Banner */}
                {isNotification && (
                    <div className="flex items-center justify-center gap-2">
                        <span className="font-semibold">🔔 Notification:</span>
                        <span>{displayContent}</span>
                    </div>
                )}

                {/* Board Invite Card */}
                {!isNotification && isInvite && message.metadata && (
                    <div className="bg-white rounded p-3 text-gray-800 shadow-sm border border-gray-200 m-1">
                        <p className="font-bold text-sm mb-1">Invitation</p>
                        <p className="text-sm mb-3">You have been invited to join <span className="font-bold text-primary">b/{message.metadata.boardName}</span></p>

                        {!isCurrentUser && message.metadata.inviteStatus === 'pending' && (
                            <div className="flex gap-2">
                                <button onClick={handleAccept} className="flex-1 bg-green-600 text-white text-xs font-bold py-2 rounded hover:bg-green-700 flex items-center justify-center gap-1">
                                    <CheckIcon className="w-3 h-3" /> Accept
                                </button>
                                <button onClick={handleReject} className="flex-1 bg-red-100 text-red-600 text-xs font-bold py-2 rounded hover:bg-red-200 flex items-center justify-center gap-1">
                                    <CloseIcon className="w-3 h-3" /> Decline
                                </button>
                            </div>
                        )}
                        {message.metadata.inviteStatus === 'accepted' && (
                            <div className="bg-green-50 text-green-700 text-xs font-bold py-2 rounded text-center border border-green-200">
                                ✅ Invitation Accepted
                            </div>
                        )}
                        {message.metadata.inviteStatus === 'rejected' && (
                            <div className="bg-gray-100 text-gray-500 text-xs font-bold py-2 rounded text-center border border-gray-200">
                                ❌ Invitation Declined
                            </div>
                        )}
                        {isCurrentUser && (
                            <div className="text-xs text-gray-500 text-center italic mt-2">
                                You sent an invitation. Status: {message.metadata.inviteStatus}
                            </div>
                        )}
                    </div>
                )}

                {/* Kopeki Transfer */}
                {!isNotification && hasKopeki && (
                     <div className={`flex items-center justify-between ${hasMedia ? 'px-2 py-1' : 'mb-1'}`}>
                         <div className="flex items-center gap-2">
                             <WalletIcon className="w-5 h-5" />
                             {/* Fixed kopekiAmount access */}
                             <span className="font-bold text-lg">{message.kopekiAmount?.toLocaleString()} K</span>
                         </div>
                     </div>
                )}

                {/* Media */}
                {!isNotification && hasMedia && (
                    <div className="mb-1">
                        <PostMedia media={message.media!} compact={true} />
                    </div>
                )}

                {/* Text Content (if not special type) */}
                {!isNotification && !isInvite && displayContent && (
                    <div className={`flex items-end gap-2 ${hasMedia ? 'px-2 pb-2 pt-1' : ''}`}>
                        <p className="text-sm" style={{ whiteSpace: 'pre-wrap', wordWrap: 'break-word' }}>
                            {displayContent}
                        </p>
                        {message.isEncrypted && (
                            <div className="mb-0.5" title="End-to-End Encrypted">
                                <LockIcon className={`w-3 h-3 ${isCurrentUser ? 'text-white/70' : 'text-gray-500'}`} />
                            </div>
                        )}
                    </div>
                )}
            </div>
        </div>
    );
};

export default Message;

import React, { useState, useEffect, useRef } from 'react';
import { useAuth } from '../hooks/useStore';
import { CloseIcon, TrashIcon, LockIcon } from './Icons';

interface PaymentMethodsModalProps {
  onClose: () => void;
}

const PaymentMethodsModal: React.FC<PaymentMethodsModalProps> = ({ onClose }) => {
  // Fixed missing methods from useAuth
  const { currentUser, addCreditCard, removeCreditCard } = useAuth();
  const [stripe, setStripe] = useState<any>(null);
  const [elements, setElements] = useState<any>(null);

  // Refs for mounting individual elements
  const cardNumberRef = useRef<HTMLDivElement>(null);
  const cardExpiryRef = useRef<HTMLDivElement>(null);
  const cardCvcRef = useRef<HTMLDivElement>(null);

  // States for individual elements
  const [cardNumberEl, setCardNumberEl] = useState<any>(null);
  const [cardExpiryEl, setCardExpiryEl] = useState<any>(null);
  const [cardCvcEl, setCardCvcEl] = useState<any>(null);

  const [isProcessing, setIsProcessing] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });

  // Shared styles for Stripe Elements
  const elementStyles = {
    style: {
      base: {
        color: '#1f2937',
        fontFamily: '"Inter", sans-serif',
        fontSmoothing: 'antialiased',
        fontSize: '16px',
        '::placeholder': { color: '#9ca3af' },
      },
      invalid: {
        color: '#ef4444',
        iconColor: '#ef4444',
      },
    },
  };

  useEffect(() => {
    if ((window as any).Stripe) {
      const stripeInstance = (window as any).Stripe('pk_test_51SLiceAp4OGbPA6SOa3r6wUFPX5TQNHNctdVBfU8eqLg1qjRw7CKPChQOYHetwFWbtwCUBgfQGIJKPmtjzqMtzDU00lQ0PKUUA');
      setStripe(stripeInstance);

      const elementsInstance = stripeInstance.elements();
      setElements(elementsInstance);

      // Create individual elements
      const num = elementsInstance.create('cardNumber', { ...elementStyles, showIcon: true });
      const exp = elementsInstance.create('cardExpiry', elementStyles);
      const cvc = elementsInstance.create('cardCvc', elementStyles);

      setCardNumberEl(num);
      setCardExpiryEl(exp);
      setCardCvcEl(cvc);
    }
  }, []);

  // Mount elements when they are created and refs are ready
  useEffect(() => {
    if (cardNumberEl && cardNumberRef.current) cardNumberEl.mount(cardNumberRef.current);
    if (cardExpiryEl && cardExpiryRef.current) cardExpiryEl.mount(cardExpiryRef.current);
    if (cardCvcEl && cardCvcRef.current) cardCvcEl.mount(cardCvcRef.current);

    return () => {
      if (cardNumberEl) cardNumberEl.unmount();
      if (cardExpiryEl) cardExpiryEl.unmount();
      if (cardCvcEl) cardCvcEl.unmount();
    };
  }, [cardNumberEl, cardExpiryEl, cardCvcEl]);

  const handleAddCard = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!stripe || !cardNumberEl) return;

    setIsProcessing(true);
    setMessage({ type: '', text: '' });

    // Stripe's createPaymentMethod handles multiple elements automatically if they belong to the same 'elements' instance
    const { paymentMethod, error } = await stripe.createPaymentMethod({
      type: 'card',
      card: cardNumberEl, // Pass the cardNumber element, Stripe finds the others
      billing_details: {
          name: currentUser?.username,
      }
    });

    if (error) {
      setMessage({ type: 'error', text: error.message });
      setIsProcessing(false);
    } else {
      addCreditCard({
        last4: paymentMethod.card.last4,
        expiry: `${paymentMethod.card.exp_month}/${paymentMethod.card.exp_year.toString().slice(-2)}`,
        brand: paymentMethod.card.brand.charAt(0).toUpperCase() + paymentMethod.card.brand.slice(1)
      });

      setMessage({ type: 'success', text: 'Card securely added!' });

      // Clear all fields
      cardNumberEl.clear();
      cardExpiryEl.clear();
      cardCvcEl.clear();

      setIsProcessing(false);
      setTimeout(() => setMessage({ type: '', text: '' }), 3000);
    }
  };

  if (!currentUser) return null;

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-[100] p-4">
      <div className="bg-white rounded-2xl w-full max-w-md relative border border-gray-200 max-h-[95vh] overflow-y-auto shadow-2xl animate-in fade-in zoom-in duration-200">
        <button onClick={onClose} className="absolute top-5 right-5 text-gray-400 hover:text-gray-700 transition-colors p-1 rounded-full hover:bg-gray-100">
          <CloseIcon className="w-6 h-6" />
        </button>

        <div className="p-8">
            <h2 className="text-2xl font-black text-gray-900 mb-2">Wallet Settings</h2>
            <p className="text-sm text-gray-500 mb-8">Manage your payment methods securely.</p>

            {/* Existing Cards Section */}
            <div className="mb-10 space-y-4">
                <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest">Your Saved Cards</h3>
                {/* Fixed savedCards access */}
                {currentUser.savedCards && currentUser.savedCards.length > 0 ? (
                    currentUser.savedCards.map(card => (
                        <div key={card.id} className="flex justify-between items-center p-4 bg-gray-50 rounded-xl border border-gray-100 hover:border-primary/20 hover:bg-white transition-all group shadow-sm hover:shadow-md">
                            <div className="flex items-center gap-4">
                                <div className="bg-white border border-gray-200 rounded-lg px-3 py-1.5 shadow-sm group-hover:border-primary/30">
                                    <span className="text-[11px] font-black italic text-blue-900">{card.brand.toUpperCase()}</span>
                                </div>
                                <div>
                                    <div className="text-sm font-bold text-gray-900 tracking-tight">•••• •••• •••• {card.last4}</div>
                                    <div className="text-[10px] text-gray-400 font-bold uppercase">Exp. {card.expiry}</div>
                                </div>
                            </div>
                            <button onClick={() => removeCreditCard(card.id)} className="text-gray-300 hover:text-red-500 p-2 rounded-full hover:bg-red-50 transition-all opacity-0 group-hover:opacity-100">
                                <TrashIcon className="w-5 h-5"/>
                            </button>
                        </div>
                    ))
                ) : (
                    <div className="text-center py-10 border-2 border-dashed border-gray-100 rounded-2xl bg-gray-50/30">
                        <p className="text-sm text-gray-400 italic">No cards added yet.</p>
                    </div>
                )}
            </div>

            {/* Add New Card Section */}
            <form onSubmit={handleAddCard} className="pt-8 border-t border-gray-100">
                <div className="flex items-center justify-between mb-6">
                    <h3 className="text-sm font-bold text-gray-900">Add New Card</h3>
                    <div className="flex items-center gap-1.5 text-[10px] font-black text-green-600 bg-green-50 px-2 py-1 rounded-md border border-green-100">
                        <LockIcon className="w-3.5 h-3.5" />
                        <span className="uppercase tracking-tighter">Stripe Encrypted</span>
                    </div>
                </div>

                {message.text && (
                    <div className={`mb-6 p-4 rounded-xl text-sm font-bold animate-in slide-in-from-top-2 duration-300 ${message.type === 'success' ? 'bg-green-50 text-green-800 border border-green-200' : 'bg-red-50 text-red-800 border border-red-200'}`}>
                        {message.text}
                    </div>
                )}

                <div className="space-y-5">
                    {/* Card Number */}
                    <div className="space-y-1.5">
                        <label className="text-[11px] font-bold text-gray-500 uppercase ml-1">Card Number</label>
                        <div className="bg-gray-50 border border-gray-200 rounded-xl p-4 focus-within:ring-2 focus-within:ring-primary/20 focus-within:border-primary focus-within:bg-white transition-all shadow-sm">
                            <div ref={cardNumberRef}>
                                {!stripe && <div className="h-5 bg-gray-200 animate-pulse rounded w-full"></div>}
                            </div>
                        </div>
                    </div>

                    {/* Expiry and CVC Row */}
                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-1.5">
                            <label className="text-[11px] font-bold text-gray-500 uppercase ml-1">Expiry Date</label>
                            <div className="bg-gray-50 border border-gray-200 rounded-xl p-4 focus-within:ring-2 focus-within:ring-primary/20 focus-within:border-primary focus-within:bg-white transition-all shadow-sm">
                                <div ref={cardExpiryRef}>
                                    {!stripe && <div className="h-5 bg-gray-200 animate-pulse rounded w-full"></div>}
                                </div>
                            </div>
                        </div>
                        <div className="space-y-1.5">
                            <label className="text-[11px] font-bold text-gray-500 uppercase ml-1">CVC / CVV</label>
                            <div className="bg-gray-50 border border-gray-200 rounded-xl p-4 focus-within:ring-2 focus-within:ring-primary/20 focus-within:border-primary focus-within:bg-white transition-all shadow-sm">
                                <div ref={cardCvcRef}>
                                    {!stripe && <div className="h-5 bg-gray-200 animate-pulse rounded w-full"></div>}
                                </div>
                            </div>
                        </div>
                    </div>

                    <p className="text-[10px] text-gray-400 font-medium leading-relaxed bg-gray-50 p-3 rounded-lg border border-gray-100">
                        This site uses Stripe for secure transactions. Your full card data is never stored on our local database, but tokenized and handled exclusively by Stripe's PCI-compliant infrastructure.
                    </p>

                    <button 
                        type="submit" 
                        disabled={isProcessing || !stripe}
                        className="w-full bg-primary text-white font-black text-sm py-4 px-6 rounded-xl hover:bg-orange-600 transition-all shadow-lg shadow-primary/20 active:scale-[0.98] disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-3 uppercase tracking-wider"
                    >
                        {isProcessing ? (
                            <>
                                <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                                <span>Verifying...</span>
                            </>
                        ) : (
                            <>
                                <LockIcon className="w-4 h-4" />
                                <span>Add Card Securely</span>
                            </>
                        )}
                    </button>
                </div>
            </form>
        </div>
      </div>
    </div>
  );
};

export default PaymentMethodsModal;

import React, { useState } from 'react';
import { useAuth } from '../hooks/useStore';
