import React, { useEffect, useMemo } from 'react';
import { useAuth } from '../hooks/useStore';
import { useNavigate, Link } from 'react-router-dom';

const TransactionsPage: React.FC = () => {
  // Fixed missing getUserTransactions from useAuth
  const { currentUser, getUserTransactions } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    if (!currentUser) {
      navigate('/');
    }
  }, [currentUser, navigate]);

  const transactions = useMemo(() => {
    if (!currentUser) return [];
    return getUserTransactions(currentUser.id);
  }, [currentUser, getUserTransactions]);

  const formatDate = (isoString: string) => {
    return new Date(isoString).toLocaleDateString('en-US', {
        year: 'numeric',
        month: 'short',
        day: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
    });
  };

  const getTypeLabel = (type: string) => {
      switch (type) {
          case 'buy': return <span className="bg-blue-100 text-blue-800 text-xs font-semibold px-2.5 py-0.5 rounded">Purchase</span>;
          case 'sell': return <span className="bg-green-100 text-green-800 text-xs font-semibold px-2.5 py-0.5 rounded">Withdrawal</span>;
          case 'fee_payment': return <span className="bg-orange-100 text-orange-800 text-xs font-semibold px-2.5 py-0.5 rounded">Fee Paid</span>;
          case 'fee_income': return <span className="bg-purple-100 text-purple-800 text-xs font-semibold px-2.5 py-0.5 rounded">Income</span>;
          default: return <span className="bg-gray-100 text-gray-800 text-xs font-semibold px-2.5 py-0.5 rounded">{type}</span>;
      }
  };

  if (!currentUser) return null;

  return (
    <div className="container mx-auto p-4 md:p-6 max-w-4xl">
      <div className="mb-6 flex items-center justify-between">
        <div>
            <Link to="/settings" className="text-primary hover:underline text-sm mb-2 block">&larr; Back to Settings</Link>
            <h1 className="text-2xl font-bold text-gray-900">Transaction History</h1>
        </div>
        <div className="text-right">
            <p className="text-sm text-gray-500">Current Balance</p>
            {/* Fixed kopeki access */}
            <p className="text-xl font-bold text-primary">{currentUser.kopeki.toLocaleString()} K</p>
        </div>
      </div>

      <div className="bg-white rounded-md border border-gray-200 overflow-hidden shadow-sm">
        {transactions.length > 0 ? (
            <div className="overflow-x-auto">
                <table className="w-full text-sm text-left text-gray-500">
                    <thead className="text-xs text-gray-700 uppercase bg-gray-50 border-b border-gray-200">
                        <tr>
                            <th className="px-6 py-3">Date</th>
                            <th className="px-6 py-3">Type</th>
                            <th className="px-6 py-3">Description</th>
                            <th className="px-6 py-3 text-right">Amount (Kopeki)</th>
                            <th className="px-6 py-3 text-right">Value (EUR)</th>
                        </tr>
                    </thead>
                    <tbody>
                        {transactions.map((tx) => (
                            <tr key={tx.id} className="bg-white border-b border-gray-200 hover:bg-gray-50">
                                <td className="px-6 py-4 font-medium text-gray-900 whitespace-nowrap">
                                    {formatDate(tx.createdAt)}
                                </td>
                                <td className="px-6 py-4">
                                    {getTypeLabel(tx.type)}
                                </td>
                                <td className="px-6 py-4 text-gray-700">
                                    {tx.description}
                                </td>
                                <td className={`px-6 py-4 text-right font-bold ${tx.type === 'sell' || tx.type === 'fee_payment' ? 'text-red-600' : 'text-green-600'}`}>
                                    {tx.type === 'sell' || tx.type === 'fee_payment' ? '-' : '+'}{tx.amount.toLocaleString()}
                                </td>
                                <td className="px-6 py-4 text-right text-gray-600">
                                    {tx.currencyAmount ? `€${tx.currencyAmount.toFixed(2)}` : '-'}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        ) : (
            <div className="p-8 text-center text-gray-500">
                No transactions found.
            </div>
        )}
      </div>
    </div>
  );
};

export default TransactionsPage;

import React, { useState, useEffect } from 'react';
import { useAuth } from '../hooks/useStore';
import { CloseIcon } from './Icons';
import { Link } from 'react-router-dom';

interface BuyKopekiModalProps {
  onClose: () => void;
}

const BuyKopekiModal: React.FC<BuyKopekiModalProps> = ({ onClose }) => {
  // Fixed missing buyKopeki from useAuth
  const { currentUser, buyKopeki } = useAuth();
  const [amount, setAmount] = useState('');
  const [selectedCardId, setSelectedCardId] = useState('');
  const [message, setMessage] = useState({ type: '', text: '' });

  useEffect(() => {
      // Fixed savedCards access
      if (currentUser && currentUser.savedCards && currentUser.savedCards.length > 0) {
          setSelectedCardId(currentUser.savedCards[0].id);
      }
  }, [currentUser]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const amountNum = parseInt(amount, 10);
    if (isNaN(amountNum) || amountNum <= 0) {
        setMessage({type: 'error', text: 'Please enter a valid Kopeki amount.'});
        return;
    }
    if (!selectedCardId) {
        setMessage({type: 'error', text: 'Please select a payment method.'});
        return;
    }

    const result = buyKopeki(amountNum);
    setMessage({type: result.success ? 'success' : 'error', text: result.message});
    if (result.success) {
        setAmount('');
        setTimeout(() => onClose(), 2000);
    }
  };

  if (!currentUser) return null;

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
      <div className="bg-white rounded-lg p-8 w-full max-w-md relative border border-gray-200">
        <button onClick={onClose} className="absolute top-4 right-4 text-gray-400 hover:text-gray-700">
          <CloseIcon className="w-6 h-6" />
        </button>
        <h2 className="text-xl font-bold text-gray-900 mb-6">Buy Kopeki</h2>

        <form onSubmit={handleSubmit} className="space-y-4">
            {message.text && (
                <p className={`p-3 rounded-md text-sm ${message.type === 'success' ? 'bg-green-50 border border-green-200 text-green-700' : 'bg-red-50 border border-red-200 text-red-700'}`}>
                {message.text}
                </p>
            )}
            <div>
                <label className="block text-gray-600 mb-1 text-sm" htmlFor="buy-amount">Amount in Kopeki</label>
                <input type="number" id="buy-amount" value={amount} onChange={(e) => setAmount(e.target.value)}
                    className="w-full bg-gray-50 border border-gray-300 rounded-md p-3 text-gray-900 focus:outline-none focus:ring-2 focus:ring-primary"
