        )}

        <div className="flex-1 overflow-y-auto p-1">
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-3">
                {AVAILABLE_AWARDS.map(award => (
                    <button
                        key={award.id}
