  updatePost: (id: string, t: string, c: string) => boolean; updateProfilePost: (id: string, t: string, c: string) => boolean; updateEditorial: (id: string, t: string, c: string) => boolean; updateBoard: (id: string, d: any) => any;
  addComment: (c: string, pid: string, paid?: string | null, m?: MediaItem[]) => Comment | null; castVote: (eid: string, t: VoteType) => void; getBoardByName: (n: string) => Board | undefined;
  deletePost: (id: string) => void; deleteProfilePost: (id: string) => void; deleteEditorial: (id: string) => void; deleteComment: (id: string) => void;
  appointModerator: (bid: string, u: string) => any; isModerator: (uid: string, bid: string) => boolean; appointAdmin: (bid: string, u: string) => any; isBoardAdmin: (uid: string, bid: string) => boolean;
  inviteUserToBoard: (bid: string, u: string) => any; removeUserFromBoard: (bid: string, uid: string) => any; subscribe: (bid: string) => void; unsubscribe: (bid: string) => void; isSubscribed: (bid: string) => boolean;
  followUser: (id: string) => void; unfollowUser: (id: string) => void; isFollowing: (id: string) => boolean; sendMessage: (rid: string, c: string, m?: MediaItem[], k?: number) => any; markConversationAsRead: (uid: string) => void;
  unlockBoard: (bid: string, pw: string) => boolean; isBoardUnlocked: (bid: string) => boolean; payBoardEntryFee: (bid: string) => any; giveAward: (eid: string, et: any, aid: string, rid: string) => any; unlockProfilePost: (pid: string) => any;
  createAd: (bid: string, t: string, c: string, l: string, i: string, b: number, m: any, ba: number) => any; approveAd: (id: string) => void; rejectAd: (id: string) => void; trackAdImpression: (id: string) => void; trackAdClick: (id: string) => void; getActiveAdsForBoard: (bid: string) => Advertisement[];
  respondToBoardInvite: (msgId: string, action: 'accept' | 'reject') => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);
const DataContext = createContext<DataContextType | undefined>(undefined);

export const StoreProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const usersS = usePersistentState<User[]>('r-users', []), boardsS = usePersistentState<Board[]>('r-boards', []), postsS = usePersistentState<Post[]>('r-posts', []), pPostsS = usePersistentState<ProfilePost[]>('r-profile-posts', []);
  const editsS = usePersistentState<Editorial[]>('r-editorials', []), commsS = usePersistentState<Comment[]>('r-comments', []), msgsS = usePersistentState<Message[]>('r-messages', []), votesS = usePersistentState<Vote[]>('r-votes', []);
  const subsS = usePersistentState<Subscription[]>('r-subscriptions', []), uSubsS = usePersistentState<UserSubscription[]>('r-user-subscriptions', []), followsS = usePersistentState<Follow[]>('r-follows', []);
  const txS = usePersistentState<Transaction[]>('r-transactions', []), awardS = usePersistentState<Award[]>('r-awards', []), adsS = usePersistentState<Advertisement[]>('r-ads', []), curUserS = usePersistentState<User | null>('r-currentUser', null);

  const [users, setUsers] = [usersS.value, usersS.setValue], [boards, setBoards] = [boardsS.value, boardsS.setValue], [posts, setPosts] = [postsS.value, postsS.setValue];
  const [profilePosts, setProfilePosts] = [pPostsS.value, pPostsS.setValue], [editorials, setEditorials] = [editsS.value, editsS.setValue], [comments, setComments] = [commsS.value, commsS.setValue];
  const [messages, setMessages] = [msgsS.value, msgsS.setValue], [votes, setVotes] = [votesS.value, votesS.setValue], [subscriptions, setSubscriptions] = [subsS.value, subsS.setValue];
  const [userSubscriptions, setUserSubscriptions] = [uSubsS.value, uSubsS.setValue], [follows, setFollows] = [followsS.value, followsS.setValue], [transactions, setTransactions] = [txS.value, txS.setValue];
  const [awards, setAwards] = [awardS.value, awardS.setValue], [ads, setAds] = [adsS.value, adsS.setValue], [currentUser, setCurrentUser] = [curUserS.value, curUserS.setValue];
  const [unlockedBoards, setUnlockedBoards] = useState<string[]>([]), [isInit, setIsInit] = useState(true);

  // Helper for "Fire and Forget" API calls
  const api = (endpoint: string, method: 'GET'|'POST'|'PUT'|'DELETE', body?: any) => {
      const url = `${getServerUrl()}${endpoint}`;
      // console.log(`[API Invoke] ${method} ${url}`, body); 
      fetch(url, {
          method,
          headers: { 'Content-Type': 'application/json' },
          body: body ? JSON.stringify(body) : undefined
      }).catch(err => console.warn(`[API Fail] ${method} ${url}`, err));
  };

  useEffect(() => {
    if (usersS.isLoaded && boardsS.isLoaded && postsS.isLoaded && curUserS.isLoaded) {
        if (users.length === 0) { 
            const d = DemoContent.getInitialData(); 
            setUsers(d.users); setBoards(d.boards); setPosts(d.posts as any); setProfilePosts(d.profilePosts as any); setEditorials(d.editorials); setComments(d.comments); setMessages(d.messages); setVotes(d.votes); setSubscriptions(d.subscriptions); setUserSubscriptions([]); setFollows(d.follows); setTransactions([]); setAwards([]); setAds(d.ads); 
        }
        setIsInit(false);
    }
  }, [usersS.isLoaded, boardsS.isLoaded, postsS.isLoaded, curUserS.isLoaded, users.length]);

  // --- Auth & User Logic ---

  const login = (u: string, p: string) => { 
      api('/auth/login', 'POST', { username: u, password: p });
      const user = users.find(x => x.username === u && x.password === p);
      if (user) setCurrentUser(user); 
      return !!user; 
  };

  const register = (u: string, p: string) => {
      api('/auth/register', 'POST', { username: u, password: p });
      if (users.some(x => x.username === u)) return { success: false, message: 'Username taken' };
      const nu: User = { 
          id: crypto.randomUUID(), username: u, password: p, role: 'user', 
          createdAt: new Date().toISOString(), iconUrl: '', bannerUrl: '', bio: '', junkSenders: [], 
          kopeki: 1000, countryCode: ['IT','US','FR'][Math.floor(Math.random()*3)], 
          publicKey: DemoContent.generateMockPublicKey(), isVerified: false, isPendingVerification: false 
      };
      setUsers(prev => [...prev, nu]);
      setCurrentUser(nu);
      return { success: true, message: 'OK' };
  };

  const logout = () => { api('/auth/logout', 'POST'); setCurrentUser(null); setUnlockedBoards([]); };
  const getUserById = (id: string) => users.find(u => u.id === id);
  const getUserByUsername = (u: string) => users.find(x => x.username.toLowerCase() === u.toLowerCase());
  const isAdmin = (id: string) => users.find(u => u.id === id)?.role === 'admin';

  const changePassword = (o: string, n: string) => {
      if(!currentUser) return { success: false, message: 'Login required' };
      api(`/users/${currentUser.id}/password`, 'PUT', { oldPassword: o, newPassword: n });
      if(currentUser.password !== o) return { success: false, message: 'Incorrect password' };
      const updatedUser = { ...currentUser, password: n };
      setUsers(users.map(u => u.id === currentUser.id ? updatedUser : u));
      setCurrentUser(updatedUser);
      return { success: true, message: 'OK' };
  };

  const updateProfile = (d: any) => {
      if(!currentUser) return { success: false, message: 'Login required' };
      api(`/users/${currentUser.id}`, 'PUT', d);
      const updatedUser = { ...currentUser, ...d };
      setUsers(users.map(u => u.id === currentUser.id ? updatedUser : u));
      setCurrentUser(updatedUser);
      return { success: true, message: 'OK' };
  };

  const moveConversationToJunk = (id: string) => { 
      if(currentUser) {
          api(`/users/${currentUser.id}/junk`, 'POST', { senderId: id });
          const currentJunk = currentUser.junkSenders || [];
          const newJunk = [...new Set([...currentJunk, id])];
          const updatedUser = { ...currentUser, junkSenders: newJunk };
          setUsers(users.map(u => u.id === currentUser.id ? updatedUser : u));
          setCurrentUser(updatedUser);
      } 
  };
  const moveConversationToInbox = (id: string) => { 
      if(currentUser) { 
          api(`/users/${currentUser.id}/junk/${id}`, 'DELETE');
          const updatedUser = { ...currentUser, junkSenders: (currentUser.junkSenders || []).filter(jid => jid !== id) };
          setUsers(users.map(u => u.id === currentUser.id ? updatedUser : u));
          setCurrentUser(updatedUser);
      } 
  };

  // --- Wallet & Economy ---

  const buyKopeki = (a: number) => {
      if(!currentUser) return {success:false, message:'Login'};
      api(`/wallet/buy`, 'POST', { amount: a });
      const updatedUser = { ...currentUser, kopeki: (currentUser.kopeki || 0) + a };
      const tx: Transaction = { 
          id: crypto.randomUUID(), userId: currentUser.id, type: 'buy', amount: a, 
          currencyAmount: parseFloat((a/10000).toFixed(2)), description: `Bought ${a.toLocaleString()}`, createdAt: new Date().toISOString() 
      };
      setUsers(users.map(u => u.id === currentUser.id ? updatedUser : u));
      setTransactions(prev => [tx, ...prev]);
      setCurrentUser(updatedUser);
      return { success: true, message: 'OK' };
  };

  const sellKopeki = (a: number) => {
      if(!currentUser) return {success:false, message:'Login'};
      if ((currentUser.kopeki || 0) < a) return { success: false, message: 'Insufficient funds' };
      api(`/wallet/sell`, 'POST', { amount: a });
      const updatedUser = { ...currentUser, kopeki: (currentUser.kopeki || 0) - a };
      const tx: Transaction = { 
          id: crypto.randomUUID(), userId: currentUser.id, type: 'sell', amount: a, 
          currencyAmount: parseFloat((a/10000).toFixed(2)), description: `Sold ${a.toLocaleString()}`, createdAt: new Date().toISOString() 
      };
      setUsers(users.map(u => u.id === currentUser.id ? updatedUser : u));
      setTransactions(prev => [tx, ...prev]);
      setCurrentUser(updatedUser);
      return { success: true, message: 'OK' };
  };

  const addCreditCard = (c: any) => { 
      if(!currentUser) return; 
      api(`/users/${currentUser.id}/cards`, 'POST', c);
      const card = { ...c, id: crypto.randomUUID() };
      const updatedUser = { ...currentUser, savedCards: [...(currentUser.savedCards || []), card] };
      setUsers(users.map(u => u.id === currentUser.id ? updatedUser : u));
      setCurrentUser(updatedUser);
      return {success:true, message:'OK'}; 
  };
  const removeCreditCard = (id: string) => { 
      if(!currentUser) return; 
      api(`/users/${currentUser.id}/cards/${id}`, 'DELETE');
      const updatedUser = { ...currentUser, savedCards: (currentUser.savedCards || []).filter(c => c.id !== id) };
      setUsers(users.map(u => u.id === currentUser.id ? updatedUser : u));
      setCurrentUser(updatedUser);
      return {success:true, message:'OK'}; 
  };
  const addIban = (i: any) => { 
      if(!currentUser) return; 
      api(`/users/${currentUser.id}/ibans`, 'POST', i);
      const iban = { ...i, id: crypto.randomUUID() };
      const updatedUser = { ...currentUser, savedIbans: [...(currentUser.savedIbans || []), iban] };
      setUsers(users.map(u => u.id === currentUser.id ? updatedUser : u));
      setCurrentUser(updatedUser);
      return {success:true, message:'OK'}; 
  };
  const removeIban = (id: string) => { 
      if(!currentUser) return; 
      api(`/users/${currentUser.id}/ibans/${id}`, 'DELETE');
      const updatedUser = { ...currentUser, savedIbans: (currentUser.savedIbans || []).filter(i => i.id !== id) };
      setUsers(users.map(u => u.id === currentUser.id ? updatedUser : u));
      setCurrentUser(updatedUser);
      return {success:true, message:'OK'}; 
  };

  const getUserTransactions = (id: string) => transactions.filter(t => t.userId === id).sort((a,b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());

  const subscribeToUser = (cid: string) => {
      if(!currentUser) return {success:false, message:'Login'};
      api(`/users/${cid}/subscribe`, 'POST', { subscriberId: currentUser.id });
      const creator = users.find(u => u.id === cid);
      if (!creator) return { success: false, message: 'User not found' };
      if (userSubscriptions.some(s => s.subscriberId === currentUser.id && s.creatorId === cid)) return { success: false, message: 'Already subscribed' };

      const fee = creator.subscriptionFee || 0;
      if (fee > 0) {
          if ((currentUser.kopeki || 0) < fee) return { success: false, message: 'Insufficient funds' };

          // Deduct from current user
          const updatedSub = { ...currentUser, kopeki: (currentUser.kopeki || 0) - fee };
          // Add to creator (find in users array, might not be current user)
          const updatedCreator = { ...creator, kopeki: (creator.kopeki || 0) + fee };

          setUsers(prev => prev.map(u => u.id === currentUser.id ? updatedSub : u.id === creator.id ? updatedCreator : u));
          setCurrentUser(updatedSub);

          setTransactions(prev => [
              { id: crypto.randomUUID(), userId: currentUser.id, type: 'fee_payment', amount: fee, description: `Sub to ${creator.username}`, createdAt: new Date().toISOString() },
              { id: crypto.randomUUID(), userId: creator.id, type: 'fee_income', amount: fee, description: `Sub from ${currentUser.username}`, createdAt: new Date().toISOString() },
              ...prev
          ]);
      }

      setUserSubscriptions(prev => [...prev, { subscriberId: currentUser.id, creatorId: cid, startedAt: new Date().toISOString() }]);
      return { success: true, message: 'OK' };
  };
  const isSubscribedToUser = (id: string) => !!currentUser && userSubscriptions.some(s => s.subscriberId === currentUser.id && s.creatorId === id);

  // --- Content (Boards, Posts, etc) ---

  const createBoard = (name: string, description: string, allowAnonymousComments: boolean, allowAnonymousPosts: boolean, password?: string, isInviteOnly?: boolean, entryFee?: number, iconUrl?: string, bannerUrl?: string) => {
      if(!currentUser) return {success:false, message:'Login'};
      api('/boards', 'POST', { name, description, allowAnonymousComments, allowAnonymousPosts, password, isInviteOnly, entryFee, iconUrl, bannerUrl });
      if (boards.some(b => b.name.toLowerCase() === name.toLowerCase())) return { success: false, message: 'Board name taken' };

      const b: Board = { 
          id: crypto.randomUUID(), name, description, allowAnonymousComments, allowAnonymousPosts, password, isInviteOnly, entryFee: entryFee || 0, iconUrl, bannerUrl,
          creatorId: currentUser.id, createdAt: new Date().toISOString(), 
          moderatorIds: [], adminIds: [currentUser.id], 
          allowedUserIds: (isInviteOnly || (entryFee || 0) > 0) ? [currentUser.id] : []
      };
      setBoards(o => [...o, b]);
      setSubscriptions(o => [...o, { userId: currentUser.id, boardId: b.id }]);
      return { success: true, message: 'OK', board: b };
  };

  const updateBoard = (id: string, d: any) => {
      if(!currentUser) return {success:false, message:'Login'};
      api(`/boards/${id}`, 'PUT', d);
      setBoards(prev => prev.map(b => b.id === id ? { ...b, ...d } : b));
      return { success: true, message: 'OK' };
  };

  const createPost = (title: string, content: string, boardId: string, media?: MediaItem[]) => {
      const aid = currentUser?.id || null;
      if(!aid && !boards.find(b=>b.id===boardId)?.allowAnonymousPosts) return null;
      const p: Post = { id: crypto.randomUUID(), title, content, media: media||[], boardId, authorId: aid, createdAt: new Date().toISOString() };
      api('/posts', 'POST', p);
      setPosts(o => [p, ...o]); return p;
  };

  const createProfilePost = (title: string, content: string, media?: MediaItem[], price?: number) => {
      if(!currentUser) return null;
      const p: ProfilePost = { id: crypto.randomUUID(), title, content, media: media||[], authorId: currentUser.id, createdAt: new Date().toISOString(), price: price||0, unlockedUserIds: [] };
      api('/profile-posts', 'POST', p);
      setProfilePosts(o => [p, ...o]); return p;
  };

  const createEditorial = (title: string, content: string, media?: MediaItem[]) => {
      if(!currentUser || !isAdmin(currentUser.id)) return null;
      const e: Editorial = { id: crypto.randomUUID(), title, content, media: media||[], authorId: currentUser.id, createdAt: new Date().toISOString() };
      api('/editorials', 'POST', e);
      setEditorials(o => [e, ...o]); return e;
  };

  const updatePost = (id: string, t: string, c: string) => { 
      api(`/posts/${id}`, 'PUT', { title: t, content: c });
      setPosts(prev => prev.map(p => p.id === id ? { ...p, title: t, content: c } : p)); return true; 
  };
  const updateProfilePost = (id: string, t: string, c: string) => { 
      api(`/profile-posts/${id}`, 'PUT', { title: t, content: c });
      setProfilePosts(prev => prev.map(p => p.id === id ? { ...p, title: t, content: c } : p)); return true; 
  };
  const updateEditorial = (id: string, t: string, c: string) => { 
      api(`/editorials/${id}`, 'PUT', { title: t, content: c });
      setEditorials(prev => prev.map(p => p.id === id ? { ...p, title: t, content: c } : p)); return true; 
  };

  const addComment = (content: string, postId: string, parentId: string|null = null, media?: MediaItem[]) => {
      const aid = currentUser?.id || null;
      const c: Comment = { id: crypto.randomUUID(), content, postId, authorId: aid, parentId, createdAt: new Date().toISOString(), media: media||[] };
      api('/comments', 'POST', c);
      setComments(o => [...o, c]); return c;
  };

  const castVote = (eid: string, t: VoteType) => { 
      let uid = currentUser?.id;
      if (!uid) {
          uid = localStorage.getItem('qult_anon_id') || '';
          if (!uid) { uid = 'anon-' + crypto.randomUUID(); localStorage.setItem('qult_anon_id', uid); }
      }
      api('/votes', 'POST', { entityId: eid, type: t, userId: uid });
      setVotes(prev => {
          const idx = prev.findIndex(v => v.userId === uid && v.entityId === eid);
          if (idx > -1) {
              if (prev[idx].type === t) return prev.filter((_, i) => i !== idx); // Toggle off
              const n = [...prev]; n[idx] = { ...n[idx], type: t }; return n; // Change type
          }
          return [...prev, { userId: uid!, entityId: eid, type: t }];
      }); 
  };

  const getBoardByName = (n: string) => boards.find(b => b.name.toLowerCase() === n.toLowerCase());

  const deletePost = (id: string) => { api(`/posts/${id}`, 'DELETE'); setPosts(o => o.filter(p => p.id !== id)); setComments(o => o.filter(c => c.postId !== id)); };
  const deleteProfilePost = (id: string) => { api(`/profile-posts/${id}`, 'DELETE'); setProfilePosts(o => o.filter(p => p.id !== id)); setComments(o => o.filter(c => c.postId !== id)); };
  const deleteEditorial = (id: string) => { api(`/editorials/${id}`, 'DELETE'); setEditorials(o => o.filter(e => e.id !== id)); };
  const deleteComment = (id: string) => { api(`/comments/${id}`, 'DELETE'); setComments(o => o.filter(c => c.id !== id && c.parentId !== id)); };

  // --- Moderation & Roles ---
  const appointModerator = (bid: string, u: string) => {
      const uid = getUserByUsername(u)?.id; if(!uid) return {success:false, message:'No user'}; 
      api(`/boards/${bid}/moderators`, 'POST', { userId: uid });
      setBoards(o => o.map(b => b.id === bid ? {...b, moderatorIds: [...b.moderatorIds, uid]} : b)); return {success:true, message:'OK'};
  };
  const isModerator = (uid: string, bid: string) => boards.find(b => b.id === bid)?.moderatorIds.includes(uid) || false;
  const appointAdmin = (bid: string, u: string) => {
      const uid = getUserByUsername(u)?.id; if(!uid) return {success:false, message:'No user'}; 
      api(`/boards/${bid}/admins`, 'POST', { userId: uid });
      setBoards(o => o.map(b => b.id === bid ? {...b, adminIds: [...b.adminIds, uid]} : b)); return {success:true, message:'OK'};
  };
  const isBoardAdmin = (uid: string, bid: string) => boards.find(b => b.id === bid)?.adminIds.includes(uid) || false;

  const inviteUserToBoard = (bid: string, u: string) => { 
      if(!currentUser) return {success:false, message: 'Login required'};
      const board = boards.find(b => b.id === bid);
      const userToInvite = users.find(x => x.username.toLowerCase() === u.toLowerCase());

      if (!board) return { success: false, message: 'Board not found' };
      if (!userToInvite) return { success: false, message: 'User not found' };
      if (board.allowedUserIds?.includes(userToInvite.id)) return { success: false, message: 'User already has access' };

      const inviteMsg: Message = {
          id: crypto.randomUUID(),
          senderId: currentUser.id,
          recipientId: userToInvite.id,
          content: `You have been invited to join b/${board.name}`,
          createdAt: new Date().toISOString(),
          type: 'board_invite',
          metadata: { boardId: board.id, boardName: board.name, inviteStatus: 'pending' }
      };

      api(`/messages`, 'POST', inviteMsg);
      setMessages(o => [...o, inviteMsg]);
      return { success: true, message: 'Invitation sent' }; 
  };

  const respondToBoardInvite = (msgId: string, action: 'accept' | 'reject') => {
      api(`/messages/${msgId}/invite`, 'POST', { action });
      const msg = messages.find(m => m.id === msgId);
      if (!msg || msg.type !== 'board_invite' || !msg.metadata?.boardId) return;
      if (msg.metadata.inviteStatus !== 'pending') return;

      const boardId = msg.metadata.boardId;
      const board = boards.find(b => b.id === boardId);
      const invitee = users.find(u => u.id === msg.recipientId);
      const inviter = users.find(u => u.id === msg.senderId);

      // Update Board if accepted
      if (action === 'accept' && board && invitee) {
          setBoards(prev => prev.map(b => b.id === boardId ? { ...b, allowedUserIds: [...(b.allowedUserIds || []), invitee.id] } : b));
      }

      // Update Message
      setMessages(prev => prev.map(m => m.id === msgId ? { ...m, metadata: { ...m.metadata, inviteStatus: action === 'accept' ? 'accepted' : 'rejected' } } : m));

      // Notify Admin
      if (inviter && invitee && board) {
          const notifMsg: Message = {
              id: crypto.randomUUID(),
              senderId: invitee.id,
              recipientId: inviter.id,
              content: `User ${invitee.username} has ${action}ed your invitation to b/${board.name}.`,
              createdAt: new Date().toISOString(),
              type: 'notification'
          };
          setMessages(prev => [...prev, notifMsg]);
      }
  };

  const removeUserFromBoard = (bid: string, uid: string) => { 
      api(`/boards/${bid}/users/${uid}`, 'DELETE');
      setBoards(o => o.map(b => b.id === bid ? {...b, allowedUserIds: (b.allowedUserIds||[]).filter(x => x!==uid)} : b)); return {success:true, message:'OK'}; 
  };

  const subscribe = (bid: string) => { 
      if(currentUser) {
          api(`/boards/${bid}/subscribe`, 'POST');
          const exists = subscriptions.some(s => s.userId === currentUser.id && s.boardId === bid);
          if (exists) setSubscriptions(o => o.filter(s => !(s.userId === currentUser.id && s.boardId === bid)));
          else setSubscriptions(o => [...o, { userId: currentUser.id, boardId: bid }]);
      }
  };
  const unsubscribe = (bid: string) => subscribe(bid); // Alias
  const isSubscribed = (bid: string) => !!currentUser && subscriptions.some(s => s.userId === currentUser.id && s.boardId === bid);

  const followUser = (id: string) => { 
      if(currentUser) {
          api(`/users/${id}/follow`, 'POST');
          const exists = follows.some(f => f.followerId === currentUser.id && f.followingId === id);
          if (exists) setFollows(o => o.filter(f => !(f.followerId === currentUser.id && f.followingId === id)));
          else setFollows(o => [...o, { followerId: currentUser.id, followingId: id }]);
      }
  };
  const unfollowUser = (id: string) => followUser(id); // Alias
  const isFollowing = (id: string) => !!currentUser && follows.some(f => f.followerId === currentUser.id && f.followingId === id);

  const sendMessage = (rid: string, c: string, m?: MediaItem[], k?: number) => {
      if(!currentUser) return {success:false, error: 'Login required'};
      const recipient = users.find(u => u.id === rid);
      if(!recipient) return {success:false, error: 'Recipient not found'};

      if (k && k > 0) {
          if ((currentUser.kopeki || 0) < k) return { success: false, error: 'Insufficient funds' };

          const updatedSender = { ...currentUser, kopeki: (currentUser.kopeki || 0) - k };
          const updatedRecipient = { ...recipient, kopeki: (recipient.kopeki || 0) + k };

          setUsers(prev => prev.map(u => u.id === currentUser.id ? updatedSender : u.id === recipient.id ? updatedRecipient : u));
          setCurrentUser(updatedSender);

          setTransactions(prev => [
              { id: crypto.randomUUID(), userId: currentUser.id, type: 'p2p_transfer', amount: k, description: `Sent to ${recipient.username}`, createdAt: new Date().toISOString() },
              { id: crypto.randomUUID(), userId: recipient.id, type: 'p2p_transfer', amount: k, description: `Received from ${currentUser.username}`, createdAt: new Date().toISOString() },
              ...prev
          ]);
      }

      const msgContent = (recipient.publicKey && c) ? mockEncrypt(c) : c;
      const msg: Message = { 
          id: crypto.randomUUID(), senderId: currentUser.id, recipientId: rid, 
          content: msgContent, media: m, kopekiAmount: k, isEncrypted: !!(recipient.publicKey && c), createdAt: new Date().toISOString(), type: 'text' 
      };

      api('/messages', 'POST', msg);
      setMessages(o => [...o, msg]);
      return { success: true, message: msg };
  };
  const markConversationAsRead = (uid: string) => { 
      if(currentUser) {
          api(`/messages/read/${uid}`, 'POST');
          setMessages(o => o.map(m => (!m.readAt && m.recipientId === currentUser.id && m.senderId === uid) ? {...m, readAt: new Date().toISOString()} : m)); 
      }
  };

  const unlockBoard = (bid: string, pw: string) => { const b = boards.find(x => x.id === bid); if(b && b.password === pw) { setUnlockedBoards(o => [...o, bid]); return true; } return false; };
  const isBoardUnlocked = (bid: string) => {
      const b = boards.find(x => x.id === bid); if(!b) return false;
      if(currentUser && (isAdmin(currentUser.id) || isBoardAdmin(currentUser.id, bid) || isModerator(currentUser.id, bid))) return true;
      if(b.isInviteOnly || (b.entryFee && b.entryFee > 0)) return !!currentUser && (b.allowedUserIds||[]).includes(currentUser.id);
      return b.password ? unlockedBoards.includes(bid) : true;
  };

  const payBoardEntryFee = (bid: string) => {
      if(!currentUser) return {success:false, message:'Login'};
      api(`/boards/${bid}/pay`, 'POST');
      const board = boards.find(b => b.id === bid);
      if(!board || !board.entryFee) return {success:false, message:'Invalid'};
      if((currentUser.kopeki || 0) < board.entryFee) return {success:false, message:'Insufficient funds'};

      const creator = users.find(u => u.id === board.creatorId);
      const updatedUser = { ...currentUser, kopeki: (currentUser.kopeki || 0) - board.entryFee };
      let updatedCreator = creator ? { ...creator, kopeki: (creator.kopeki || 0) + board.entryFee } : undefined;

      setUsers(prev => prev.map(u => u.id === currentUser.id ? updatedUser : (updatedCreator && u.id === creator!.id) ? updatedCreator : u));
      setCurrentUser(updatedUser);

      setBoards(prev => prev.map(b => b.id === bid ? { ...b, allowedUserIds: [...(b.allowedUserIds||[]), currentUser.id] } : b));

      const newTxs: Transaction[] = [{ id: crypto.randomUUID(), userId: currentUser.id, type: 'fee_payment', amount: board.entryFee, description: `Entry ${board.name}`, createdAt: new Date().toISOString() }];
      if(updatedCreator) newTxs.push({ id: crypto.randomUUID(), userId: updatedCreator.id, type: 'fee_income', amount: board.entryFee, description: `Entry income ${board.name}`, createdAt: new Date().toISOString() });

      setTransactions(prev => [...newTxs, ...prev]);
      return { success: true, message: 'OK' };
  };

  const giveAward = (eid: string, et: any, aid: string, rid: string) => {
      if(!currentUser) return {success:false, message:'Login'};
      api('/awards', 'POST', { entityId: eid, entityType: et, awardId: aid, receiverId: rid });
      const awardDef = AVAILABLE_AWARDS.find(a => a.id === aid);
      if (!awardDef) return {success:false, message:'Invalid award'};
      if ((currentUser.kopeki || 0) < awardDef.cost) return {success:false, message:'Insufficient Kopeki'};

      const receiver = users.find(u => u.id === rid);
      if (!receiver) return {success:false, message:'Receiver not found'};

      const updatedSender = { ...currentUser, kopeki: (currentUser.kopeki || 0) - awardDef.cost };
      const updatedReceiver = { ...receiver, kopeki: (receiver.kopeki || 0) + awardDef.cost };

      setUsers(prev => prev.map(u => u.id === currentUser.id ? updatedSender : u.id === receiver.id ? updatedReceiver : u));
      setCurrentUser(updatedSender);

      const award: Award = { id: crypto.randomUUID(), typeId: aid, senderId: currentUser.id, receiverId: rid, entityId: eid, entityType: et, createdAt: new Date().toISOString() };
      setAwards(o => [...o, award]);

      setTransactions(prev => [
          { id: crypto.randomUUID(), userId: currentUser.id, type: 'award_given', amount: awardDef.cost, description: `Gave ${awardDef.label}`, createdAt: new Date().toISOString() },
          { id: crypto.randomUUID(), userId: receiver.id, type: 'award_received', amount: awardDef.cost, description: `Received ${awardDef.label}`, createdAt: new Date().toISOString() },
          ...prev
      ]);
      return { success: true, message: 'OK' };
  };

  const unlockProfilePost = (pid: string) => {
      if(!currentUser) return {success:false, message:'Login'};
      api(`/profile-posts/${pid}/unlock`, 'POST');
      const post = profilePosts.find(p => p.id === pid);
      if(!post || !post.price) return {success:false};
      if((currentUser.kopeki || 0) < post.price) return {success:false, message:'Insufficient funds'};

      const author = users.find(u => u.id === post.authorId);
      if(!author) return {success:false, message:'Author error'};

      const updatedUser = { ...currentUser, kopeki: (currentUser.kopeki || 0) - post.price };
      const updatedAuthor = { ...author, kopeki: (author.kopeki || 0) + post.price };

      setUsers(prev => prev.map(u => u.id === currentUser.id ? updatedUser : u.id === author.id ? updatedAuthor : u));
      setCurrentUser(updatedUser);
      setProfilePosts(prev => prev.map(p => p.id === pid ? { ...p, unlockedUserIds: [...(p.unlockedUserIds||[]), currentUser.id] } : p));

      setTransactions(prev => [
          { id: crypto.randomUUID(), userId: currentUser.id, type: 'post_unlock', amount: post.price!, description: `Unlocked post`, createdAt: new Date().toISOString() },
          { id: crypto.randomUUID(), userId: author.id, type: 'post_income', amount: post.price!, description: `Post unlocked by ${currentUser.username}`, createdAt: new Date().toISOString() },
          ...prev
      ]);
      return { success: true, message: 'OK' };
  };

  const createAd = (bid: string, t: string, c: string, l: string, i: string, b: number, m: any, ba: number) => {
      if(!currentUser) return {success:false, message:'Login'};
      if ((currentUser.kopeki || 0) < b) return {success:false, message:'Insufficient funds'};

      const updatedUser = { ...currentUser, kopeki: (currentUser.kopeki || 0) - b };
      setUsers(prev => prev.map(u => u.id === currentUser.id ? updatedUser : u));
      setCurrentUser(updatedUser);

      const ad: Advertisement = { 
          id: crypto.randomUUID(), userId: currentUser.id, boardId: bid, title: t, content: c, linkUrl: l, imageUrl: i, 
          budget: b, spent: 0, model: m, bidAmount: ba, status: 'pending', views: 0, clicks: 0, createdAt: new Date().toISOString() 
      };

      api('/ads', 'POST', ad);
      setAds(o => [...o, ad]);
      setTransactions(prev => [{ id: crypto.randomUUID(), userId: currentUser.id, type: 'ad_payment', amount: b, description: `Ad ${t}`, createdAt: new Date().toISOString() }, ...prev]);
      return { success: true, message: 'OK' };
  };

  const approveAd = (id: string) => { 
      if(currentUser) {
          api(`/ads/${id}/approve`, 'POST');
          setAds(o => o.map(a => a.id === id ? {...a, status: 'active'} : a)); 
      }
  };
  const rejectAd = (id: string) => {
      if(!currentUser) return;
      api(`/ads/${id}/reject`, 'POST');
      const ad = ads.find(a => a.id === id);
      if(!ad) return;

      const refund = ad.budget - ad.spent;
      if (refund > 0) {
          const user = users.find(u => u.id === ad.userId);
          if (user) {
              const updatedUser = { ...user, kopeki: (user.kopeki || 0) + refund };
              setUsers(prev => prev.map(u => u.id === user.id ? updatedUser : u));
              if (currentUser.id === user.id) setCurrentUser(updatedUser);
              setTransactions(prev => [{ id: crypto.randomUUID(), userId: user.id, type: 'ad_refund' as const, amount: refund, description: `Refund ${ad.title}`, createdAt: new Date().toISOString() }, ...prev]);
          }
      }
      setAds(prev => prev.map(a => a.id === id ? {...a, status: 'rejected'} : a));
  };

  const trackAdImpression = (id: string) => {
      api(`/ads/${id}/impression`, 'POST');
      setAds(o => o.map(a => {
        if (a.id === id && a.status === 'active') {
            const cost = a.model === 'CPM' ? a.bidAmount/1000 : 0;
            const newSpent = a.spent + cost;
            return {...a, views: a.views + 1, spent: newSpent, status: newSpent >= a.budget ? 'completed' : 'active'};
        }
        return a;
      }));
  };
  const trackAdClick = (id: string) => {
      api(`/ads/${id}/click`, 'POST');
      setAds(o => o.map(a => {
        if (a.id === id && a.status === 'active') {
            const cost = a.model === 'CPC' ? a.bidAmount : 0;
            const newSpent = a.spent + cost;
            return {...a, clicks: a.clicks + 1, spent: newSpent, status: newSpent >= a.budget ? 'completed' : 'active'};
        }
        return a;
      }));
  };
  const getActiveAdsForBoard = (bid: string) => ads.filter(a => a.boardId === bid && a.status === 'active');

  const authCtx = useMemo(() => ({ currentUser, users, transactions, login, register, logout, getUserById, getUserByUsername, isAdmin, changePassword, updateProfile, moveConversationToJunk, moveConversationToInbox, buyKopeki, sellKopeki, addCreditCard, removeCreditCard, addIban, removeIban, getUserTransactions, subscribeToUser, isSubscribedToUser }), [currentUser, users, transactions]);
  const dataCtx = useMemo(() => ({ boards, posts, profilePosts, editorials, comments, messages, votes, subscriptions, follows, awards, ads, createBoard, createPost, createProfilePost, createEditorial, updatePost, updateProfilePost, updateEditorial, updateBoard, addComment, castVote, getBoardByName, deletePost, deleteProfilePost, deleteEditorial, deleteComment, appointModerator, isModerator, appointAdmin, isBoardAdmin, inviteUserToBoard, removeUserFromBoard, subscribe, unsubscribe, isSubscribed, followUser, unfollowUser, isFollowing, sendMessage, markConversationAsRead, unlockBoard, isBoardUnlocked, payBoardEntryFee, giveAward, unlockProfilePost, createAd, approveAd, rejectAd, trackAdImpression, trackAdClick, getActiveAdsForBoard, respondToBoardInvite }), [boards, posts, profilePosts, editorials, comments, messages, votes, subscriptions, follows, awards, ads, currentUser, users]);

  if (isInit) return React.createElement('div', { className: "h-screen flex items-center justify-center" }, "Loading...");
  return React.createElement(AuthContext.Provider, { value: authCtx }, React.createElement(DataContext.Provider, { value: dataCtx }, children));
};

export const useAuth = () => { const c = useContext(AuthContext); if(!c) throw new Error(); return c; };
export const useData = () => { const c = useContext(DataContext); if(!c) throw new Error(); return c; };

import React, { useState } from 'react';
import { useData } from '../hooks/useStore';
import { CloseIcon, LockIcon, UsersIcon, CheckIcon } from './Icons';
import { useNavigate } from 'react-router-dom';

interface CreateBoardModalProps {
  onClose: () => void;
}

const CreateBoardModal: React.FC<CreateBoardModalProps> = ({ onClose }) => {
  const navigate = useNavigate();
  const { createBoard } = useData();
  const [error, setError] = useState('');
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [accessType, setAccessType] = useState<'public' | 'password' | 'invite'>('public');
  const [password, setPassword] = useState('');
  const [allowAnonymousComments, setAllowAnonymousComments] = useState(true);
  const [allowAnonymousPosts, setAllowAnonymousPosts] = useState(true);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!name.trim()) {
        setError('Board name is required.');
        return;
    }

    if (accessType === 'password' && !password) {
        setError('Password is required for password-protected boards.');
        return;
    }

    const { success, message } = createBoard(
        name.trim(), 
        description.trim(), 
        allowAnonymousComments, 
        allowAnonymousPosts, 
        accessType === 'password' ? password : undefined, 
        accessType === 'invite'
    );

    if (success) {
      navigate(`/b/${name.trim()}`);
      onClose();
    } else {
      setError(message);
    }
  };

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-[60] p-4">
      <div className="bg-white rounded-2xl w-full max-w-lg relative border border-gray-200 shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
        {/* Header */}
        <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-gray-50/50">
          <div>
            <h2 className="text-2xl font-black text-gray-900 tracking-tight">Create a Community</h2>
            <p className="text-sm text-gray-500">Build your corner of the qult.</p>
          </div>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-700 transition-colors p-2 hover:bg-gray-100 rounded-full">
            <CloseIcon className="w-6 h-6" />
          </button>
        </div>

        {/* Body */}
        <div className="flex-1 overflow-y-auto p-6 space-y-8">
            {error && (
                <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-xl text-sm font-semibold animate-in fade-in slide-in-from-top-1 duration-200">
                    {error}
                </div>
            )}

            <form id="create-board-form" onSubmit={handleSubmit} className="space-y-8">
                {/* Basic Info Section */}
                <section className="space-y-4">
                    <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest px-1">Basic Information</h3>
                    <div className="space-y-4">
                        <div>
                            <label className="block text-sm font-bold text-gray-700 mb-2 ml-1">Name</label>
                            <div className="relative">
                                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 font-bold">b/</span>
                                <input 
                                    type="text" 
                                    value={name} 
                                    onChange={e => setName(e.target.value.replace(/\s+/g, '_').toLowerCase())} 
                                    className="w-full bg-gray-50 border border-gray-200 rounded-xl p-3 pl-8 text-gray-900 focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none font-bold transition-all" 
                                    placeholder="community_name" 
                                    required 
                                />
                            </div>
                            <p className="text-[10px] text-gray-400 mt-1.5 ml-1">Names cannot have spaces. Underscores are encouraged.</p>
                        </div>

                        <div>
                            <label className="block text-sm font-bold text-gray-700 mb-2 ml-1">Description</label>
                            <textarea 
                                value={description} 
                                onChange={e => setDescription(e.target.value)} 
                                className="w-full bg-gray-50 border border-gray-200 rounded-xl p-3 text-gray-800 focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none resize-none transition-all" 
                                placeholder="What's this community about?"
                                rows={3}
                            />
                        </div>
                    </div>
                </section>

                {/* Access & Privacy Section */}
                <section className="space-y-4">
                    <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest px-1">Privacy & Access</h3>
                    <div className="grid grid-cols-1 gap-3">
                        {[
                            { id: 'public', label: 'Public', desc: 'Anyone can view and post.', icon: <UsersIcon className="w-4 h-4" /> },
                            { id: 'password', label: 'Password', desc: 'Protected by a secret key.', icon: <LockIcon className="w-4 h-4" /> },
                            { id: 'invite', label: 'Invite Only', desc: 'Manual approval required.', icon: <UsersIcon className="w-4 h-4" /> }
                        ].map((type) => (
                            <label key={type.id} className={`flex items-center gap-4 p-4 border rounded-xl cursor-pointer transition-all ${accessType === type.id ? 'bg-primary/5 border-primary ring-1 ring-primary' : 'bg-white border-gray-200 hover:border-gray-300'}`}>
                                <input 
                                    type="radio" 
                                    name="accessType" 
                                    checked={accessType === type.id} 
                                    onChange={() => setAccessType(type.id as any)} 
                                    className="accent-primary w-4 h-4" 
                                />
                                <div className="flex-1">
                                    <div className="flex items-center gap-2">
                                        <span className="text-sm font-black text-gray-900">{type.label}</span>
                                        <div className="text-gray-400">{type.icon}</div>
                                    </div>
                                    <p className="text-xs text-gray-500 font-medium">{type.desc}</p>
                                </div>
                            </label>
                        ))}
                    </div>

                    {accessType === 'password' && (
                        <div className="p-4 bg-yellow-50 rounded-xl border border-yellow-200 animate-in zoom-in-95 duration-200 mt-3">
                            <label className="block text-xs font-black text-yellow-800 uppercase mb-2">Set Board Password</label>
                            <input 
                                type="text" 
                                value={password} 
                                onChange={e => setPassword(e.target.value)} 
                                className="w-full bg-white border border-yellow-300 rounded-lg p-2.5 text-sm focus:ring-2 focus:ring-yellow-500/20 focus:border-yellow-600 outline-none" 
                                placeholder="Enter secret password..." 
                            />
                        </div>
                    )}
                </section>

                {/* Community Rules Section */}
                <section className="space-y-4">
                    <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest px-1">Community Rules</h3>
                    <div className="space-y-3 bg-gray-50 rounded-xl p-4 border border-gray-100">
                        <label className="flex items-center justify-between cursor-pointer group">
                            <div className="flex-1">
                                <span className="block text-sm font-bold text-gray-700 group-hover:text-primary transition-colors">Allow Anonymous Posts</span>
                                <span className="text-[10px] text-gray-400">Users can post without showing their username.</span>
                            </div>
                            <input 
                                type="checkbox" 
                                checked={allowAnonymousPosts} 
                                onChange={e => setAllowAnonymousPosts(e.target.checked)} 
                                className="w-5 h-5 accent-primary rounded cursor-pointer"
                            />
                        </label>
                        <div className="h-px bg-gray-200/50" />
                        <label className="flex items-center justify-between cursor-pointer group">
                            <div className="flex-1">
                                <span className="block text-sm font-bold text-gray-700 group-hover:text-primary transition-colors">Allow Anonymous Comments</span>
                                <span className="text-[10px] text-gray-400">Enable guests or hidden identities in threads.</span>
                            </div>
                            <input 
                                type="checkbox" 
                                checked={allowAnonymousComments} 
                                onChange={e => setAllowAnonymousComments(e.target.checked)} 
                                className="w-5 h-5 accent-primary rounded cursor-pointer"
                            />
                        </label>
                    </div>
                </section>
            </form>
        </div>

        {/* Footer */}
        <div className="p-6 border-t border-gray-100 flex justify-end gap-3 bg-gray-50/50">
            <button 
                type="button" 
                onClick={onClose} 
                className="px-6 py-2.5 text-sm font-bold text-gray-500 hover:text-gray-800 transition-colors"
            >
                Cancel
            </button>
            <button 
                type="submit" 
                form="create-board-form"
                className="bg-primary text-white font-black py-2.5 px-10 rounded-full hover:bg-orange-600 transition-all shadow-lg shadow-primary/20 active:scale-95 disabled:opacity-50 disabled:grayscale"
                disabled={!name.trim()}
            >
                Create Board
            </button>
        </div>
      </div>
    </div>
  );
};

export default CreateBoardModal;

import React, { useState } from 'react';
import { useData, useAuth } from '../hooks/useStore';
import { CloseIcon, LockIcon, UsersIcon, WalletIcon, CheckIcon } from './Icons';
import { useNavigate } from 'react-router-dom';

interface CreateBoardModalProps {
  onClose: () => void;
}

const CreateBoardModal: React.FC<CreateBoardModalProps> = ({ onClose }) => {
  const navigate = useNavigate();
  const { currentUser } = useAuth();
  const { createBoard } = useData();
  const [error, setError] = useState('');
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [accessType, setAccessType] = useState<'public' | 'password' | 'invite' | 'paid'>('public');
  const [password, setPassword] = useState('');
  const [entryFee, setEntryFee] = useState('100');
  const [allowAnonymousComments, setAllowAnonymousComments] = useState(true);
  const [allowAnonymousPosts, setAllowAnonymousPosts] = useState(true);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!name.trim()) {
        setError('Il nome della board è obbligatorio.');
        return;
    }

    if (accessType === 'password' && !password) {
        setError('La password è obbligatoria per le board protette.');
        return;
    }

    const feeNum = parseInt(entryFee, 10);
    if (accessType === 'paid' && (isNaN(feeNum) || feeNum <= 0)) {
        setError('Inserisci un prezzo di ingresso valido in Kopeki.');
        return;
    }

    const { success, message, board } = createBoard(
        name.trim(), 
        description.trim(), 
        allowAnonymousComments, 
        allowAnonymousPosts, 
        accessType === 'password' ? password : undefined, 
        accessType === 'invite',
        undefined, // iconUrl
        undefined, // bannerUrl
        accessType === 'paid' ? feeNum : 0
    );

    if (success && board) {
      navigate(`/b/${board.name}`);
      onClose();
    } else {
      setError(message);
    }
  };

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-[60] p-4">
      <div className="bg-white rounded-2xl w-full max-w-xl relative border border-gray-200 shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
        {/* Header */}
        <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-gray-50/50">
          <div>
            <h2 className="text-2xl font-black text-gray-900 tracking-tight">Crea una Community</h2>
            <p className="text-sm text-gray-500 font-medium">Configura il tuo spazio in un unico passaggio.</p>
          </div>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-700 transition-colors p-2 hover:bg-gray-100 rounded-full">
            <CloseIcon className="w-6 h-6" />
          </button>
        </div>

        {/* Body */}
        <div className="flex-1 overflow-y-auto p-6 space-y-8">
            {error && (
                <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-xl text-sm font-semibold animate-in fade-in slide-in-from-top-1">
                    {error}
                </div>
            )}

            <form id="create-board-form" onSubmit={handleSubmit} className="space-y-8">
                {/* Info Base */}
                <section className="space-y-4">
                    <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest px-1 flex items-center gap-2">
                        <span className="w-4 h-px bg-gray-200"></span> Informazioni Base
                    </h3>
                    <div className="space-y-4">
                        <div>
                            <label className="block text-sm font-bold text-gray-700 mb-2 ml-1">Nome Board</label>
                            <div className="relative">
                                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 font-bold">b/</span>
                                <input 
                                    type="text" 
                                    value={name} 
                                    onChange={e => setName(e.target.value.replace(/\s+/g, '_').toLowerCase())} 
                                    className="w-full bg-gray-50 border border-gray-200 rounded-xl p-3 pl-8 text-gray-900 focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none font-bold transition-all" 
                                    placeholder="nome_community" 
                                    required 
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-bold text-gray-700 mb-2 ml-1">Descrizione</label>
                            <textarea 
                                value={description} 
                                onChange={e => setDescription(e.target.value)} 
                                className="w-full bg-gray-50 border border-gray-200 rounded-xl p-3 text-gray-800 focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none resize-none transition-all" 
                                placeholder="Di cosa tratta questa community?"
                                rows={3}
                            />
                        </div>
                    </div>
                </section>

                {/* Privacy & Accesso */}
                <section className="space-y-4">
                    <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest px-1 flex items-center gap-2">
                        <span className="w-4 h-px bg-gray-200"></span> Privacy e Accesso
                    </h3>
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        {[
                            { id: 'public', label: 'Pubblica', desc: 'Visibile a chiunque.', icon: <UsersIcon className="w-4 h-4" /> },
                            { id: 'password', label: 'Password', desc: 'Accesso con chiave segreta.', icon: <LockIcon className="w-4 h-4" /> },
                            { id: 'invite', label: 'Solo Invito', desc: 'Gli admin inviano PM di invito.', icon: <UsersIcon className="w-4 h-4" /> },
                            { id: 'paid', label: 'Premium', desc: 'Si paga in Kopeki per entrare.', icon: <WalletIcon className="w-4 h-4" /> }
                        ].map((type) => (
                            <label key={type.id} className={`flex items-center gap-3 p-4 border rounded-xl cursor-pointer transition-all ${accessType === type.id ? 'bg-primary/5 border-primary ring-1 ring-primary' : 'bg-white border-gray-200 hover:border-gray-300'}`}>
                                <input 
                                    type="radio" 
                                    name="accessType" 
                                    checked={accessType === type.id} 
                                    onChange={() => setAccessType(type.id as any)} 
                                    className="accent-primary w-4 h-4" 
                                />
                                <div className="flex-1">
                                    <div className="flex items-center gap-2">
                                        <span className="text-sm font-black text-gray-900">{type.label}</span>
                                    </div>
                                    <p className="text-[10px] text-gray-500 font-bold leading-tight">{type.desc}</p>
                                </div>
                            </label>
                        ))}
                    </div>

                    {accessType === 'password' && (
                        <div className="p-4 bg-yellow-50 rounded-xl border border-yellow-200 animate-in zoom-in-95 mt-2">
                            <label className="block text-xs font-black text-yellow-800 uppercase mb-2">Imposta Password Board</label>
                            <input 
                                type="text" 
                                value={password} 
                                onChange={e => setPassword(e.target.value)} 
                                className="w-full bg-white border border-yellow-300 rounded-lg p-2.5 text-sm focus:ring-2 focus:ring-yellow-500/20 focus:border-yellow-600 outline-none" 
                                placeholder="Chiave segreta..." 
                            />
                        </div>
                    )}

                    {accessType === 'paid' && (
                        <div className="p-4 bg-green-50 rounded-xl border border-green-200 animate-in zoom-in-95 mt-2">
                            <label className="block text-xs font-black text-green-800 uppercase mb-2">Prezzo di Ingresso (Kopeki)</label>
                            <div className="relative">
                                <input 
                                    type="number" 
                                    value={entryFee} 
                                    onChange={e => setEntryFee(e.target.value)} 
                                    className="w-full bg-white border border-green-300 rounded-lg p-2.5 pl-8 text-sm focus:ring-2 focus:ring-green-500/20 focus:border-green-600 outline-none font-bold" 
                                    min="1"
                                />
                                <span className="absolute left-3 top-1/2 -translate-y-1/2 text-green-600 font-bold text-xs">K</span>
                            </div>
                        </div>
                    )}
                </section>

                {/* Regole Community */}
                <section className="space-y-4">
                    <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest px-1 flex items-center gap-2">
                        <span className="w-4 h-px bg-gray-200"></span> Regole della Community
                    </h3>
                    <div className="space-y-3 bg-gray-50 rounded-xl p-4 border border-gray-100">
                        <label className="flex items-center justify-between cursor-pointer group">
                            <div className="flex-1">
                                <span className="block text-sm font-bold text-gray-700">Consenti Post Anonimi</span>
                                <span className="text-[10px] text-gray-400">Gli utenti possono postare senza mostrare il nome.</span>
                            </div>
                            <input 
                                type="checkbox" 
                                checked={allowAnonymousPosts} 
                                onChange={e => setAllowAnonymousPosts(e.target.checked)} 
                                className="w-5 h-5 accent-primary rounded cursor-pointer"
                            />
                        </label>
                        <div className="h-px bg-gray-200/50" />
                        <label className="flex items-center justify-between cursor-pointer group">
                            <div className="flex-1">
                                <span className="block text-sm font-bold text-gray-700">Consenti Commenti Anonimi</span>
                                <span className="text-[10px] text-gray-400">Abilita identità nascoste nei thread.</span>
                            </div>
                            <input 
                                type="checkbox" 
                                checked={allowAnonymousComments} 
                                onChange={e => setAllowAnonymousComments(e.target.checked)} 
                                className="w-5 h-5 accent-primary rounded cursor-pointer"
                            />
                        </label>
                    </div>
                </section>
            </form>
        </div>

        {/* Footer */}
        <div className="p-6 border-t border-gray-100 flex justify-end gap-3 bg-gray-50/50">
            <button type="button" onClick={onClose} className="px-6 py-2.5 text-sm font-bold text-gray-500 hover:text-gray-800 transition-colors">Annulla</button>
            <button 
                type="submit" 
                form="create-board-form"
                className="bg-primary text-white font-black py-2.5 px-10 rounded-full hover:bg-orange-600 transition-all shadow-lg shadow-primary/20 active:scale-95 disabled:grayscale"
                disabled={!name.trim()}
            >
                Crea Board
            </button>
        </div>
      </div>
    </div>
  );
};

export default CreateBoardModal;

import React, { useState, useEffect, useRef } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { useData, useAuth } from '../hooks/useStore';
import NotFoundPage from './NotFoundPage';
import BoardIcon from '../components/BoardIcon';
import { CheckIcon, CloseIcon, MessageIcon } from '../components/Icons';

const BoardSettingsPage: React.FC = () => {
  const { boardName } = useParams<{ boardName: string }>();
  const { getBoardByName, appointModerator, isBoardAdmin, appointAdmin, updateBoard, inviteUserToBoard, removeUserFromBoard, ads, approveAd, rejectAd } = useData();
  const { currentUser, isAdmin, getUserById, users } = useAuth();
  const navigate = useNavigate();

  const board = boardName ? getBoardByName(boardName) : undefined;

  // State for appearance
  const [iconUrl, setIconUrl] = useState('');
  const [bannerUrl, setBannerUrl] = useState('');
  const [description, setDescription] = useState('');
  const [appearanceMessage, setAppearanceMessage] = useState({ type: '', text: '' });
  const iconInputRef = useRef<HTMLInputElement>(null);
  const bannerInputRef = useRef<HTMLInputElement>(null);
  const [previewBannerSrc, setPreviewBannerSrc] = useState('');

  // State for moderation
  const [modUsername, setModUsername] = useState('');
  const [modMessage, setModMessage] = useState({ type: '', text: '' });
  const [modSuggestions, setModSuggestions] = useState<string[]>([]);

  // State for administration
  const [adminUsername, setAdminUsername] = useState('');
  const [adminMessage, setAdminMessage] = useState({ type: '', text: '' });
  const [adminSuggestions, setAdminSuggestions] = useState<string[]>([]);

  // State for security/privacy
  const [accessType, setAccessType] = useState<'public' | 'password' | 'invite' | 'paid'>('public');
  const [newPassword, setNewPassword] = useState('');
  const [entryFee, setEntryFee] = useState('');
  const [allowAnonymousComments, setAllowAnonymousComments] = useState(false);
  const [allowAnonymousPosts, setAllowAnonymousPosts] = useState(false);
  const [securityMessage, setSecurityMessage] = useState({ type: '', text: '' });

  // State for invites
  const [inviteUsername, setInviteUsername] = useState('');
  const [inviteMessage, setInviteMessage] = useState({ type: '', text: '' });
  const [inviteSuggestions, setInviteSuggestions] = useState<string[]>([]);

  useEffect(() => {
    if (!currentUser) {
        navigate('/');
        return;
    }
    if (board) {
        const canManage = isAdmin(currentUser.id) || isBoardAdmin(currentUser.id, board.id);
        if (!canManage) {
            navigate(`/b/${board.name}`);
        }
        setIconUrl(board.iconUrl || '');
        setBannerUrl(board.bannerUrl || '');
        setDescription(board.description || '');
        setAllowAnonymousComments(board.allowAnonymousComments);
        setAllowAnonymousPosts(board.allowAnonymousPosts || false);

        if (board.isInviteOnly) {
            setAccessType('invite');
        } else if (board.password) {
            setAccessType('password');
            setNewPassword(board.password);
        } else if (board.entryFee && board.entryFee > 0) {
            setAccessType('paid');
            setEntryFee(board.entryFee.toString());
        } else {
            setAccessType('public');
        }
    }
  }, [currentUser, board, isAdmin, isBoardAdmin, navigate]);

  const defaultBannerUrl = board ? `https://picsum.photos/seed/${board.id}/1000/200` : '';

  useEffect(() => {
    if (bannerUrl) {
      const img = new Image();
      img.src = bannerUrl;
      img.onload = () => setPreviewBannerSrc(bannerUrl);
      img.onerror = () => setPreviewBannerSrc(defaultBannerUrl);
    } else {
      setPreviewBannerSrc(defaultBannerUrl);
    }
  }, [bannerUrl, defaultBannerUrl]);


  if (!board) {
    return <NotFoundPage />;
  }

  const boardAdmins = board.adminIds.map(id => getUserById(id)).filter(Boolean) as { id: string, username: string }[];
  const boardModerators = board.moderatorIds.map(id => getUserById(id)).filter(Boolean) as { id: string, username: string }[];
  const allowedUsers = (board.allowedUserIds || []).map(id => getUserById(id)).filter(Boolean) as { id: string, username: string }[];
  const boardAds = ads.filter(ad => ad.boardId === board.id && (ad.status === 'pending' || ad.status === 'active'));

  const fileToDataUrl = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = () => resolve(reader.result as string);
        reader.onerror = reject;
        reader.readAsDataURL(file);
    });
  };

  const handleIconUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (!file.type.startsWith('image/')) {
        setAppearanceMessage({ type: 'error', text: 'Please select a valid image file.' });
        return;
      }
      try {
        const dataUrl = await fileToDataUrl(file);
        setIconUrl(dataUrl);
        setAppearanceMessage({ type: '', text: '' });
      } catch (error) {
        setAppearanceMessage({ type: 'error', text: 'Failed to read image file.' });
      }
    }
  };

  const handleBannerUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (!file.type.startsWith('image/')) {
        setAppearanceMessage({ type: 'error', text: 'Please select a valid image file.' });
        return;
      }
      try {
        const dataUrl = await fileToDataUrl(file);
        setBannerUrl(dataUrl);
        setAppearanceMessage({ type: '', text: '' });
      } catch (error) {
        setAppearanceMessage({ type: 'error', text: 'Failed to read image file.' });
      }
    }
  };

  const handleAppearanceSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setAppearanceMessage({ type: '', text: '' });
    const result = updateBoard(board.id, { iconUrl, bannerUrl, description });
    setAppearanceMessage({ type: result.success ? 'success' : 'error', text: result.message });
    setTimeout(() => setAppearanceMessage({ type: '', text: '' }), 4000);
  };

  const handleSecuritySubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setSecurityMessage({ type: '', text: '' });

    let updateData: any = {
        allowAnonymousComments,
        allowAnonymousPosts
    };

    if (accessType === 'public') {
        updateData = { ...updateData, password: '', isInviteOnly: false, entryFee: 0 };
    } else if (accessType === 'password') {
        if (!newPassword) {
             setSecurityMessage({ type: 'error', text: 'Password cannot be empty.' });
             return;
        }
        updateData = { ...updateData, password: newPassword, isInviteOnly: false, entryFee: 0 };
    } else if (accessType === 'invite') {
        updateData = { ...updateData, password: '', isInviteOnly: true, entryFee: 0 };
    } else if (accessType === 'paid') {
        const fee = parseInt(entryFee, 10);
        if (isNaN(fee) || fee <= 0) {
            setSecurityMessage({ type: 'error', text: 'Invalid entry fee.' });
            return;
        }
        updateData = { ...updateData, password: '', isInviteOnly: false, entryFee: fee };
    }

    const result = updateBoard(board.id, updateData);
    setSecurityMessage({ type: result.success ? 'success' : 'error', text: result.message });
    setTimeout(() => setSecurityMessage({ type: '', text: '' }), 4000);
  }

  const handleUserSearchChange = (value: string, setter: (v: string) => void, suggestionsSetter: (v: string[]) => void) => {
    setter(value);
    if (value.length > 0) {
      const filteredUsers = users
        .filter(u => u.username.toLowerCase().startsWith(value.toLowerCase()))
        .map(u => u.username)
        .slice(0, 5);
      suggestionsSetter(filteredUsers);
    } else {
      suggestionsSetter([]);
    }
  };

  const handleAppointAdmin = (e: React.FormEvent) => {
    e.preventDefault();
    if (!adminUsername.trim()) return;
    const result = appointAdmin(board.id, adminUsername);
    setAdminMessage({ type: result.success ? 'success' : 'error', text: result.message });
    if(result.success) setAdminUsername('');
    setAdminSuggestions([]);
    setTimeout(() => setAdminMessage({type: '', text: ''}), 3000);
  };

  const handleAppointModerator = (e: React.FormEvent) => {
    e.preventDefault();
    if (!modUsername.trim()) return;
    const result = appointModerator(board.id, modUsername);
    setModMessage({ type: result.success ? 'success' : 'error', text: result.message });
    if (result.success) setModUsername('');
    setModSuggestions([]);
    setTimeout(() => setModMessage({ type: '', text: '' }), 3000);
  };

  const handleInviteUser = (e: React.FormEvent) => {
      e.preventDefault();
      if (!inviteUsername.trim()) return;
      const result = inviteUserToBoard(board.id, inviteUsername);
      setInviteMessage({ type: result.success ? 'success' : 'error', text: result.message });
      if (result.success) {
          setInviteUsername('');
          setInviteMessage({ type: 'success', text: `Messaggio d'invito inviato a ${inviteUsername}!` });
      }
      setInviteSuggestions([]);
      setTimeout(() => setInviteMessage({ type: '', text: '' }), 4000);
  };

  const handleRemoveUser = (userId: string) => {
      if (window.confirm('Revocare l\'accesso a questo utente?')) {
          removeUserFromBoard(board.id, userId);
      }
  };

  return (
    <div className="container mx-auto p-4 md:p-6 max-w-4xl">
      <Link to={`/b/${board.name}`} className="text-gray-500 hover:text-gray-900 mb-6 inline-block font-medium">&larr; Torna alla Board</Link>
      <div className="flex items-center gap-4 mb-8">
          <BoardIcon board={board} className="w-16 h-16"/>
          <h1 className="text-3xl font-bold text-gray-900">Impostazioni: b/{board.name}</h1>
      </div>

      <div className="space-y-8">

        {/* SECTION 1: APPEARANCE */}
        <div className="bg-white rounded-md border border-gray-200 p-6 shadow-sm">
            <h2 className="text-xl font-bold text-gray-800 mb-4 border-b border-gray-100 pb-2">Aspetto</h2>
            <form onSubmit={handleAppearanceSubmit} className="space-y-4">
                 {appearanceMessage.text && (
                    <p className={`p-3 rounded-md text-sm ${appearanceMessage.type === 'success' ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                        {appearanceMessage.text}
                    </p>
                )}

                <div className="flex gap-6 items-start">
                    <div className="flex-1">
                        <label className="block text-sm font-semibold text-gray-700 mb-2">Icona</label>
                        <div className="flex items-center gap-4">
                            <div className="w-16 h-16 rounded-full bg-gray-100 overflow-hidden border border-gray-200">
                                {iconUrl ? <img src={iconUrl} alt="icon" className="w-full h-full object-cover"/> : <BoardIcon board={board} className="w-full h-full"/>}
                            </div>
                             <div>
                                <button type="button" onClick={() => iconInputRef.current?.click()} className="px-4 py-2 bg-gray-100 hover:bg-gray-200 text-gray-700 rounded-md text-sm font-semibold transition-colors">Carica</button>
                                <input type="file" ref={iconInputRef} onChange={handleIconUpload} accept="image/*" className="hidden"/>
                            </div>
                        </div>
                    </div>
                     <div className="flex-1">
                        <label className="block text-sm font-semibold text-gray-700 mb-2">Banner</label>
                         <div 
                            className="h-20 w-full bg-gray-100 rounded-md bg-cover bg-center border border-gray-200 mb-2"
                            style={{ backgroundImage: `url(${previewBannerSrc})` }}
                         ></div>
                         <div>
                            <button type="button" onClick={() => bannerInputRef.current?.click()} className="px-4 py-2 bg-gray-100 hover:bg-gray-200 text-gray-700 rounded-md text-sm font-semibold transition-colors">Carica Banner</button>
                             <input type="file" ref={bannerInputRef} onChange={handleBannerUpload} accept="image/*" className="hidden"/>
                        </div>
                    </div>
                </div>

                <div>
                    <label className="block text-sm font-semibold text-gray-700 mb-1">Descrizione</label>
                    <textarea 
                        value={description} 
                        onChange={(e) => setDescription(e.target.value)}
                        className="w-full border border-gray-300 rounded-md p-2 focus:ring-primary focus:border-primary"
                        rows={3}
                        placeholder="Di cosa tratta questa community?"
                    />
                </div>

                <div className="flex justify-end">
                    <button type="submit" className="bg-primary text-white font-bold py-2 px-6 rounded-md hover:opacity-90 transition-opacity">Salva Aspetto</button>
                </div>
            </form>
        </div>

        {/* SECTION 2: ACCESS & SECURITY */}
        <div className="bg-white rounded-md border border-gray-200 p-6 shadow-sm">
             <h2 className="text-xl font-bold text-gray-800 mb-4 border-b border-gray-100 pb-2">Accesso e Permessi</h2>
             <form onSubmit={handleSecuritySubmit} className="space-y-6">
                {securityMessage.text && (
                    <p className={`p-3 rounded-md text-sm ${securityMessage.type === 'success' ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                        {securityMessage.text}
                    </p>
                )}

                <div className="grid grid-cols-2 gap-4">
                    {['public', 'password', 'invite', 'paid'].map((type) => (
                         <label key={type} className={`border rounded-lg p-3 cursor-pointer hover:bg-gray-50 ${accessType === type ? 'border-primary ring-1 ring-primary bg-blue-50' : 'border-gray-200'}`}>
                            <div className="flex items-center gap-2 mb-1">
                                <input 
                                    type="radio" 
                                    name="accessType" 
                                    value={type} 
                                    checked={accessType === type} 
                                    onChange={(e) => setAccessType(e.target.value as any)}
                                    className="accent-primary"
                                />
                                <span className="font-bold text-gray-800 capitalize">{type === 'invite' ? 'Solo Invito' : type === 'paid' ? 'Premium' : type}</span>
                            </div>
                            <p className="text-[10px] text-gray-500 pl-6 leading-tight">
                                {type === 'public' && 'Chiunque può visualizzare e postare.'}
                                {type === 'password' && 'Richiede una chiave per visualizzare i post.'}
                                {type === 'invite' && 'Solo gli utenti invitati tramite PM possono entrare.'}
                                {type === 'paid' && 'Richiede il pagamento di Kopeki per l\'accesso.'}
                            </p>
                         </label>
                    ))}
                </div>

                {accessType === 'password' && (
                    <div className="bg-yellow-50 p-4 rounded-md border border-yellow-200">
                        <label className="block text-sm font-bold text-yellow-800 mb-1">Imposta Password</label>
                        <input 
                            type="text" 
                            value={newPassword} 
                            onChange={(e) => setNewPassword(e.target.value)} 
                            className="w-full border border-yellow-300 rounded p-2"
                            placeholder="Inserisci la password della board"
                        />
                    </div>
                )}

                {accessType === 'paid' && (
                     <div className="bg-green-50 p-4 rounded-md border border-green-200">
                        <label className="block text-sm font-bold text-green-800 mb-1">Fee di ingresso (Kopeki)</label>
                        <input 
                            type="number" 
                            value={entryFee} 
                            onChange={(e) => setEntryFee(e.target.value)} 
                            className="w-full border border-green-300 rounded p-2"
                            placeholder="es. 500"
                            min="1"
                        />
                    </div>
                )}

                <div className="border-t border-gray-100 pt-4 space-y-3">
                    <label className="flex items-center gap-3 cursor-pointer">
                        <input type="checkbox" checked={allowAnonymousPosts} onChange={e => setAllowAnonymousPosts(e.target.checked)} className="w-5 h-5 accent-primary" disabled={accessType !== 'public'} />
                        <div>
                             <span className={`block font-semibold text-sm ${accessType !== 'public' ? 'text-gray-400' : 'text-gray-700'}`}>Consenti Post Anonimi</span>
                             <span className="text-xs text-gray-500">Solo per board pubbliche.</span>
                        </div>
                    </label>
                    <label className="flex items-center gap-3 cursor-pointer">
                        <input type="checkbox" checked={allowAnonymousComments} onChange={e => setAllowAnonymousComments(e.target.checked)} className="w-5 h-5 accent-primary" disabled={accessType !== 'public'} />
                         <div>
                             <span className={`block font-semibold text-sm ${accessType !== 'public' ? 'text-gray-400' : 'text-gray-700'}`}>Consenti Commenti Anonimi</span>
                             <span className="text-xs text-gray-500">Solo per board pubbliche.</span>
                        </div>
                    </label>
                </div>

                <div className="flex justify-end">
                    <button type="submit" className="bg-primary text-white font-bold py-2 px-6 rounded-md hover:opacity-90 transition-opacity">Aggiorna Sicurezza</button>
                </div>
             </form>

             {/* Invite Management */}
             {(accessType === 'invite' || accessType === 'paid') && (
                 <div className="mt-8 border-t border-gray-100 pt-6">
                     <h3 className="font-bold text-gray-900 mb-1 flex items-center gap-2">
                        <MessageIcon className="w-5 h-5 text-primary" /> Invia Inviti
                     </h3>
                     <p className="text-xs text-gray-500 mb-4">Cerca un utente per inviargli un messaggio privato d'invito.</p>

                     <form onSubmit={handleInviteUser} className="flex gap-2 mb-4 relative">
                        <input
                            type="text"
                            value={inviteUsername}
                            onChange={(e) => handleUserSearchChange(e.target.value, setInviteUsername, setInviteSuggestions)}
                            placeholder="Username da invitare..."
                            className="flex-1 border border-gray-300 rounded-md p-2"
                        />
                        <button type="submit" className="bg-gray-900 text-white font-bold px-4 rounded-md">Invia PM</button>
                         {inviteSuggestions.length > 0 && (
                            <ul className="absolute top-full left-0 w-full bg-white border border-gray-200 rounded-md shadow-lg z-10 max-h-40 overflow-y-auto">
                                {inviteSuggestions.map(s => (
                                    <li key={s} onClick={() => { setInviteUsername(s); setInviteSuggestions([]); }} className="px-4 py-2 hover:bg-gray-100 cursor-pointer text-sm">
                                        {s}
                                    </li>
                                ))}
                            </ul>
                        )}
                     </form>
                     {inviteMessage.text && (
                        <p className={`mb-3 text-xs font-bold ${inviteMessage.type === 'success' ? 'text-green-600' : 'text-red-600'}`}>
                            {inviteMessage.text}
                        </p>
                    )}

                     <div className="mt-6">
                        <h4 className="text-sm font-bold text-gray-700 mb-2">Utenti con Accesso ({allowedUsers.length})</h4>
                        <div className="bg-gray-50 rounded-md border border-gray-200 max-h-60 overflow-y-auto">
                            {allowedUsers.length > 0 ? (
                                <ul className="divide-y divide-gray-200">
                                    {allowedUsers.map(u => (
                                        <li key={u.id} className="p-3 flex justify-between items-center">
                                            <div className="flex items-center gap-2">
                                                <div className="w-8 h-8 bg-gray-300 rounded-full flex items-center justify-center font-bold text-white text-xs">
                                                    {u.username[0].toUpperCase()}
                                                </div>
                                                <span className="text-sm font-medium text-gray-700">{u.username}</span>
                                            </div>
                                            {u.id !== board.creatorId && (
                                                <button onClick={() => handleRemoveUser(u.id)} className="text-red-400 hover:text-red-600 hover:bg-red-50 p-1 rounded transition-colors" title="Rimuovi accesso">
                                                    <CloseIcon className="w-4 h-4"/>
                                                </button>
                                            )}
                                        </li>
                                    ))}
                                </ul>
                            ) : (
                                <p className="p-4 text-center text-gray-500 text-sm">Nessun utente aggiunto oltre al creatore.</p>
                            )}
                        </div>
                     </div>
                 </div>
             )}
        </div>

        {/* SECTION 3: ROLES */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
             <div className="bg-white rounded-md border border-gray-200 p-6 shadow-sm">
                <h2 className="text-xl font-bold text-gray-800 mb-4">Amministratori</h2>
                <form onSubmit={handleAppointAdmin} className="relative mb-4">
                    <div className="flex gap-2">
                        <input
                            type="text"
                            value={adminUsername}
                            onChange={(e) => handleUserSearchChange(e.target.value, setAdminUsername, setAdminSuggestions)}
                            placeholder="Aggiungi admin..."
                            className="flex-1 border border-gray-300 rounded-md p-2 text-sm"
                        />
                        <button type="submit" className="bg-gray-800 text-white font-bold px-3 rounded-md text-sm">Add</button>
                    </div>
                    {adminSuggestions.length > 0 && (
                        <ul className="absolute top-full left-0 w-full bg-white border border-gray-200 rounded-md shadow-lg z-10 mt-1">
                            {adminSuggestions.map(s => (
                                <li key={s} onClick={() => { setAdminUsername(s); setAdminSuggestions([]); }} className="px-4 py-2 hover:bg-gray-100 cursor-pointer text-sm">
                                    {s}
                                </li>
                            ))}
                        </ul>
                    )}
                    {adminMessage.text && <p className={`mt-2 text-xs ${adminMessage.type === 'success' ? 'text-green-600' : 'text-red-600'}`}>{adminMessage.text}</p>}
                </form>
                <div className="space-y-2">
                    {boardAdmins.map(admin => (
                        <div key={admin.id} className="flex items-center gap-2 p-2 bg-gray-50 rounded border border-gray-100">
                             <span className="w-2 h-2 bg-green-500 rounded-full"></span>
                             <span className="text-sm font-medium text-gray-700">{admin.username}</span>
                        </div>
                    ))}
                </div>
            </div>

            <div className="bg-white rounded-md border border-gray-200 p-6 shadow-sm">
                <h2 className="text-xl font-bold text-gray-800 mb-4">Moderatori</h2>
                <form onSubmit={handleAppointModerator} className="relative mb-4">
                    <div className="flex gap-2">
                        <input
                            type="text"
                            value={modUsername}
                            onChange={(e) => handleUserSearchChange(e.target.value, setModUsername, setModSuggestions)}
                            placeholder="Aggiungi mod..."
                            className="flex-1 border border-gray-300 rounded-md p-2 text-sm"
                        />
                        <button type="submit" className="bg-gray-800 text-white font-bold px-3 rounded-md text-sm">Add</button>
                    </div>
                    {modSuggestions.length > 0 && (
                        <ul className="absolute top-full left-0 w-full bg-white border border-gray-200 rounded-md shadow-lg z-10 mt-1">
                            {modSuggestions.map(s => (
                                <li key={s} onClick={() => { setModUsername(s); setModSuggestions([]); }} className="px-4 py-2 hover:bg-gray-100 cursor-pointer text-sm">
                                    {s}
                                </li>
                            ))}
                        </ul>
                    )}
                     {modMessage.text && <p className={`mt-2 text-xs ${modMessage.type === 'success' ? 'text-green-600' : 'text-red-600'}`}>{modMessage.text}</p>}
                </form>
                <div className="space-y-2">
                    {boardModerators.length > 0 ? boardModerators.map(mod => (
                        <div key={mod.id} className="flex items-center gap-2 p-2 bg-gray-50 rounded border border-gray-100">
                             <span className="w-2 h-2 bg-blue-500 rounded-full"></span>
                             <span className="text-sm font-medium text-gray-700">{mod.username}</span>
                        </div>
                    )) : <p className="text-sm text-gray-400 italic">Nessun moderatore nominato.</p>}
                </div>
            </div>
        </div>

        {/* SECTION 4: ADVERTISEMENTS */}
        <div className="bg-white rounded-md border border-gray-200 p-6 shadow-sm">
             <h2 className="text-xl font-bold text-gray-800 mb-4">Richieste Pubblicitarie</h2>
             {boardAds.length > 0 ? (
                 <div className="space-y-4">
                     {boardAds.map(ad => (
                         <div key={ad.id} className="border border-gray-200 rounded-lg p-4 flex flex-col md:flex-row gap-4 items-start">
                             {ad.imageUrl && <img src={ad.imageUrl} alt="ad" className="w-20 h-20 object-cover rounded bg-gray-100 flex-shrink-0" />}
                             <div className="flex-1">
                                 <div className="flex justify-between items-start">
                                     <h4 className="font-bold text-gray-900">{ad.title}</h4>
                                     <span className={`text-[10px] font-black px-2 py-0.5 rounded uppercase ${ad.status === 'active' ? 'bg-green-100 text-green-700' : 'bg-yellow-100 text-yellow-700'}`}>{ad.status}</span>
                                 </div>
                                 <p className="text-xs text-gray-600 mb-2">{ad.content}</p>
                                 <div className="flex gap-4 text-[10px] font-bold text-gray-400">
                                     <span>Budget: {ad.budget} K</span>
                                     <span>Modello: {ad.model}</span>
                                     <span>Viste: {ad.views}</span>
                                     <span>Click: {ad.clicks}</span>
                                 </div>
                             </div>
                             <div className="flex flex-col gap-2 min-w-[100px]">
                                 {ad.status === 'pending' && (
                                     <>
                                        <button onClick={() => approveAd(ad.id)} className="bg-green-600 text-white text-xs font-bold py-1.5 px-3 rounded-full hover:bg-green-700 shadow-sm transition-all">Approva</button>
                                        <button onClick={() => rejectAd(ad.id)} className="bg-red-50 text-red-600 text-xs font-bold py-1.5 px-3 rounded-full hover:bg-red-100 transition-all">Rifiuta</button>
                                     </>
                                 )}
                                 {ad.status === 'active' && (
                                     <button onClick={() => rejectAd(ad.id)} className="border border-red-200 text-red-600 text-xs font-bold py-1.5 px-3 rounded-full hover:bg-red-50 transition-all">Ferma Ad</button>
                                 )}
                             </div>
                         </div>
                     ))}
                 </div>
             ) : (
                 <p className="text-gray-400 text-sm italic py-4 text-center border-2 border-dashed border-gray-100 rounded-xl">Nessuna richiesta pubblicitaria per questa board.</p>
             )}
        </div>

      </div>
    </div>
  );
};

export default BoardSettingsPage;

import React, { useState } from 'react';
import { CloseIcon, CheckIcon, ReportIcon } from './Icons';

interface ReportModalProps {
  entityId: string;
  entityType: 'post' | 'comment';
  onClose: () => void;
}

const ReportModal: React.FC<ReportModalProps> = ({ entityId, entityType, onClose }) => {
  const [isSubmitted, setIsSubmitted] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Logica di segnalazione semplificata: il contenuto è segnalato, i mod decideranno il perché.
    console.log({
      report: 'Content Flagged',
      entityType,
      entityId,
      timestamp: new Date().toISOString()
    });

    setIsSubmitted(true);
    // Chiusura automatica dopo 2 secondi per migliorare la UX
