import React, { useRef } from 'react';
import { ImageFileIcon, VideoFileIcon, AudioFileIcon, FileIcon, CloseIcon } from './Icons';
import type { MediaItem } from '../types';

interface MediaUploaderProps {
  media: MediaItem[];
  onChange: (media: MediaItem[]) => void;
}

const MediaUploader: React.FC<MediaUploaderProps> = ({ media, onChange }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    const newMediaItems: MediaItem[] = [];

    for (let i = 0; i < files.length; i++) {
      const file = files[i];
      let type: 'image' | 'video' | 'audio' | 'file' = 'file';

      if (file.type.startsWith('image/')) type = 'image';
      else if (file.type.startsWith('video/')) type = 'video';
      else if (file.type.startsWith('audio/')) type = 'audio';

      const url = await fileToDataUrl(file);
      newMediaItems.push({
        id: crypto.randomUUID(),
        type,
        url,
        name: file.name
      });
    }

    onChange([...media, ...newMediaItems]);

    // Reset input
    if (fileInputRef.current) {
        fileInputRef.current.value = '';
    }
  };

  const fileToDataUrl = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });
  };

  const removeMedia = (id: string) => {
    onChange(media.filter(item => item.id !== id));
  };

  const getIcon = (type: string) => {
      switch(type) {
          case 'image': return <ImageFileIcon className="w-6 h-6 text-blue-500" />;
          case 'video': return <VideoFileIcon className="w-6 h-6 text-purple-500" />;
          case 'audio': return <AudioFileIcon className="w-6 h-6 text-orange-500" />;
          case 'file': return <FileIcon className="w-6 h-6 text-gray-500" />;
          default: return null;
      }
  }

  return (
    <div className="space-y-4">
      <div className="flex gap-4">
        <button
          type="button"
          onClick={() => fileInputRef.current?.click()}
          className="flex items-center gap-2 px-4 py-2 bg-gray-100 text-gray-700 rounded-md hover:bg-gray-200 transition-colors border border-gray-300"
        >
          <span className="text-xl font-bold">+</span>
          <span className="text-sm font-bold">Aggiungi File</span>
        </button>
        <input
          type="file"
          ref={fileInputRef}
          onChange={handleFileChange}
          accept="*"
          multiple
          className="hidden"
        />
      </div>

      {media.length > 0 && (
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          {media.map((item) => (
            <div key={item.id} className="relative group bg-gray-50 border border-gray-200 rounded-md overflow-hidden aspect-square flex items-center justify-center">
               <button
                  type="button"
                  onClick={() => removeMedia(item.id)}
                  className="absolute top-1 right-1 bg-red-500 text-white p-1 rounded-full opacity-0 group-hover:opacity-100 transition-opacity z-10 hover:bg-red-600"
                  title="Remove"
                >
                  <CloseIcon className="w-4 h-4" />
                </button>

              {item.type === 'image' && (
                <img src={item.url} alt="preview" className="w-full h-full object-cover" />
              )}
              {item.type === 'video' && (
                <video src={item.url} className="w-full h-full object-cover" />
              )}
              {(item.type === 'audio' || item.type === 'file') && (
                 <div className="flex flex-col items-center px-2 text-center">
                    {item.type === 'audio' ? <AudioFileIcon className="w-8 h-8 text-gray-400 mb-1" /> : <FileIcon className="w-8 h-8 text-gray-400 mb-1" />}
                    <span className="text-[10px] text-gray-500 truncate w-full">{item.name || (item.type === 'audio' ? 'Audio Clip' : 'File')}</span>
                 </div>
              )}
               <div className="absolute bottom-1 left-1 bg-white/80 p-1 rounded-full shadow-sm">
                 {getIcon(item.type)}
               </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default MediaUploader;

import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { ChevronLeftIcon, ChevronRightIcon, CloseIcon, FileIcon } from './Icons';
import type { MediaItem } from '../types';

interface PostMediaProps {
  media: MediaItem[];
  postLink?: string; // If provided, clicking navigates to this link (Preview Mode)
  compact?: boolean; // Use compact layout (e.g. for messages)
}

const PostMedia: React.FC<PostMediaProps> = ({ media, postLink, compact = false }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isExpanded, setIsExpanded] = useState(false);

  if (!media || media.length === 0) return null;

  // CSS classes based on mode
  const containerMargin = compact ? 'mt-1' : 'mt-4';
  const splitViewHeight = compact ? 'h-[200px]' : 'h-[400px]';
  const carouselHeight = compact ? 'h-[300px]' : 'h-[500px]';
  const singleMediaMaxHeight = compact ? 'max-h-[300px]' : 'max-h-[600px]';

  // Helper to render non-interactive previews (for Single Item Preview & Split View)
  const renderPreviewContent = (item: MediaItem) => {
      if (item.type === 'image') {
          return <img src={item.url} alt="media preview" className="w-full h-full object-cover" />;
      }
      if (item.type === 'video') {
          return (
            <div className="w-full h-full relative">
                <video src={item.url} className="w-full h-full object-cover pointer-events-none" />
                <div className="absolute inset-0 flex items-center justify-center bg-black/20">
                    <div className="w-12 h-12 rounded-full bg-white/30 backdrop-blur-sm flex items-center justify-center border-2 border-white">
                        <div className="ml-1 w-0 h-0 border-t-[8px] border-t-transparent border-l-[14px] border-l-white border-b-[8px] border-b-transparent"></div>
                    </div>
                </div>
            </div>
          );
      }
      if (item.type === 'audio' || item.type === 'file') {
          return (
            <div className="w-full h-full flex flex-col items-center justify-center bg-gray-100 p-4">
                <div className={`${item.type === 'audio' ? 'bg-orange-100' : 'bg-blue-100'} p-6 rounded-full mb-4`}>
                    {item.type === 'audio' ? (
                        <svg xmlns="http://www.w3.org/2000/svg" className="w-12 h-12 text-orange-500" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M9 18V5l12-2v13" /><circle cx="6" cy="18" r="3" /><circle cx="18" cy="16" r="3" /></svg>
                    ) : (
                        <FileIcon className="w-12 h-12 text-blue-500" />
                    )}
                </div>
                <p className="text-gray-500 font-medium truncate max-w-full px-4">{item.name || (item.type === 'audio' ? 'Audio Clip' : 'Document')}</p>
            </div>
          );
      }
      return null;
  };

  // Helper to render the Split View UI (Visuals only)
  const renderSplitViewUI = () => {
      const firstItem = media[0];
      return (
        <div className="flex h-full w-full">
            {/* Left Side (75%) */}
            <div className="w-[75%] h-full bg-gray-100 relative border-r border-gray-200 overflow-hidden">
                {renderPreviewContent(firstItem)}
                {!postLink && <div className="absolute inset-0 bg-black opacity-0 group-hover:opacity-10 transition-opacity"></div>}
            </div>

            {/* Right Side (25%) */}
            <div className="w-[25%] h-full bg-gray-50 flex flex-col items-center justify-center text-center p-2 hover:bg-gray-100 transition-colors">
                <span className={`${compact ? 'text-xl' : 'text-3xl md:text-4xl'} font-bold text-gray-800 mb-1`}>{media.length}</span>
                <span className="text-[10px] md:text-xs text-gray-500 font-semibold uppercase tracking-wider">Total</span>
                <span className={`mt-2 ${compact ? 'text-[10px] px-2' : 'text-xs px-3'} text-primary font-bold bg-primary/10 py-1 rounded-full`}>View All</span>
            </div>
        </div>
      );
  };


  // --- PREVIEW MODE (Navigation) ---
  if (postLink) {
      const isSingle = media.length === 1;
      return (
        <Link 
            to={postLink} 
            className={`block ${containerMargin} rounded-lg overflow-hidden border border-gray-200 shadow-sm hover:shadow-md transition-all ${isSingle ? `max-h-[500px] flex justify-center bg-black/5` : 'h-[400px]'}`}
        >
            {isSingle ? (
                 media[0].type === 'image' ? (
                     <img src={media[0].url} alt="post content" className="max-w-full max-h-[500px] object-contain" />
                 ) : (
                     <div className="w-full h-full min-h-[300px]">
                        {renderPreviewContent(media[0])}
                     </div>
                 )
            ) : (
                renderSplitViewUI()
            )}
        </Link>
      );
  }


  // --- DETAIL / INTERACTIVE MODE ---

  if (media.length === 1) {
    const item = media[0];
    return (
      <div className={`${containerMargin} rounded-lg overflow-hidden bg-black/5 border border-gray-200 flex justify-center`}>
        {item.type === 'image' && <img src={item.url} alt="post content" className={`max-w-full ${singleMediaMaxHeight} object-contain`} />}
        {item.type === 'video' && <video src={item.url} controls className={`max-w-full ${singleMediaMaxHeight}`} />}
        {item.type === 'audio' && <audio src={item.url} controls className="w-full p-4" />}
        {item.type === 'file' && (
            <div className="w-full p-8 flex flex-col items-center bg-gray-50">
                <FileIcon className="w-16 h-16 text-primary mb-4" />
                <h3 className="font-bold text-gray-900 mb-2 truncate max-w-xs">{item.name || 'File Document'}</h3>
                <a 
                    href={item.url} 
                    download={item.name || 'file'} 
                    className="bg-primary text-white font-black py-2 px-8 rounded-full shadow-lg shadow-primary/20 hover:bg-orange-600 transition-all"
                >
                    Scarica File
                </a>
            </div>
        )}
      </div>
    );
  }

  // 2. Split View (Collapsed, Click to Expand)
  if (!isExpanded) {
      return (
          <div 
            className={`${containerMargin} ${splitViewHeight} border border-gray-200 rounded-lg overflow-hidden cursor-pointer group shadow-sm hover:shadow-md transition-all`}
            onClick={() => setIsExpanded(true)}
            title="Click to view all media"
          >
              {renderSplitViewUI()}
          </div>
      )
  }

  // 3. Full Carousel View (Expanded)
  const nextSlide = (e: React.MouseEvent) => {
    e.stopPropagation();
    setCurrentIndex((prev) => (prev + 1) % media.length);
  };

  const prevSlide = (e: React.MouseEvent) => {
    e.stopPropagation();
    setCurrentIndex((prev) => (prev - 1 + media.length) % media.length);
  };

  const currentItem = media[currentIndex];

  return (
    <div className={`${containerMargin} relative bg-black rounded-lg border border-gray-800 overflow-hidden group ${carouselHeight}`}>
       <button 
         onClick={(e) => { e.stopPropagation(); setIsExpanded(false); }}
         className="absolute top-4 right-4 z-20 bg-black/50 text-white p-2 rounded-full hover:bg-black/80 transition-colors"
         title="Close Gallery"
       >
           <CloseIcon className="w-6 h-6" />
       </button>

       <div className="w-full h-full flex items-center justify-center bg-black">
            {currentItem?.type === 'image' && (
                <img src={currentItem.url} alt={`slide ${currentIndex}`} className="w-full h-full object-contain" />
            )}
            {currentItem?.type === 'video' && (
                <video src={currentItem.url} controls className="w-full h-full object-contain" />
            )}
            {currentItem?.type === 'audio' && (
                <div className="w-full p-12 bg-gray-900 flex items-center justify-center h-full">
                        <audio src={currentItem.url} controls className="w-full max-w-md" />
                </div>
            )}
            {currentItem?.type === 'file' && (
                <div className="w-full p-12 bg-gray-900 flex flex-col items-center justify-center h-full text-white">
                        <FileIcon className="w-20 h-20 mb-4 opacity-50" />
                        <h4 className="text-xl font-bold mb-4">{currentItem.name}</h4>
                        <a href={currentItem.url} download={currentItem.name} className="bg-primary text-white py-2 px-10 rounded-full font-bold">Scarica</a>
                </div>
            )}
       </div>

      {media.length > 1 && (
        <>
            <button
                onClick={prevSlide}
                className="absolute top-1/2 left-2 -translate-y-1/2 bg-white/10 hover:bg-white/20 p-2 rounded-full text-white transition-colors"
            >
                <ChevronLeftIcon className="w-8 h-8" />
            </button>
            <button
                onClick={nextSlide}
                className="absolute top-1/2 right-2 -translate-y-1/2 bg-white/10 hover:bg-white/20 p-2 rounded-full text-white transition-colors"
            >
                <ChevronRightIcon className="w-8 h-8" />
            </button>
            <div className="absolute bottom-4 left-0 right-0 flex justify-center items-center pointer-events-none">
                <div className="bg-black/60 px-4 py-1 rounded-full text-white text-sm font-medium backdrop-blur-sm">
                    {currentIndex + 1} / {media.length}
                </div>
            </div>
        </>
      )}
    </div>
  );
};

export default PostMedia;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { useAuth, useData, timeAgo } from '../hooks/useStore';
import UserAvatar from '../components/UserAvatar';
import { MessageIcon, TrashIcon, CloseIcon } from '../components/Icons';
import type { User, Message as MessageType, MediaItem } from '../types';
import MessageComponent from '../components/Message';
import MediaUploader from '../components/MediaUploader';

// Added explicit interface for conversation data to fix type inference issues
interface ConversationData {
    user: User;
    messages: MessageType[];
    lastMessage: MessageType;
    unreadCount: number;
}

const MessagesPage: React.FC = () => {
    const { username: activeUsername } = useParams();
    const navigate = useNavigate();
    const { currentUser, getUserById, getUserByUsername } = useAuth();
    const { messages, sendMessage, markConversationAsRead } = useData();
    const messagesEndRef = useRef<HTMLDivElement>(null);
    const [newMessage, setNewMessage] = useState('');
    const [attachedMedia, setAttachedMedia] = useState<MediaItem[]>([]);

    useEffect(() => { 
        if (!currentUser) navigate('/'); 
    }, [currentUser, navigate]);

    // Identifica l'utente attivo dall'URL
    const activeUser = useMemo(() => 
        activeUsername ? getUserByUsername(activeUsername) : undefined, 
    [activeUsername, getUserByUsername]);

    // Mappa tutte le conversazioni esistenti basate sui messaggi nel database
    const conversations = useMemo(() => {
        if (!currentUser) return new Map<string, ConversationData>();
        const convos = new Map<string, ConversationData>();

        // Ordiniamo i messaggi per data per trovare l'ultimo messaggio di ogni conversazione
        const sortedMessages = [...messages].sort((a, b) => 
            new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime()
        );

        sortedMessages.forEach(msg => {
            const otherId = msg.senderId === currentUser.id ? msg.recipientId : msg.senderId;
            if (!convos.has(otherId)) {
                const user = getUserById(otherId);
                if (user) convos.set(otherId, { user, messages: [], lastMessage: msg, unreadCount: 0 });
            }
            const convo = convos.get(otherId);
            if (convo) {
                convo.messages.push(msg);
                convo.lastMessage = msg;
                if (!msg.readAt && msg.recipientId === currentUser.id) convo.unreadCount++;
            }
        });

        // Se abbiamo un utente attivo nell'URL ma non abbiamo ancora messaggi con lui, 
        // lo aggiungiamo forzatamente alla mappa così appare nella sidebar
        if (activeUser && activeUser.id !== currentUser.id && !convos.has(activeUser.id)) {
            convos.set(activeUser.id, {
                user: activeUser,
                messages: [],
                // Creiamo un placeholder per lastMessage per permettere l'ordinamento in cima
                lastMessage: { 
                    id: 'temp', 
                    createdAt: new Date().toISOString(), 
                    content: '', 
                    senderId: '', 
                    recipientId: '' 
                } as any,
                unreadCount: 0
            });
        }

        return convos;
    }, [messages, currentUser, getUserById, activeUser]);

    // Converte la mappa in un array ordinato per l'ultimo messaggio (più recenti in alto)
    const sortedConvoList = useMemo(() => {
        return Array.from(conversations.values()).sort((a: ConversationData, b: ConversationData) => 
            new Date(b.lastMessage.createdAt).getTime() - new Date(a.lastMessage.createdAt).getTime()
        );
    }, [conversations]);

    // Determina la conversazione attiva
    const activeConversation = useMemo(() => {
        if (!activeUser) return undefined;
        return conversations.get(activeUser.id);
    }, [activeUser, conversations]);

    // Effetto per segnare come letti i messaggi quando si entra in una chat
    useEffect(() => {
        if (activeUser && currentUser) {
            markConversationAsRead(activeUser.id);
        }
    }, [activeUser, currentUser, messages.length, markConversationAsRead]);

    // Auto-scroll alla fine della chat
    useEffect(() => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, [activeConversation?.messages.length]);

    const handleSendMessage = (e: React.FormEvent) => {
        e.preventDefault();
        if ((newMessage.trim() || attachedMedia.length > 0) && activeUser) {
            sendMessage(activeUser.id, newMessage.trim(), attachedMedia);
            setNewMessage(''); 
            setAttachedMedia([]);
        }
    };

    if (!currentUser) return null;

    return (
        <div className="container mx-auto px-4 h-[calc(100vh-7rem)] mb-4">
            <div className="flex h-full bg-white border border-gray-200 rounded-2xl overflow-hidden shadow-sm">

                {/* Sidebar - Lista Conversazioni */}
                <aside className="w-full md:w-80 border-r border-gray-100 flex flex-col bg-gray-50/30 shrink-0">
                    <div className="p-4 border-b border-gray-100 bg-white">
                        <h2 className="font-black text-xl text-gray-900 tracking-tight">Messaggi</h2>
                    </div>
                    <div className="flex-1 overflow-y-auto">
                        {sortedConvoList.length > 0 ? (
                            <div className="divide-y divide-gray-50">
                                {sortedConvoList.map((convo) => (
                                    <Link 
                                        key={convo.user.id} 
                                        to={`/messages/${convo.user.username}`}
                                        className={`flex items-center gap-3 p-4 transition-colors hover:bg-white ${activeUser?.id === convo.user.id ? 'bg-white border-l-4 border-primary' : 'border-l-4 border-transparent'}`}
                                    >
                                        <UserAvatar user={convo.user} className="w-12 h-12 shadow-sm" />
                                        <div className="flex-1 min-w-0">
                                            <div className="flex justify-between items-baseline">
                                                <h3 className={`font-bold truncate ${convo.unreadCount > 0 ? 'text-gray-900' : 'text-gray-700'}`}>
                                                    {convo.user.username}
                                                </h3>
                                                <span className="text-[10px] text-gray-400 font-medium">
                                                    {convo.messages.length > 0 ? timeAgo(convo.lastMessage.createdAt) : 'Ora'}
                                                </span>
                                            </div>
                                            <p className={`text-xs truncate ${convo.unreadCount > 0 ? 'font-bold text-gray-900' : 'text-gray-500'}`}>
                                                {convo.messages.length > 0 ? (
                                                    <>
                                                        {convo.lastMessage.senderId === currentUser.id && 'Tu: '}
                                                        {convo.lastMessage.content || (convo.lastMessage.media ? '📎 Media' : 'Messaggio vuoto')}
                                                    </>
                                                ) : (
                                                    <span className="text-primary font-bold italic">Nuova conversazione</span>
                                                )}
                                            </p>
                                        </div>
                                        {convo.unreadCount > 0 && (
                                            <div className="w-2.5 h-2.5 bg-primary rounded-full shadow-sm shadow-primary/40"></div>
                                        )}
                                    </Link>
                                ))}
                            </div>
                        ) : (
