const MapPage: React.FC = () => {
    const { currentUser, users, getUserById, isAdmin } = useAuth();
    const { territoryAssignments, assignTerritory } = useData();
    const [selectedId, setSelectedId] = useState<string | null>(null);
    const [hoveredId, setHoveredId] = useState<string | null>(null);
    const [searchTerm, setSearchTerm] = useState('');

    const selectedTerritory = useMemo(() => 
        TERRITORIES.find(t => t.id === selectedId), 
    [selectedId]);

    const hoveredTerritory = useMemo(() => 
        TERRITORIES.find(t => t.id === hoveredId), 
    [hoveredId]);

    const assignment = useMemo(() => 
        territoryAssignments.find(a => a.territoryId === selectedId), 
    [territoryAssignments, selectedId]);

    const ambassador = useMemo(() => 
        assignment ? getUserById(assignment.userId) : null, 
    [assignment, getUserById]);

    const filteredUsers = useMemo(() => {
        if (!searchTerm.trim()) return [];
        return users.filter(u => 
            u.username.toLowerCase().includes(searchTerm.toLowerCase())
        ).slice(0, 5);
    }, [users, searchTerm]);

    const handleAssign = (userId: string) => {
        if (selectedId) {
            assignTerritory(selectedId, userId);
            setSearchTerm('');
        }
    };

    return (
        <div className="container mx-auto px-4 h-[calc(100vh-8rem)]">
            <div className="flex flex-col lg:flex-row h-full gap-6">

                {/* Map Area */}
                <div className="flex-1 bg-white rounded-2xl border border-gray-200 shadow-sm relative overflow-hidden flex flex-col">
                    <div className="p-4 border-b border-gray-100 flex justify-between items-center">
                        <div>
                            <h1 className="text-xl font-black text-gray-900 tracking-tight">World Ambassador Map</h1>
                            <p className="text-xs text-gray-500 font-medium">Select a territory to view its governance.</p>
                        </div>
                        {hoveredTerritory && (
                            <div className="bg-primary/10 text-primary px-3 py-1 rounded-full text-xs font-bold animate-in fade-in zoom-in duration-200">
                                {hoveredTerritory.name}
                            </div>
                        )}
                    </div>

                    <div className="flex-1 p-8 flex items-center justify-center bg-gray-50/50">
                        <svg 
                            viewBox="0 0 1000 600" 
                            className="w-full h-full drop-shadow-xl"
                            preserveAspectRatio="xMidYMid meet"
                        >
                            {/* Background Water (Decorative) */}
                            <rect width="1000" height="600" fill="#f8fafc" rx="12" />

                            {TERRITORIES.map((territory) => {
                                const isAssigned = territoryAssignments.some(a => a.territoryId === territory.id);
                                const isSelected = selectedId === territory.id;

                                return (
                                    <path
                                        key={territory.id}
                                        d={territory.path}
                                        onClick={() => setSelectedId(territory.id)}
                                        onMouseEnter={() => setHoveredId(territory.id)}
                                        onMouseLeave={() => setHoveredId(null)}
                                        className={`cursor-pointer transition-all duration-300 stroke-2 ${
                                            isSelected 
                                                ? 'fill-primary stroke-orange-300 scale-105 filter drop-shadow-md z-20' 
                                                : isAssigned 
                                                    ? 'fill-orange-200 stroke-orange-300 hover:fill-orange-300' 
                                                    : 'fill-gray-200 stroke-gray-300 hover:fill-gray-300'
                                        }`}
                                    />
                                );
                            })}
                        </svg>
                    </div>
                </div>

                {/* Sidebar */}
                <aside className="w-full lg:w-96 shrink-0 flex flex-col gap-6">
                    <div className="bg-white rounded-2xl border border-gray-200 shadow-sm p-6 flex flex-col flex-1">
                        {selectedTerritory ? (
                            <div className="space-y-8 animate-in slide-in-from-right-4 duration-300">
                                {/* Territory Header */}
                                <div className="flex items-center gap-4">
                                    <img 
                                        src={getFlagUrl(selectedTerritory.id)} 
                                        alt={selectedTerritory.name} 
                                        className="w-16 h-12 rounded-lg shadow-sm object-cover border border-gray-100"
                                    />
                                    <div>
                                        <h2 className="text-2xl font-black text-gray-900 tracking-tight">{selectedTerritory.name}</h2>
                                        <p className="text-xs font-bold text-gray-400 uppercase tracking-widest">{selectedTerritory.id} Division</p>
                                    </div>
                                </div>

                                {/* Ambassador Status */}
                                <div>
                                    <h3 className="text-xs font-black text-gray-400 uppercase tracking-widest mb-4">Official Ambassador</h3>
                                    {ambassador ? (
                                        <div className="bg-gray-50 rounded-2xl p-4 border border-gray-100">
                                            <div className="flex items-center gap-3 mb-4">
                                                <UserAvatar user={ambassador} className="w-12 h-12 shadow-sm ring-2 ring-white" />
                                                <div className="flex-1 min-w-0">
                                                    <Link to={`/u/${ambassador.username}`} className="font-bold text-gray-900 hover:text-primary transition-colors block truncate">
                                                        u/{ambassador.username}
                                                    </Link>
                                                    <p className="text-[10px] text-green-500 font-black uppercase tracking-tighter">Active Governor</p>
                                                </div>
                                            </div>
                                            <div className="flex gap-2">
                                                <Link to={`/u/${ambassador.username}`} className="flex-1 bg-white border border-gray-200 text-gray-700 font-bold py-2 rounded-xl text-xs text-center hover:bg-gray-50 transition-all">View Profile</Link>
                                                <Link to={`/messages/${ambassador.username}`} className="p-2 bg-primary text-white rounded-xl hover:bg-orange-600 transition-all">
                                                    <MessageIcon className="w-4 h-4" />
                                                </Link>
                                            </div>
                                        </div>
                                    ) : (
                                        <div className="bg-orange-50/50 border-2 border-dashed border-orange-100 rounded-2xl p-8 text-center">
                                            <UsersIcon className="w-10 h-10 text-orange-200 mx-auto mb-3" />
                                            <p className="text-sm font-bold text-orange-400">No Ambassador Assigned</p>
                                            <p className="text-[10px] text-gray-400 mt-1 max-w-[180px] mx-auto leading-tight">This territory is currently open for governance.</p>
                                        </div>
                                    )}
                                </div>

                                {/* Admin Assignment Section */}
                                {currentUser && isAdmin(currentUser.id) && (
                                    <div className="pt-8 border-t border-gray-100">
                                        <h3 className="text-xs font-black text-gray-400 uppercase tracking-widest mb-4">Assign Governance</h3>
                                        <div className="relative">
                                            <input 
                                                type="text" 
                                                value={searchTerm}
                                                onChange={(e) => setSearchTerm(e.target.value)}
                                                className="w-full bg-gray-50 border border-gray-200 rounded-xl p-3 text-sm focus:ring-2 focus:ring-primary/20 outline-none font-bold"
                                                placeholder="Search username..."
                                            />
                                            {filteredUsers.length > 0 && (
                                                <div className="absolute top-full left-0 right-0 mt-2 bg-white border border-gray-100 rounded-xl shadow-xl z-30 overflow-hidden divide-y divide-gray-50">
                                                    {filteredUsers.map(user => (
                                                        <button 
                                                            key={user.id}
                                                            onClick={() => handleAssign(user.id)}
                                                            className="w-full px-4 py-3 flex items-center gap-3 hover:bg-gray-50 text-left transition-colors"
                                                        >
                                                            <UserAvatar user={user} className="w-8 h-8" />
                                                            <span className="font-bold text-gray-800 text-sm">u/{user.username}</span>
                                                        </button>
                                                    ))}
                                                </div>
                                            )}
                                        </div>
                                        {ambassador && (
                                            <button 
                                                onClick={() => handleAssign('')}
                                                className="w-full mt-3 text-[10px] font-black text-red-400 hover:text-red-600 uppercase tracking-widest transition-colors"
                                            >
                                                Revoke Mandate
                                            </button>
                                        )}
                                    </div>
                                )}
                            </div>
                        ) : (
                            <div className="flex-1 flex flex-col items-center justify-center text-center p-8">
                                <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mb-6 border border-gray-100">
                                    <polygon points="1 6 1 22 8 18 16 22 23 18 23 2 16 6 8 2 1 6" className="w-10 h-10 text-gray-200" fill="none" stroke="currentColor" strokeWidth="2" />
                                </div>
                                <h2 className="text-xl font-black text-gray-900 mb-2 tracking-tight">Geographic Hub</h2>
                                <p className="text-sm text-gray-400 max-w-[220px]">Select a territory on the map to see who is leading the local community.</p>
                            </div>
                        )}
                    </div>

                    {/* Stats Widget */}
                    <div className="bg-white rounded-2xl border border-gray-200 shadow-sm p-4">
                        <div className="flex justify-between items-center text-xs font-black uppercase tracking-widest text-gray-400">
                            <span>Global Status</span>
                            <span className="text-primary">{territoryAssignments.length} / {TERRITORIES.length} Assigned</span>
                        </div>
                        <div className="w-full bg-gray-100 h-1.5 rounded-full mt-3 overflow-hidden">
                            <div 
                                className="bg-primary h-full transition-all duration-1000" 
                                style={{ width: `${(territoryAssignments.length / TERRITORIES.length) * 100}%` }}
                            />
                        </div>
                    </div>
                </aside>
            </div>
        </div>
    );
};

export default MapPage;

