const MapPage: React.FC = () => {
    const { currentUser, users, getUserById, isAdmin } = useAuth();
    const { territoryAssignments, assignTerritory } = useData();
    const [selectedId, setSelectedId] = useState<string | null>(null);
    const [hoveredId, setHoveredId] = useState<string | null>(null);
    const [searchTerm, setSearchTerm] = useState('');

    const selectedTerritory = useMemo(() => 
        WORLD_MAP_DETAILED.find(t => t.id === selectedId), 
    [selectedId]);

    const hoveredTerritory = useMemo(() => 
        WORLD_MAP_DETAILED.find(t => t.id === hoveredId), 
    [hoveredId]);

    const assignment = useMemo(() => 
        territoryAssignments.find(a => a.territoryId === selectedId), 
    [territoryAssignments, selectedId]);

    const ambassador = useMemo(() => 
        assignment ? getUserById(assignment.userId) : null, 
    [assignment, getUserById]);

    const filteredUsers = useMemo(() => {
        if (!searchTerm.trim()) return [];
        return users.filter(u => 
            u.username.toLowerCase().includes(searchTerm.toLowerCase())
        ).slice(0, 5);
    }, [users, searchTerm]);

    const handleAssign = (userId: string) => {
        if (selectedId) {
            assignTerritory(selectedId, userId);
            setSearchTerm('');
        }
    };

    return (
        <div className="container mx-auto px-4 h-[calc(100vh-8rem)]">
            <div className="flex flex-col lg:flex-row h-full gap-6">

                {/* Area Mappa - Pulita */}
                <div className="flex-1 bg-white rounded-3xl border border-gray-200 shadow-sm relative overflow-hidden flex flex-col">
                    <div className="p-6 border-b border-gray-100 flex justify-between items-center">
                        <div>
                            <h1 className="text-2xl font-bold text-gray-900 tracking-tight">World Map</h1>
                            <p className="text-sm text-gray-500 font-medium">Seleziona una nazione per visualizzarne l'Ambasciatore.</p>
                        </div>
                        {hoveredTerritory && (
                            <div className="bg-gray-100 text-gray-800 px-4 py-2 rounded-full text-sm font-bold animate-in fade-in duration-200">
                                {hoveredTerritory.name}
                            </div>
                        )}
                    </div>

                    <div className="flex-1 p-4 flex items-center justify-center bg-gray-50/50">
                        <svg 
                            viewBox="100 50 850 450" 
                            className="w-full h-full"
                            preserveAspectRatio="xMidYMid meet"
                        >
                            {WORLD_MAP_DETAILED.map((territory) => {
                                const isAssigned = territoryAssignments.some(a => a.territoryId === territory.id);
                                const isSelected = selectedId === territory.id;

                                return (
                                    <path
                                        key={territory.id}
                                        d={territory.path}
                                        onClick={() => setSelectedId(territory.id)}
                                        onMouseEnter={() => setHoveredId(territory.id)}
                                        onMouseLeave={() => setHoveredId(null)}
                                        className={`cursor-pointer transition-all duration-300 outline-none ${
                                            isSelected 
                                                ? 'fill-primary stroke-white stroke-[2px] z-10 scale-[1.02]' 
                                                : isAssigned 
                                                    ? 'fill-orange-400 stroke-orange-600 hover:fill-orange-500' 
                                                    : 'fill-gray-200 stroke-gray-300 hover:fill-gray-300 hover:stroke-gray-400'
                                        }`}
                                        style={{ transformOrigin: 'center', transformBox: 'fill-box' }}
                                    >
                                        <title>{territory.name}</title>
                                    </path>
                                );
                            })}
                        </svg>

                        {/* Legenda Semplificata */}
                        <div className="absolute bottom-6 left-6 flex items-center gap-6 p-4 bg-white/80 backdrop-blur-sm rounded-xl border border-gray-200 shadow-sm">
                             <div className="flex items-center gap-2">
                                <div className="w-3 h-3 bg-primary rounded-full"></div>
                                <span className="text-[11px] font-bold text-gray-600 uppercase tracking-wider">Selezionata</span>
                            </div>
                            <div className="flex items-center gap-2">
                                <div className="w-3 h-3 bg-orange-400 rounded-full"></div>
                                <span className="text-[11px] font-bold text-gray-600 uppercase tracking-wider">Ambasciatore</span>
                            </div>
                            <div className="flex items-center gap-2">
                                <div className="w-3 h-3 bg-gray-200 rounded-full"></div>
                                <span className="text-[11px] font-bold text-gray-600 uppercase tracking-wider">Disponibile</span>
                            </div>
                        </div>
                    </div>
                </div>

                {/* Sidebar di Controllo */}
                <aside className="w-full lg:w-[400px] shrink-0 flex flex-col gap-6">
                    <div className="bg-white rounded-3xl border border-gray-200 shadow-sm p-8 flex flex-col flex-1 relative overflow-hidden">
                        {selectedTerritory ? (
                            <div className="space-y-8 animate-in slide-in-from-right-4 duration-500">
                                {/* Header Nazione */}
                                <div className="flex items-center gap-6">
                                    <img 
                                        src={getFlagUrl(selectedTerritory.id)} 
                                        alt={selectedTerritory.name} 
                                        className="w-20 h-14 rounded-lg shadow-sm object-cover border border-gray-100"
                                    />
                                    <div>
                                        <h2 className="text-3xl font-bold text-gray-900 tracking-tight">{selectedTerritory.name}</h2>
                                        <p className="text-xs font-bold text-gray-400 uppercase tracking-widest">{selectedTerritory.id}</p>
                                    </div>
                                </div>

                                {/* Sezione Ambasciatore */}
                                <div className="pt-6 border-t border-gray-100">
                                    <h3 className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-4">Ambasciatore Incaricato</h3>
                                    {ambassador ? (
                                        <div className="bg-gray-50 rounded-2xl p-6 border border-gray-100">
                                            <div className="flex items-center gap-4 mb-6">
                                                <UserAvatar user={ambassador} className="w-16 h-16 shadow-sm border-2 border-white" />
                                                <div className="flex-1 min-w-0">
                                                    <Link to={`/u/${ambassador.username}`} className="font-bold text-xl text-gray-900 hover:text-primary transition-colors block truncate">
                                                        u/{ambassador.username}
                                                    </Link>
                                                    <div className="flex items-center gap-1.5 mt-1">
                                                        <div className="w-2 h-2 bg-green-500 rounded-full"></div>
                                                        <p className="text-[10px] text-gray-500 font-bold uppercase">Attivo</p>
                                                    </div>
                                                </div>
                                            </div>
                                            <div className="flex gap-2">
                                                <Link to={`/u/${ambassador.username}`} className="flex-1 bg-white border border-gray-200 text-gray-700 font-bold py-2.5 rounded-xl text-xs text-center hover:bg-gray-50 transition-colors">Profilo</Link>
                                                <Link to={`/messages/${ambassador.username}`} className="p-2.5 bg-primary text-white rounded-xl hover:bg-orange-600 transition-colors">
                                                    <MessageIcon className="w-5 h-5" />
                                                </Link>
                                            </div>
                                        </div>
                                    ) : (
                                        <div className="bg-gray-50 border border-dashed border-gray-200 rounded-2xl p-8 text-center">
                                            <UsersIcon className="w-8 h-8 text-gray-300 mx-auto mb-3" />
                                            <p className="text-sm font-bold text-gray-500">Nessun Ambasciatore</p>
                                            <p className="text-xs text-gray-400 mt-1">Questa nazione non ha ancora un rappresentante ufficiale.</p>
                                        </div>
                                    )}
                                </div>

                                {/* Pannello Admin */}
                                {currentUser && isAdmin(currentUser.id) && (
                                    <div className="pt-6 mt-auto border-t border-gray-100">
                                        <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-3">Assegna Responsabile (Admin)</label>
                                        <div className="relative">
                                            <input 
                                                type="text" 
                                                value={searchTerm}
                                                onChange={(e) => setSearchTerm(e.target.value)}
                                                className="w-full bg-gray-50 border border-gray-200 rounded-xl p-3 text-sm focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none font-medium"
                                                placeholder="Cerca utente..."
                                            />
                                            {filteredUsers.length > 0 && (
                                                <div className="absolute bottom-full left-0 right-0 mb-2 bg-white border border-gray-200 rounded-xl shadow-xl z-50 overflow-hidden divide-y divide-gray-50 animate-in fade-in slide-in-from-bottom-2">
                                                    {filteredUsers.map(user => (
                                                        <button 
                                                            key={user.id}
                                                            onClick={() => handleAssign(user.id)}
                                                            className="w-full px-4 py-3 flex items-center gap-3 hover:bg-gray-50 text-left transition-colors"
                                                        >
                                                            <UserAvatar user={user} className="w-8 h-8" />
                                                            <span className="font-bold text-gray-800 text-sm">u/{user.username}</span>
                                                        </button>
                                                    ))}
                                                </div>
                                            )}
                                        </div>
                                        {ambassador && (
                                            <button 
                                                onClick={() => handleAssign('')}
                                                className="w-full mt-3 text-[10px] font-bold text-red-500 hover:text-red-700 uppercase tracking-widest transition-colors py-2"
                                            >
                                                Rimuovi Incarico
                                            </button>
                                        )}
                                    </div>
                                )}
                            </div>
                        ) : (
                            <div className="flex-1 flex flex-col items-center justify-center text-center p-10 animate-in fade-in duration-500">
                                <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mb-6 border border-gray-100">
                                    <svg className="w-10 h-10 text-gray-200" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M3.055 11H5a2 2 0 012 2v1a2 2 0 002 2 2 2 0 012 2v2.945M8 3.935V5.5A2.5 2.5 0 0010.5 8h.5a2 2 0 012 2 2 2 0 104 0 2 2 0 012-2h1.064M15 20.488V18a2 2 0 012-2h3.064M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                                </div>
                                <h2 className="text-xl font-bold text-gray-900 mb-2">Mappa Ambasciatori</h2>
                                <p className="text-sm text-gray-400 max-w-[240px] leading-relaxed">Seleziona un settore geografico sulla mappa per visualizzarne i dettagli.</p>
                            </div>
                        )}
                    </div>
                </aside>
            </div>
        </div>
    );
};

