                    const attrId = p.getAttribute('id');
                    const attrTitle = p.getAttribute('title') || p.getAttribute('name');
                    // Garantiamo un ID sempre presente, anche se manca nell'SVG originale
                    const finalId = attrId || `p-${index}`;

                    return {
                        id: finalId,
