import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useAuth, useData, getFlagUrl } from '../hooks/useStore';
import UserAvatar from '../components/UserAvatar';
import { Link } from 'react-router-dom';
import { MessageIcon, UsersIcon, PlusIcon } from '../components/Icons';

interface MapPath {
  id: string;
  d: string;
  name: string;
}

const MapPage: React.FC = () => {
    const { currentUser, users, getUserById, isAdmin } = useAuth();
    const { territoryAssignments, assignTerritory } = useData();
    const [selectedId, setSelectedId] = useState<string | null>(null);
    const [hoveredId, setHoveredId] = useState<string | null>(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [mapPaths, setMapPaths] = useState<MapPath[]>([]);
    const [viewBox, setViewBox] = useState<string>('0 0 2000 1001');
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [zoom, setZoom] = useState(1);
    const scrollContainerRef = useRef<HTMLDivElement>(null);

    // Resolver per i nomi delle nazioni basato su standard internazionali
    const regionNames = useMemo(() => new Intl.DisplayNames(['it'], { type: 'region' }), []);

    useEffect(() => {
        const fetchMap = async () => {
            try {
                const response = await fetch('https://raw.githubusercontent.com/flekschas/simple-world-map/refs/heads/master/world-map.min.svg');
                if (!response.ok) throw new Error('Errore di rete');
                const svgText = await response.text();

                const parser = new DOMParser();
                const doc = parser.parseFromString(svgText, 'image/svg+xml');

                const svgEl = doc.querySelector('svg');
                if (svgEl && svgEl.getAttribute('viewBox')) {
                    setViewBox(svgEl.getAttribute('viewBox')!);
                }

                const paths = Array.from(doc.querySelectorAll('path'));
                const extractedPaths: MapPath[] = paths.map((p, index) => {
                    const attrId = p.getAttribute('id') || '';
                    const attrTitle = p.getAttribute('title') || p.getAttribute('name');

                    // Se l'ID è un codice ISO (2 lettere), usiamo Intl per ottenere il nome reale
                    let finalName = attrTitle;
                    if (!finalName && attrId.length === 2) {
                        try {
                            finalName = regionNames.of(attrId.toUpperCase());
                        } catch (e) {
                            finalName = attrId;
                        }
                    }

                    const finalId = attrId || `p-${index}`;

                    return {
                        id: finalId,
                        d: p.getAttribute('d') || '',
                        name: finalName || finalId
                    };
                }).filter(p => p.d);

                setMapPaths(extractedPaths);
                setIsLoading(false);
            } catch (err) {
                console.error(err);
                setError('Errore nel caricamento della cartografia.');
                setIsLoading(false);
            }
        };

        fetchMap();
    }, [regionNames]);

    // Gestione navigazione con tastiera
    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if (!scrollContainerRef.current || zoom <= 1) return;

            const step = 80; // Pixel di spostamento
            switch(e.key) {
                case 'ArrowUp':
                    e.preventDefault();
                    scrollContainerRef.current.scrollBy({ top: -step, behavior: 'smooth' });
                    break;
                case 'ArrowDown':
                    e.preventDefault();
                    scrollContainerRef.current.scrollBy({ top: step, behavior: 'smooth' });
                    break;
                case 'ArrowLeft':
                    e.preventDefault();
                    scrollContainerRef.current.scrollBy({ left: -step, behavior: 'smooth' });
                    break;
                case 'ArrowRight':
                    e.preventDefault();
                    scrollContainerRef.current.scrollBy({ left: step, behavior: 'smooth' });
                    break;
            }
        };

        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, [zoom]);

    const selectedTerritory = useMemo(() => 
        mapPaths.find(t => t.id === selectedId), 
    [selectedId, mapPaths]);

    const hoveredTerritory = useMemo(() => 
        mapPaths.find(t => t.id === hoveredId), 
    [hoveredId, mapPaths]);

    const assignment = useMemo(() => 
        selectedId ? territoryAssignments.find(a => a.territoryId === selectedId) : null, 
    [territoryAssignments, selectedId]);

    const ambassador = useMemo(() => 
        assignment ? getUserById(assignment.userId) : null, 
    [assignment, getUserById]);

    const filteredUsers = useMemo(() => {
        if (!searchTerm.trim()) return [];
        return users.filter(u => 
            u.username.toLowerCase().includes(searchTerm.toLowerCase())
        ).slice(0, 5);
    }, [users, searchTerm]);

    const handleAssign = (userId: string) => {
        if (selectedId) {
            assignTerritory(selectedId, userId);
            setSearchTerm('');
        }
    };

    const handleZoomIn = () => setZoom(prev => Math.min(prev + 1, 12));
    const handleZoomOut = () => setZoom(prev => Math.max(prev - 1, 1));
    const handleZoomReset = () => setZoom(1);

    return (
        <div className="container mx-auto px-4 h-[calc(100vh-8rem)]">
            <div className="flex flex-col lg:flex-row h-full gap-4">

                {/* Mappa - Main View */}
                <div className="flex-1 bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden flex flex-col relative group">
                    <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-white z-20">
                        <div>
                            <h1 className="text-xl font-black text-gray-900 tracking-tight">Global Coverage</h1>
                            <p className="text-[9px] text-gray-400 font-bold uppercase tracking-widest">
                                {zoom > 1 ? 'Usa le frecce della tastiera per navigare' : 'Seleziona una nazione'} • Magnification: x{zoom}
                            </p>
                        </div>
                        {hoveredTerritory && (
                            <div className="bg-gray-900 text-white px-3 py-1 rounded text-[10px] font-black uppercase tracking-wider animate-in fade-in zoom-in duration-150">
                                {hoveredTerritory.name}
                            </div>
                        )}
                    </div>

                    {/* Zoom Controls Overlay */}
                    <div className="absolute bottom-6 right-6 z-30 flex flex-col gap-1.5 shadow-2xl">
                        <button 
                            onClick={handleZoomIn} 
                            className="w-12 h-12 bg-white border border-gray-200 rounded-t-xl flex items-center justify-center text-gray-800 hover:text-primary hover:bg-gray-50 transition-all active:scale-95 border-b-0"
                            title="Zoom In"
                        >
                            <PlusIcon className="w-6 h-6" />
                        </button>
                        <button 
                            onClick={handleZoomOut} 
                            className="w-12 h-12 bg-white border border-gray-200 flex items-center justify-center text-gray-800 hover:text-primary hover:bg-gray-50 transition-all active:scale-95"
                            title="Zoom Out"
                        >
                            <div className="w-5 h-0.5 bg-current rounded-full" />
                        </button>
                        <button 
                            onClick={handleZoomReset} 
                            className="w-12 h-12 bg-primary text-white rounded-b-xl flex items-center justify-center hover:bg-orange-600 transition-all active:scale-95"
                            title="Reset View"
                        >
                            <span className="text-[11px] font-black uppercase">FIT</span>
