                    <div 
                        ref={scrollContainerRef}
                        tabIndex={0}
                        className="flex-1 bg-[#f0f2f5] relative overflow-auto custom-scrollbar p-4 outline-none focus:ring-2 focus:ring-primary/10 transition-shadow"
