                                className="transition-all duration-300 ease-out origin-center mx-auto"
                                style={{ 
                                    width: `${zoom * 100}%`,
                                    minWidth: '100%',
                                    aspectRatio: '2000 / 1001',
                                }}
                            >
                                <svg 
                                    viewBox={viewBox} 
                                    className="w-full h-full block"
                                    preserveAspectRatio="xMidYMid meet"
                                >
                                    {mapPaths.map((territory, idx) => {
                                        const isAssigned = territoryAssignments.some(a => a.territoryId === territory.id);
                                        const isSelected = selectedId === territory.id;

                                        return (
                                            <path
                                                key={`${territory.id}-${idx}`}
                                                d={territory.d}
                                                onClick={() => setSelectedId(territory.id)}
                                                onMouseEnter={() => setHoveredId(territory.id)}
                                                onMouseLeave={() => setHoveredId(null)}
                                                vectorEffect="non-scaling-stroke"
                                                className={`transition-all duration-150 outline-none cursor-pointer ${
                                                    isSelected 
                                                        ? 'fill-primary stroke-gray-900 stroke-[1.5px]' 
                                                        : isAssigned 
                                                            ? 'fill-orange-400 stroke-gray-900 stroke-[0.8px] hover:fill-orange-500' 
                                                            : 'fill-white stroke-gray-300 stroke-[0.5px] hover:fill-gray-100 hover:stroke-gray-500'
                                                }`}
                                            >
                                                <title>{territory.name}</title>
                                            </path>
                                        );
                                    })}
                                </svg>
                            </div>
                        )}
                    </div>
                </div>

                {/* Info Panel */}
                <aside className="w-full lg:w-[380px] shrink-0 flex flex-col">
                    <div className="bg-white rounded-xl border border-gray-200 shadow-sm p-6 flex flex-col flex-1">
