                                                        <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
                                                        <p className="text-[10px] text-gray-500 font-bold uppercase">Online ora</p>
                                                    </div>
                                                </div>
                                            </div>

                                            <div className="flex gap-2">
                                                <Link to={`/u/${ambassador.username}`} className="flex-1 bg-white text-gray-900 border border-gray-200 font-black py-2.5 rounded-lg text-[10px] text-center hover:bg-gray-50 transition-all uppercase tracking-widest">Vai al Profilo</Link>
                                                <Link to={`/messages/${ambassador.username}`} className="p-2.5 bg-gray-900 text-white rounded-lg hover:bg-gray-800 transition-all shadow-sm">
                                                    <MessageIcon className="w-5 h-5" />
                                                </Link>
                                            </div>
                                        </div>
                                    ) : (
                                        <div className="bg-gray-50 border border-dashed border-gray-300 rounded-xl p-10 text-center">
                                            <p className="text-[12px] font-black text-gray-400 uppercase tracking-widest">Nessuna Nomina</p>
                                            <p className="text-[10px] text-gray-400 mt-2 font-medium">Sede diplomatica attualmente vacante.</p>
                                        </div>
                                    )}
                                </div>

                                {currentUser && isAdmin(currentUser.id) && (
                                    <div className="pt-6 mt-auto border-t border-gray-100">
                                        <label className="block text-[9px] font-black text-gray-500 uppercase tracking-widest mb-3">Pannello Assegnazione</label>
                                        <div className="relative">
                                            <input 
                                                type="text" 
                                                value={searchTerm}
                                                onChange={(e) => setSearchTerm(e.target.value)}
                                                className="w-full bg-gray-50 border border-gray-200 rounded-lg p-3 text-xs focus:ring-2 focus:ring-primary/10 focus:border-primary outline-none font-bold text-gray-900 transition-all"
                                                placeholder="Cerca utente da nominare..."
                                            />
                                            {filteredUsers.length > 0 && (
                                                <div className="absolute bottom-full left-0 right-0 mb-2 bg-white border border-gray-200 rounded-xl shadow-2xl z-50 overflow-hidden divide-y divide-gray-50 animate-in fade-in slide-in-from-bottom-2">
                                                    {filteredUsers.map(user => (
                                                        <button 
                                                            key={user.id}
                                                            onClick={() => handleAssign(user.id)}
                                                            className="w-full px-4 py-3 flex items-center gap-3 hover:bg-gray-50 text-left transition-all group/user"
                                                        >
                                                            <UserAvatar user={user} className="w-8 h-8 group-hover/user:scale-105 transition-transform" />
                                                            <span className="font-bold text-gray-800 text-sm">u/{user.username}</span>
                                                        </button>
                                                    ))}
                                                </div>
                                            )}
                                        </div>
                                        {ambassador && (
                                            <button 
                                                onClick={() => handleAssign('')}
                                                className="w-full mt-3 text-[10px] font-black text-red-500 hover:text-red-700 uppercase py-2.5 border border-transparent hover:border-red-50 rounded-lg transition-all"
                                            >
                                                Revoca Incarico Attuale
                                            </button>
