                        ) : (
                            <div className="flex-1 flex flex-col items-center justify-center text-center p-8 opacity-60">
                                <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mb-6 border border-gray-200 text-gray-300">
                                    <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3.055 11H5a2 2 0 012 2v1a2 2 0 002 2 2 2 0 012 2v2.945M8 3.935V5.5A2.5 2.5 0 0010.5 8h.5a2 2 0 012 2 2 2 0 104 0 2 2 0 012-2h1.064M15 20.488V18a2 2 0 012-2h3.064M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                                </div>
                                <h2 className="text-xl font-black text-gray-900 uppercase italic tracking-tighter">Esplora l'Atlante</h2>
                                <p className="text-[10px] text-gray-400 font-bold uppercase mt-2 tracking-widest leading-relaxed">Clicca su uno stato per consultare i dati diplomatici o assegnare incarichi.</p>
                            </div>
                        )}
                    </div>
                </aside>
            </div>
            <style>{`
                .custom-scrollbar::-webkit-scrollbar { width: 6px; height: 6px; }
                .custom-scrollbar::-webkit-scrollbar-track { background: #f0f2f5; }
                .custom-scrollbar::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 20px; }
                .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #94a3b8; }
                /* Firefox */
                .custom-scrollbar { scrollbar-width: thin; scrollbar-color: #cbd5e1 #f0f2f5; }
            `}</style>
        </div>
    );
};

export default MapPage;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useAuth, useData, getFlagUrl } from '../hooks/useStore';
import UserAvatar from '../components/UserAvatar';
import { Link } from 'react-router-dom';
import { MessageIcon, UsersIcon, PlusIcon } from '../components/Icons';

interface MapPath {
  id: string;
  d: string;
  name: string;
}

const MapPage: React.FC = () => {
    const { currentUser, users, getUserById, isAdmin } = useAuth();
    const { territoryAssignments, assignTerritory } = useData();
    const [selectedId, setSelectedId] = useState<string | null>(null);
    const [hoveredId, setHoveredId] = useState<string | null>(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [mapPaths, setMapPaths] = useState<MapPath[]>([]);
    const [viewBox, setViewBox] = useState<string>('0 0 2000 1001');
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [zoom, setZoom] = useState(1);

    const scrollContainerRef = useRef<HTMLDivElement>(null);
    const isDragging = useRef(false);
    const startPos = useRef({ x: 0, y: 0, scrollLeft: 0, scrollTop: 0 });

    const regionNames = useMemo(() => new Intl.DisplayNames(['it'], { type: 'region' }), []);

    useEffect(() => {
        const fetchMap = async () => {
            try {
                // Utilizziamo una versione più completa dell'SVG se disponibile o puliamo quella esistente
                const response = await fetch('https://raw.githubusercontent.com/flekschas/simple-world-map/refs/heads/master/world-map.min.svg');
                if (!response.ok) throw new Error('Errore di rete');
                const svgText = await response.text();

                const parser = new DOMParser();
                const doc = parser.parseFromString(svgText, 'image/svg+xml');
                const svgEl = doc.querySelector('svg');
                if (svgEl && svgEl.getAttribute('viewBox')) {
                    setViewBox(svgEl.getAttribute('viewBox')!);
                }

                const paths = Array.from(doc.querySelectorAll('path'));
                const extractedPaths: MapPath[] = paths.map((p, index) => {
                    const attrId = p.getAttribute('id') || '';
                    const attrTitle = p.getAttribute('title') || p.getAttribute('name');

                    let finalName = attrTitle;

                    // Se il nome manca o è un ID tecnico (es. p-90), proviamo a risalire alla nazione
                    if (!finalName || /^[pP]-\d+$/.test(finalName)) {
                        if (attrId && attrId.length === 2) {
                            try {
                                finalName = regionNames.of(attrId.toUpperCase());
                            } catch (e) {
                                finalName = `Territorio ${attrId}`;
                            }
                        } else {
                            // Fallback per isole o territori minori senza ID ISO
                            finalName = attrTitle || `Area Geografica ${index + 1}`;
                        }
                    }

                    const finalId = attrId || `area-${index}`;

                    return {
                        id: finalId,
                        d: p.getAttribute('d') || '',
                        name: finalName || 'Settore Non Identificato'
                    };
                }).filter(p => p.d);

                setMapPaths(extractedPaths);
                setIsLoading(false);
            } catch (err) {
                console.error(err);
                setError('Impossibile caricare la cartografia satellitare.');
                setIsLoading(false);
            }
        };

        fetchMap();
    }, [regionNames]);

    // Navigazione con Tastiera e Mouse Panning
    useEffect(() => {
        const container = scrollContainerRef.current;
        if (!container) return;

        const handleKeyDown = (e: KeyboardEvent) => {
            if (document.activeElement?.tagName === 'INPUT') return;
            if (zoom <= 1) return;

            const step = 100;
            const scrollOpts: ScrollToOptions = { behavior: 'smooth' };

            switch(e.key) {
                case 'ArrowUp': e.preventDefault(); container.scrollBy({ top: -step, ...scrollOpts }); break;
                case 'ArrowDown': e.preventDefault(); container.scrollBy({ top: step, ...scrollOpts }); break;
                case 'ArrowLeft': e.preventDefault(); container.scrollBy({ left: -step, ...scrollOpts }); break;
                case 'ArrowRight': e.preventDefault(); container.scrollBy({ left: step, ...scrollOpts }); break;
            }
        };

        const handleMouseDown = (e: MouseEvent) => {
            if (zoom <= 1) return;
            isDragging.current = true;
            container.classList.add('cursor-grabbing');
            startPos.current = {
                x: e.pageX - container.offsetLeft,
                y: e.pageY - container.offsetTop,
                scrollLeft: container.scrollLeft,
                scrollTop: container.scrollTop
            };
        };

        const handleMouseLeave = () => {
            isDragging.current = false;
            container.classList.remove('cursor-grabbing');
        };

        const handleMouseUp = () => {
            isDragging.current = false;
            container.classList.remove('cursor-grabbing');
        };

        const handleMouseMove = (e: MouseEvent) => {
            if (!isDragging.current) return;
            e.preventDefault();
            const x = e.pageX - container.offsetLeft;
            const y = e.pageY - container.offsetTop;
            const walkX = (x - startPos.current.x) * 1.5;
            const walkY = (y - startPos.current.y) * 1.5;
            container.scrollLeft = startPos.current.scrollLeft - walkX;
            container.scrollTop = startPos.current.scrollTop - walkY;
        };

        window.addEventListener('keydown', handleKeyDown);
        container.addEventListener('mousedown', handleMouseDown);
        container.addEventListener('mouseleave', handleMouseLeave);
        container.addEventListener('mouseup', handleMouseUp);
        container.addEventListener('mousemove', handleMouseMove);

        return () => {
            window.removeEventListener('keydown', handleKeyDown);
            container.removeEventListener('mousedown', handleMouseDown);
            container.removeEventListener('mouseleave', handleMouseLeave);
            container.removeEventListener('mouseup', handleMouseUp);
            container.removeEventListener('mousemove', handleMouseMove);
        };
    }, [zoom]);

    const selectedTerritory = useMemo(() => 
        mapPaths.find(t => t.id === selectedId), 
    [selectedId, mapPaths]);

    const hoveredTerritory = useMemo(() => 
        mapPaths.find(t => t.id === hoveredId), 
    [hoveredId, mapPaths]);

    const assignment = useMemo(() => 
        selectedId ? territoryAssignments.find(a => a.territoryId === selectedId) : null, 
    [territoryAssignments, selectedId]);

    const ambassador = useMemo(() => 
        assignment ? getUserById(assignment.userId) : null, 
    [assignment, getUserById]);

    const filteredUsers = useMemo(() => {
        if (!searchTerm.trim()) return [];
        return users.filter(u => 
            u.username.toLowerCase().includes(searchTerm.toLowerCase())
        ).slice(0, 5);
    }, [users, searchTerm]);

    const handleAssign = (userId: string) => {
        if (selectedId) {
            assignTerritory(selectedId, userId);
            setSearchTerm('');
        }
    };

    return (
        <div className="container mx-auto px-4 h-[calc(100vh-8rem)]">
            <div className="flex flex-col lg:flex-row h-full gap-4">

                {/* Mappa Area */}
                <div className="flex-1 bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden flex flex-col relative group">
                    <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-white z-20 shadow-sm">
                        <div className="flex items-center gap-3">
                            <div className="w-2 h-2 bg-primary rounded-full animate-pulse"></div>
                            <div>
                                <h1 className="text-lg font-black text-gray-900 tracking-tighter uppercase italic">Global Atlas</h1>
                                <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">
                                    {zoom > 1 ? 'Trascina per spostarti • Frecce per navigare' : 'Seleziona una nazione sulla mappa'}
                                </p>
                            </div>
                        </div>
                        <div className="flex items-center gap-2">
                            <div className="bg-gray-100 px-3 py-1 rounded-full text-[10px] font-black text-gray-500 uppercase tracking-tighter border border-gray-200">
                                Zoom: x{zoom}
                            </div>
                            {hoveredTerritory && (
                                <div className="bg-primary text-white px-3 py-1 rounded text-[10px] font-black uppercase tracking-wider animate-in fade-in zoom-in duration-150">
                                    {hoveredTerritory.name}
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Controls */}
                    <div className="absolute bottom-6 right-6 z-30 flex flex-col gap-1.5 shadow-2xl">
                        <button onClick={() => setZoom(z => Math.min(z + 1, 12))} className="w-12 h-12 bg-white border border-gray-200 rounded-t-xl flex items-center justify-center text-gray-800 hover:text-primary transition-all active:scale-95"><PlusIcon className="w-6 h-6" /></button>
                        <button onClick={() => setZoom(z => Math.max(z - 1, 1))} className="w-12 h-12 bg-white border border-gray-200 flex items-center justify-center text-gray-800 hover:text-primary transition-all active:scale-95"><div className="w-5 h-0.5 bg-current rounded-full" /></button>
                        <button onClick={() => setZoom(1)} className="w-12 h-12 bg-primary text-white rounded-b-xl flex items-center justify-center hover:bg-orange-600 transition-all font-black text-[10px]">RE-FIT</button>
                    </div>

                    {/* Map Interaction Layer */}
                    <div 
                        ref={scrollContainerRef}
                        className={`flex-1 bg-[#f8fafc] relative overflow-auto custom-scrollbar p-12 transition-colors ${zoom > 1 ? 'cursor-grab' : 'cursor-default'}`}
                    >
                        {isLoading ? (
                            <div className="absolute inset-0 flex flex-col items-center justify-center bg-white/90 z-10">
                                <div className="w-10 h-10 border-4 border-primary border-t-transparent rounded-full animate-spin mb-4"></div>
                                <p className="text-xs font-black text-gray-400 uppercase tracking-[0.3em]">Mapping Vectors...</p>
                            </div>
                        ) : error ? (
                            <div className="absolute inset-0 flex items-center justify-center text-red-500 font-bold">{error}</div>
                        ) : (
                            <div 
                                className="transition-all duration-300 ease-out origin-top-left mx-auto"
                                style={{ 
                                    width: `${zoom * 100}%`,
                                    minWidth: '100%',
                                    aspectRatio: '2000 / 1001',
                                }}
                            >
                                <svg 
                                    viewBox={viewBox} 
                                    className="w-full h-full block"
                                    preserveAspectRatio="xMidYMid meet"
                                    style={{ pointerEvents: 'auto' }}
                                >
                                    {mapPaths.map((territory, idx) => {
                                        const isAssigned = territoryAssignments.some(a => a.territoryId === territory.id);
                                        const isSelected = selectedId === territory.id;

                                        return (
                                            <path
                                                key={`${territory.id}-${idx}`}
                                                d={territory.d}
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    setSelectedId(territory.id);
                                                }}
                                                onMouseEnter={() => setHoveredId(territory.id)}
                                                onMouseLeave={() => setHoveredId(null)}
                                                vectorEffect="non-scaling-stroke"
                                                pointerEvents="visiblePainted"
                                                className={`transition-all duration-150 outline-none cursor-pointer ${
                                                    isSelected 
                                                        ? 'fill-primary stroke-gray-900 stroke-[2px]' 
                                                        : isAssigned 
                                                            ? 'fill-orange-400 stroke-gray-900 stroke-[1px] hover:fill-orange-500' 
                                                            : 'fill-white stroke-gray-200 stroke-[0.5px] hover:fill-gray-100 hover:stroke-gray-400'
                                                }`}
                                            >
                                                <title>{territory.name}</title>
                                            </path>
                                        );
                                    })}
                                </svg>
                            </div>
                        )}
                    </div>
                </div>

                {/* Sidebar Info */}
                <aside className="w-full lg:w-[400px] shrink-0 flex flex-col gap-4">
                    <div className="bg-white rounded-xl border border-gray-200 shadow-sm p-6 flex flex-col flex-1 overflow-hidden">
                        {selectedTerritory ? (
                            <div className="space-y-6 animate-in slide-in-from-right-4 duration-300 flex flex-col h-full">
                                <div className="flex items-center gap-5">
                                    <div className="relative shrink-0 group">
                                        <img 
                                            src={getFlagUrl(selectedTerritory.id)} 
                                            alt={selectedTerritory.id} 
                                            className="w-24 h-16 rounded-lg shadow-xl border-2 border-white object-cover transition-transform group-hover:scale-105"
                                            onError={(e) => (e.currentTarget.style.display = 'none')}
                                        />
                                        <div className="absolute -bottom-2 -right-2 bg-gray-900 text-white px-2 py-1 rounded-md text-[9px] font-black uppercase shadow-lg">
                                            {selectedTerritory.id.length <= 3 ? selectedTerritory.id : 'REG'}
                                        </div>
                                    </div>
                                    <div className="min-w-0">
                                        <h2 className="text-3xl font-black text-gray-900 tracking-tighter truncate leading-none uppercase italic">
                                            {selectedTerritory.name}
                                        </h2>
                                        <p className="text-[10px] font-bold text-primary uppercase tracking-[0.2em] mt-2">Dati Geopolitici Verificati</p>
                                    </div>
                                </div>

                                <div className="pt-6 border-t border-gray-100">
                                    <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
                                        <UsersIcon className="w-4 h-4" /> Autorità Diplomatica
                                    </h3>

                                    {ambassador ? (
                                        <div className="bg-gray-900 rounded-2xl p-6 text-white hover:shadow-2xl transition-all group relative overflow-hidden">
                                            <div className="absolute -right-4 -top-4 w-24 h-24 bg-white/5 rounded-full group-hover:scale-150 transition-transform duration-700"></div>
                                            <div className="flex items-center gap-4 mb-6 relative z-10">
                                                <UserAvatar user={ambassador} className="w-16 h-16 border-2 border-primary shadow-lg" />
                                                <div className="min-w-0">
                                                    <Link to={`/u/${ambassador.username}`} className="font-black text-2xl hover:text-primary transition-colors block truncate tracking-tighter">
                                                        u/{ambassador.username}
                                                    </Link>
                                                    <div className="flex items-center gap-1.5 mt-1">
                                                        <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
                                                        <p className="text-[9px] text-gray-400 font-black uppercase tracking-widest">In Carica</p>
                                                    </div>
                                                </div>
                                            </div>

                                            <div className="flex gap-2 relative z-10">
                                                <Link to={`/u/${ambassador.username}`} className="flex-1 bg-white text-gray-900 font-black py-3 rounded-xl text-[10px] text-center hover:bg-primary hover:text-white transition-all uppercase tracking-widest">Dossier Profilo</Link>
                                                <Link to={`/messages/${ambassador.username}`} className="px-4 bg-primary text-white rounded-xl hover:bg-orange-600 transition-all flex items-center justify-center">
                                                    <MessageIcon className="w-5 h-5" />
                                                </Link>
                                            </div>
                                        </div>
                                    ) : (
                                        <div className="bg-gray-50 border-2 border-dashed border-gray-200 rounded-2xl p-12 text-center group hover:border-primary/30 transition-colors">
                                            <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center mx-auto mb-4 border border-gray-100 shadow-sm text-gray-300 group-hover:text-primary transition-colors">
                                                <PlusIcon className="w-6 h-6" />
                                            </div>
                                            <p className="text-[12px] font-black text-gray-400 uppercase tracking-widest">Nessun Rappresentante</p>
                                            <p className="text-[10px] text-gray-400 mt-2 font-medium">Area disponibile per nuove nomine amministrative.</p>
                                        </div>
                                    )}
                                </div>

                                {currentUser && isAdmin(currentUser.id) && (
                                    <div className="pt-6 mt-auto border-t border-gray-100">
                                        <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest mb-3">Gestione Territoriale Admin</label>
                                        <div className="relative">
                                            <input 
                                                type="text" 
                                                value={searchTerm}
                                                onChange={(e) => setSearchTerm(e.target.value)}
                                                className="w-full bg-gray-50 border border-gray-200 rounded-xl p-4 text-xs focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none font-bold text-gray-900 transition-all"
                                                placeholder="Cerca u/ per assegnare incarico..."
                                            />
                                            {filteredUsers.length > 0 && (
                                                <div className="absolute bottom-full left-0 right-0 mb-2 bg-white border border-gray-200 rounded-2xl shadow-2xl z-50 overflow-hidden divide-y divide-gray-50 animate-in fade-in slide-in-from-bottom-2">
                                                    {filteredUsers.map(user => (
                                                        <button 
                                                            key={user.id}
                                                            onClick={() => handleAssign(user.id)}
                                                            className="w-full px-4 py-4 flex items-center gap-3 hover:bg-primary hover:text-white group/u text-left transition-all"
                                                        >
                                                            <UserAvatar user={user} className="w-8 h-8 group-hover/u:border-white transition-all" />
                                                            <span className="font-bold text-sm">u/{user.username}</span>
                                                        </button>
                                                    ))}
                                                </div>
                                            )}
                                        </div>
                                        {ambassador && (
                                            <button 
                                                onClick={() => handleAssign('')}
                                                className="w-full mt-4 text-[10px] font-black text-red-500 hover:text-red-700 uppercase py-3 border-2 border-transparent hover:border-red-50 rounded-xl transition-all tracking-widest"
                                            >
                                                Revoca Incarico Attuale
                                            </button>
                                        )}
                                    </div>
                                )}
                            </div>
                        ) : (
                            <div className="flex-1 flex flex-col items-center justify-center text-center p-12 opacity-50 select-none">
                                <div className="w-24 h-24 bg-gray-50 rounded-full flex items-center justify-center mb-8 border-2 border-gray-100 shadow-inner">
                                    <svg className="w-12 h-12 text-gray-200" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 20l-5.447-2.724A2 2 0 013 15.487V6a2 2 0 011.106-1.789l5.447-2.724a2 2 0 011.894 0l5.447 2.724A2 2 0 0118 6v9.487a2 2 0 01-1.106 1.789L11.447 20a2 2 0 01-1.894 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 3v17M13 3v17" /></svg>
                                </div>
                                <h2 className="text-2xl font-black text-gray-900 uppercase italic tracking-tighter">Radar Inattivo</h2>
                                <p className="text-[11px] text-gray-400 font-bold uppercase mt-3 tracking-[0.2em] leading-relaxed max-w-[200px]">
                                    Sposta il cursore sulla mappa per analizzare i distretti globali.
                                </p>
                            </div>
                        )}
                    </div>

                    {/* Legenda Quick View */}
                    <div className="bg-gray-900 rounded-xl p-4 flex justify-between items-center text-white">
                        <div className="flex items-center gap-2">
                            <div className="w-3 h-3 bg-white rounded-sm"></div>
                            <span className="text-[9px] font-black uppercase tracking-widest">Libero</span>
                        </div>
                        <div className="flex items-center gap-2">
                            <div className="w-3 h-3 bg-orange-400 rounded-sm"></div>
                            <span className="text-[9px] font-black uppercase tracking-widest">Presidiato</span>
                        </div>
                        <div className="flex items-center gap-2">
                            <div className="w-3 h-3 bg-primary rounded-sm"></div>
                            <span className="text-[9px] font-black uppercase tracking-widest">Focus</span>
                        </div>
                    </div>
                </aside>
            </div>
            <style>{`
                .custom-scrollbar::-webkit-scrollbar { width: 5px; height: 5px; }
                .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
                .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }
                .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #cbd5e1; }
                .cursor-grabbing { cursor: grabbing !important; }
            `}</style>
        </div>
    );
};

export default MapPage;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useAuth, useData, getFlagUrl } from '../hooks/useStore';
import UserAvatar from '../components/UserAvatar';
import { Link } from 'react-router-dom';
import { MessageIcon, UsersIcon, PlusIcon } from '../components/Icons';

interface MapPath {
  id: string;
  d: string;
  name: string;
}

const MapPage: React.FC = () => {
    const { currentUser, users, getUserById, isAdmin } = useAuth();
    const { territoryAssignments, assignTerritory } = useData();
    const [selectedId, setSelectedId] = useState<string | null>(null);
    const [hoveredId, setHoveredId] = useState<string | null>(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [mapPaths, setMapPaths] = useState<MapPath[]>([]);
    const [viewBox, setViewBox] = useState<string>('0 0 1000 600');
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [zoom, setZoom] = useState(1);

    const scrollContainerRef = useRef<HTMLDivElement>(null);
    const isDragging = useRef(false);
    const startPos = useRef({ x: 0, y: 0, scrollLeft: 0, scrollTop: 0 });

    // Localizzatore nomi in Italiano
    const regionNames = useMemo(() => new Intl.DisplayNames(['it'], { type: 'region' }), []);

    useEffect(() => {
        const fetchMap = async () => {
            try {
                // Utilizziamo la mappa professionale di AmCharts (worldLow)
                const response = await fetch('https://raw.githubusercontent.com/amcharts/amcharts-geodata/master/dist/svg/worldLow.svg');
                if (!response.ok) throw new Error('Errore di caricamento mappa');
                const svgText = await response.text();

                const parser = new DOMParser();
                const doc = parser.parseFromString(svgText, 'image/svg+xml');
                const svgEl = doc.querySelector('svg');

                if (svgEl && svgEl.getAttribute('viewBox')) {
                    setViewBox(svgEl.getAttribute('viewBox')!);
                }

                // In AmCharts le nazioni sono <path> con attributi id (ISO) e title
                const paths = Array.from(doc.querySelectorAll('path'));
                const extractedPaths: MapPath[] = paths.map((p, index) => {
                    const attrId = p.getAttribute('id') || '';
                    const attrTitle = p.getAttribute('title') || p.getAttribute('name');

                    let finalName = attrTitle;

                    // Se l'ID è un codice ISO (es: IT, US, FR), usiamo Intl per il nome localizzato
                    if (attrId && attrId.length === 2) {
                        try {
                            finalName = regionNames.of(attrId.toUpperCase());
                        } catch (e) {
                            // Fallback al titolo originale se Intl fallisce
                            finalName = attrTitle || attrId;
                        }
                    }

                    // Se non abbiamo ancora un nome pulito (es. nomi tecnici tipo p-90), usiamo un fallback leggibile
                    if (!finalName || /^[pP]-\d+$/.test(finalName)) {
                        finalName = attrTitle || `Settore ${attrId || index + 1}`;
                    }

                    return {
                        id: attrId || `area-${index}`,
                        d: p.getAttribute('d') || '',
                        name: finalName
                    };
                }).filter(p => p.d);

                setMapPaths(extractedPaths);
                setIsLoading(false);
            } catch (err) {
                console.error(err);
                setError('Impossibile caricare la cartografia globale.');
                setIsLoading(false);
            }
        };

        fetchMap();
    }, [regionNames]);

    // Navigazione con Tastiera e Drag del Mouse
    useEffect(() => {
        const container = scrollContainerRef.current;
        if (!container) return;

        const handleKeyDown = (e: KeyboardEvent) => {
            if (document.activeElement?.tagName === 'INPUT') return;
            if (zoom <= 1) return;

            const step = 120;
            const scrollOpts: ScrollToOptions = { behavior: 'smooth' };

            switch(e.key) {
                case 'ArrowUp': e.preventDefault(); container.scrollBy({ top: -step, ...scrollOpts }); break;
                case 'ArrowDown': e.preventDefault(); container.scrollBy({ top: step, ...scrollOpts }); break;
                case 'ArrowLeft': e.preventDefault(); container.scrollBy({ left: -step, ...scrollOpts }); break;
                case 'ArrowRight': e.preventDefault(); container.scrollBy({ left: step, ...scrollOpts }); break;
            }
        };

        const handleMouseDown = (e: MouseEvent) => {
            if (zoom <= 1) return;
            isDragging.current = true;
            container.classList.add('cursor-grabbing');
            startPos.current = {
                x: e.pageX - container.offsetLeft,
                y: e.pageY - container.offsetTop,
                scrollLeft: container.scrollLeft,
                scrollTop: container.scrollTop
            };
        };

        const handleMouseLeave = () => { isDragging.current = false; container.classList.remove('cursor-grabbing'); };
        const handleMouseUp = () => { isDragging.current = false; container.classList.remove('cursor-grabbing'); };

        const handleMouseMove = (e: MouseEvent) => {
            if (!isDragging.current) return;
            e.preventDefault();
            const x = e.pageX - container.offsetLeft;
            const y = e.pageY - container.offsetTop;
            const walkX = (x - startPos.current.x) * 1.5;
            const walkY = (y - startPos.current.y) * 1.5;
            container.scrollLeft = startPos.current.scrollLeft - walkX;
            container.scrollTop = startPos.current.scrollTop - walkY;
        };

        window.addEventListener('keydown', handleKeyDown);
        container.addEventListener('mousedown', handleMouseDown);
        container.addEventListener('mouseleave', handleMouseLeave);
        container.addEventListener('mouseup', handleMouseUp);
        container.addEventListener('mousemove', handleMouseMove);

        return () => {
            window.removeEventListener('keydown', handleKeyDown);
            container.removeEventListener('mousedown', handleMouseDown);
            container.removeEventListener('mouseleave', handleMouseLeave);
            container.removeEventListener('mouseup', handleMouseUp);
            container.removeEventListener('mousemove', handleMouseMove);
        };
    }, [zoom]);

    const selectedTerritory = useMemo(() => 
        mapPaths.find(t => t.id === selectedId), 
    [selectedId, mapPaths]);

    const hoveredTerritory = useMemo(() => 
        mapPaths.find(t => t.id === hoveredId), 
    [hoveredId, mapPaths]);

    const assignment = useMemo(() => 
        selectedId ? territoryAssignments.find(a => a.territoryId === selectedId) : null, 
    [territoryAssignments, selectedId]);

    const ambassador = useMemo(() => 
        assignment ? getUserById(assignment.userId) : null, 
    [assignment, getUserById]);

    const filteredUsers = useMemo(() => {
        if (!searchTerm.trim()) return [];
        return users.filter(u => 
            u.username.toLowerCase().includes(searchTerm.toLowerCase())
        ).slice(0, 5);
    }, [users, searchTerm]);

    const handleAssign = (userId: string) => {
        if (selectedId) {
            assignTerritory(selectedId, userId);
            setSearchTerm('');
        }
    };

    return (
        <div className="container mx-auto px-4 h-[calc(100vh-8rem)]">
            <div className="flex flex-col lg:flex-row h-full gap-4">

                {/* Mappa - Vista Principale */}
                <div className="flex-1 bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden flex flex-col relative group">
                    <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-white z-20 shadow-sm">
                        <div className="flex items-center gap-3">
                            <div className="w-2 h-2 bg-primary rounded-full animate-pulse"></div>
                            <div>
                                <h1 className="text-lg font-black text-gray-900 tracking-tighter uppercase italic">The Atlas</h1>
                                <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">
                                    {zoom > 1 ? 'Usa le frecce o trascina per esplorare' : 'Clicca su una nazione per i dettagli'}
                                </p>
                            </div>
                        </div>
                        <div className="flex items-center gap-2">
                            <div className="bg-gray-100 px-3 py-1 rounded-full text-[10px] font-black text-gray-500 uppercase tracking-tighter border border-gray-200">
                                Magnification: x{zoom}
                            </div>
                            {hoveredTerritory && (
                                <div className="bg-primary text-white px-3 py-1 rounded text-[10px] font-black uppercase tracking-wider animate-in fade-in zoom-in duration-150 border border-orange-600 shadow-sm">
                                    {hoveredTerritory.name}
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Controlli Overlay */}
                    <div className="absolute bottom-6 right-6 z-30 flex flex-col gap-1.5 shadow-2xl">
                        <button onClick={() => setZoom(z => Math.min(z + 1, 12))} className="w-12 h-12 bg-white border border-gray-200 rounded-t-xl flex items-center justify-center text-gray-800 hover:text-primary transition-all active:scale-95 shadow-sm" title="Zoom In"><PlusIcon className="w-6 h-6" /></button>
                        <button onClick={() => setZoom(z => Math.max(z - 1, 1))} className="w-12 h-12 bg-white border border-gray-200 flex items-center justify-center text-gray-800 hover:text-primary transition-all active:scale-95 shadow-sm" title="Zoom Out"><div className="w-5 h-0.5 bg-current rounded-full" /></button>
                        <button onClick={() => setZoom(1)} className="w-12 h-12 bg-primary text-white rounded-b-xl flex items-center justify-center hover:bg-orange-600 transition-all font-black text-[10px] shadow-sm">RE-FIT</button>
                    </div>

                    {/* Area Cartografica */}
                    <div 
                        ref={scrollContainerRef}
                        className={`flex-1 bg-[#f0f4f8] relative overflow-auto custom-scrollbar p-12 transition-colors ${zoom > 1 ? 'cursor-grab' : 'cursor-default'}`}
                    >
                        {isLoading ? (
                            <div className="absolute inset-0 flex flex-col items-center justify-center bg-white/90 z-10">
                                <div className="w-12 h-12 border-4 border-primary border-t-transparent rounded-full animate-spin mb-4"></div>
                                <p className="text-xs font-black text-gray-400 uppercase tracking-[0.4em]">Acquiring Sat-Link...</p>
                            </div>
                        ) : error ? (
                            <div className="absolute inset-0 flex items-center justify-center text-red-500 font-bold">{error}</div>
                        ) : (
                            <div 
                                className="transition-all duration-300 ease-out origin-top-left mx-auto"
                                style={{ 
                                    width: `${zoom * 100}%`,
                                    minWidth: '100%',
                                    aspectRatio: '1000 / 600',
                                }}
                            >
                                <svg 
                                    viewBox={viewBox} 
                                    className="w-full h-full block"
                                    preserveAspectRatio="xMidYMid meet"
                                >
                                    {mapPaths.map((territory, idx) => {
                                        const isAssigned = territoryAssignments.some(a => a.territoryId === territory.id);
                                        const isSelected = selectedId === territory.id;

                                        return (
                                            <path
                                                key={`${territory.id}-${idx}`}
                                                d={territory.d}
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    setSelectedId(territory.id);
                                                }}
                                                onMouseEnter={() => setHoveredId(territory.id)}
                                                onMouseLeave={() => setHoveredId(null)}
                                                vectorEffect="non-scaling-stroke"
                                                className={`transition-all duration-150 outline-none cursor-pointer ${
                                                    isSelected 
                                                        ? 'fill-primary stroke-gray-900 stroke-[2.5px]' 
                                                        : isAssigned 
                                                            ? 'fill-orange-400 stroke-gray-900 stroke-[1.2px] hover:fill-orange-500' 
                                                            : 'fill-white stroke-gray-300 stroke-[0.6px] hover:fill-gray-100 hover:stroke-gray-500'
                                                }`}
                                            >
                                                <title>{territory.name}</title>
                                            </path>
                                        );
                                    })}
                                </svg>
                            </div>
                        )}
                    </div>
                </div>

                {/* Sidebar Dettagli */}
                <aside className="w-full lg:w-[400px] shrink-0 flex flex-col gap-4">
                    <div className="bg-white rounded-xl border border-gray-200 shadow-sm p-6 flex flex-col flex-1 overflow-hidden">
                        {selectedTerritory ? (
                            <div className="space-y-6 animate-in slide-in-from-right-4 duration-300 flex flex-col h-full">
                                <div className="flex items-center gap-5">
                                    <div className="relative shrink-0 group">
                                        <img 
                                            src={getFlagUrl(selectedTerritory.id)} 
                                            alt={selectedTerritory.id} 
                                            className="w-24 h-16 rounded-lg shadow-xl border-2 border-white object-cover transition-transform group-hover:scale-105"
                                            onError={(e) => (e.currentTarget.style.display = 'none')}
                                        />
                                        <div className="absolute -bottom-2 -right-2 bg-gray-900 text-white px-2 py-1 rounded-md text-[9px] font-black uppercase shadow-lg">
                                            {selectedTerritory.id.length <= 3 ? selectedTerritory.id : 'ISO'}
                                        </div>
                                    </div>
                                    <div className="min-w-0">
                                        <h2 className="text-3xl font-black text-gray-900 tracking-tighter truncate leading-none uppercase italic">
                                            {selectedTerritory.name}
                                        </h2>
                                        <p className="text-[10px] font-bold text-primary uppercase tracking-[0.2em] mt-2">Territorio Autorizzato</p>
                                    </div>
                                </div>

                                <div className="pt-6 border-t border-gray-100">
                                    <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
                                        <UsersIcon className="w-4 h-4" /> Rappresentante in Carica
                                    </h3>

                                    {ambassador ? (
                                        <div className="bg-gray-900 rounded-2xl p-6 text-white hover:shadow-2xl transition-all group relative overflow-hidden">
                                            <div className="absolute -right-4 -top-4 w-24 h-24 bg-white/5 rounded-full group-hover:scale-150 transition-transform duration-700"></div>
                                            <div className="flex items-center gap-4 mb-6 relative z-10">
                                                <UserAvatar user={ambassador} className="w-16 h-16 border-2 border-primary shadow-lg" />
                                                <div className="min-w-0">
                                                    <Link to={`/u/${ambassador.username}`} className="font-black text-2xl hover:text-primary transition-colors block truncate tracking-tighter">
                                                        u/{ambassador.username}
                                                    </Link>
                                                    <div className="flex items-center gap-1.5 mt-1">
                                                        <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
                                                        <p className="text-[9px] text-gray-400 font-black uppercase tracking-widest">Diplomatico</p>
                                                    </div>
                                                </div>
                                            </div>

                                            <div className="flex gap-2 relative z-10">
                                                <Link to={`/u/${ambassador.username}`} className="flex-1 bg-white text-gray-900 font-black py-3 rounded-xl text-[10px] text-center hover:bg-primary hover:text-white transition-all uppercase tracking-widest">Dossier Profilo</Link>
                                                <Link to={`/messages/${ambassador.username}`} className="px-4 bg-primary text-white rounded-xl hover:bg-orange-600 transition-all flex items-center justify-center shadow-lg">
                                                    <MessageIcon className="w-5 h-5" />
                                                </Link>
                                            </div>
                                        </div>
                                    ) : (
                                        <div className="bg-gray-50 border-2 border-dashed border-gray-200 rounded-2xl p-12 text-center group hover:border-primary/30 transition-colors">
                                            <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center mx-auto mb-4 border border-gray-100 shadow-sm text-gray-300 group-hover:text-primary transition-colors">
                                                <PlusIcon className="w-6 h-6" />
                                            </div>
                                            <p className="text-[12px] font-black text-gray-400 uppercase tracking-widest">Sede Vacante</p>
                                            <p className="text-[10px] text-gray-400 mt-2 font-medium">L'area è attualmente libera da incarichi diplomatici.</p>
                                        </div>
                                    )}
                                </div>

                                {currentUser && isAdmin(currentUser.id) && (
                                    <div className="pt-6 mt-auto border-t border-gray-100">
                                        <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest mb-3">Pannello Controllo Admin</label>
                                        <div className="relative">
                                            <input 
                                                type="text" 
                                                value={searchTerm}
                                                onChange={(e) => setSearchTerm(e.target.value)}
                                                className="w-full bg-gray-50 border border-gray-200 rounded-xl p-4 text-xs focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none font-bold text-gray-900 transition-all shadow-inner"
                                                placeholder="Incarica u/ per questa regione..."
                                            />
                                            {filteredUsers.length > 0 && (
                                                <div className="absolute bottom-full left-0 right-0 mb-2 bg-white border border-gray-200 rounded-2xl shadow-2xl z-50 overflow-hidden divide-y divide-gray-50 animate-in fade-in slide-in-from-bottom-2">
                                                    {filteredUsers.map(user => (
                                                        <button 
                                                            key={user.id}
                                                            onClick={() => handleAssign(user.id)}
                                                            className="w-full px-4 py-4 flex items-center gap-3 hover:bg-primary hover:text-white group/u text-left transition-all"
                                                        >
                                                            <UserAvatar user={user} className="w-8 h-8 group-hover/u:border-white transition-all shadow-sm" />
                                                            <span className="font-bold text-sm">u/{user.username}</span>
                                                        </button>
                                                    ))}
                                                </div>
                                            )}
                                        </div>
                                        {ambassador && (
                                            <button 
                                                onClick={() => handleAssign('')}
                                                className="w-full mt-4 text-[10px] font-black text-red-500 hover:text-red-700 uppercase py-3 border-2 border-transparent hover:border-red-50 rounded-xl transition-all tracking-widest"
                                            >
                                                Revoca Ambasciatore
                                            </button>
                                        )}
                                    </div>
                                )}
                            </div>
                        ) : (
                            <div className="flex-1 flex flex-col items-center justify-center text-center p-12 opacity-50 select-none">
                                <div className="w-24 h-24 bg-gray-50 rounded-full flex items-center justify-center mb-8 border-2 border-gray-100 shadow-inner">
                                    <svg className="w-12 h-12 text-gray-200" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 20l-5.447-2.724A2 2 0 013 15.487V6a2 2 0 011.106-1.789l5.447-2.724a2 2 0 011.894 0l5.447 2.724A2 2 0 0118 6v9.487a2 2 0 01-1.106 1.789L11.447 20a2 2 0 01-1.894 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 3v17M13 3v17" /></svg>
                                </div>
                                <h2 className="text-2xl font-black text-gray-900 uppercase italic tracking-tighter">Atlas Offline</h2>
                                <p className="text-[11px] text-gray-400 font-bold uppercase mt-3 tracking-[0.2em] leading-relaxed max-w-[200px]">
                                    Sposta il cursore o naviga la mappa per interrogare i database territoriali.
                                </p>
                            </div>
                        )}
                    </div>

                    {/* Legenda Dinamica */}
                    <div className="bg-gray-900 rounded-xl p-4 flex justify-between items-center text-white border border-gray-800 shadow-xl">
                        <div className="flex items-center gap-2">
                            <div className="w-3 h-3 bg-white rounded-sm"></div>
                            <span className="text-[9px] font-black uppercase tracking-widest text-gray-400">Neutro</span>
                        </div>
                        <div className="flex items-center gap-2">
                            <div className="w-3 h-3 bg-orange-400 rounded-sm"></div>
                            <span className="text-[9px] font-black uppercase tracking-widest text-gray-400">Presidio</span>
                        </div>
                        <div className="flex items-center gap-2">
                            <div className="w-3 h-3 bg-primary rounded-sm"></div>
                            <span className="text-[9px] font-black uppercase tracking-widest text-white">Target</span>
                        </div>
                    </div>
                </aside>
            </div>
            <style>{`
                .custom-scrollbar::-webkit-scrollbar { width: 4px; height: 4px; }
                .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
                .custom-scrollbar::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 10px; }
                .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #94a3b8; }
                .cursor-grabbing { cursor: grabbing !important; }
            `}</style>
        </div>
    );
};

export default MapPage;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useAuth, useData, getFlagUrl } from '../hooks/useStore';
import UserAvatar from '../components/UserAvatar';
import { Link } from 'react-router-dom';
import { MessageIcon, UsersIcon, PlusIcon } from '../components/Icons';

interface MapPath {
  id: string;
  d: string;
  name: string;
}

const MapPage: React.FC = () => {
    const { currentUser, users, getUserById, isAdmin } = useAuth();
    const { territoryAssignments, assignTerritory } = useData();
    const [selectedId, setSelectedId] = useState<string | null>(null);
    const [hoveredId, setHoveredId] = useState<string | null>(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [mapPaths, setMapPaths] = useState<MapPath[]>([]);
    const [viewBox, setViewBox] = useState<string>('0 0 1000 600');
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [zoom, setZoom] = useState(1);

    const scrollContainerRef = useRef<HTMLDivElement>(null);
    const isDragging = useRef(false);
    const startPos = useRef({ x: 0, y: 0, scrollLeft: 0, scrollTop: 0 });

    // Traduttore automatico ISO -> Nome Italiano
    const regionNames = useMemo(() => new Intl.DisplayNames(['it'], { type: 'region' }), []);

    useEffect(() => {
        const fetchMap = async () => {
            try {
                // Utilizziamo la mappa AmCharts professionale caricata tramite Raw GitHub (CORS Friendly)
                const response = await fetch('https://raw.githubusercontent.com/amcharts/amcharts-geodata/master/dist/svg/worldLow.svg');
                if (!response.ok) throw new Error('Errore nel recupero dei dati cartografici');
                const svgText = await response.text();

                const parser = new DOMParser();
                const doc = parser.parseFromString(svgText, 'image/svg+xml');
                const svgEl = doc.querySelector('svg');

                if (svgEl && svgEl.getAttribute('viewBox')) {
                    setViewBox(svgEl.getAttribute('viewBox')!);
                }

                const paths = Array.from(doc.querySelectorAll('path'));
                const extractedPaths: MapPath[] = paths.map((p, index) => {
                    const attrId = p.getAttribute('id') || '';
                    const attrTitle = p.getAttribute('title') || p.getAttribute('name') || '';

                    let finalName = attrTitle;

                    // Se abbiamo un codice ISO (2 lettere), usiamo Intl per avere il nome vero in italiano
                    if (attrId && attrId.length === 2) {
                        try {
                            const translated = regionNames.of(attrId.toUpperCase());
                            if (translated) finalName = translated;
                        } catch (e) {
                            finalName = attrTitle || attrId;
                        }
                    }

                    // Pulizia finale per evitare codici tecnici come p-90
                    if (!finalName || /^[pP]-\d+$/.test(finalName) || !isNaN(Number(finalName))) {
                        finalName = attrTitle || `Settore Geografico ${attrId || index + 1}`;
                    }

                    return {
                        id: attrId || `area-${index}`,
                        d: p.getAttribute('d') || '',
                        name: finalName
                    };
                }).filter(p => p.d);

                setMapPaths(extractedPaths);
                setIsLoading(false);
            } catch (err) {
                console.error('Map Load Error:', err);
                setError('Connessione al satellite fallita. Riprova più tardi.');
                setIsLoading(false);
            }
        };

        fetchMap();
    }, [regionNames]);

    // Navigazione: Mouse Drag & Frecce Tastiera
    useEffect(() => {
        const container = scrollContainerRef.current;
        if (!container) return;

        const handleKeyDown = (e: KeyboardEvent) => {
            if (document.activeElement?.tagName === 'INPUT') return;
            if (zoom <= 1) return;

            const step = 100;
            const scrollOpts: ScrollToOptions = { behavior: 'smooth' };

            switch(e.key) {
                case 'ArrowUp': e.preventDefault(); container.scrollBy({ top: -step, ...scrollOpts }); break;
                case 'ArrowDown': e.preventDefault(); container.scrollBy({ top: step, ...scrollOpts }); break;
                case 'ArrowLeft': e.preventDefault(); container.scrollBy({ left: -step, ...scrollOpts }); break;
                case 'ArrowRight': e.preventDefault(); container.scrollBy({ left: step, ...scrollOpts }); break;
            }
        };

        const handleMouseDown = (e: MouseEvent) => {
            if (zoom <= 1) return;
            isDragging.current = true;
            container.classList.add('cursor-grabbing');
            startPos.current = {
                x: e.pageX - container.offsetLeft,
                y: e.pageY - container.offsetTop,
                scrollLeft: container.scrollLeft,
                scrollTop: container.scrollTop
            };
        };

        const stopDragging = () => {
            isDragging.current = false;
            container.classList.remove('cursor-grabbing');
        };

        const handleMouseMove = (e: MouseEvent) => {
            if (!isDragging.current) return;
            e.preventDefault();
            const x = e.pageX - container.offsetLeft;
            const y = e.pageY - container.offsetTop;
            const walkX = (x - startPos.current.x) * 1.5;
            const walkY = (y - startPos.current.y) * 1.5;
            container.scrollLeft = startPos.current.scrollLeft - walkX;
            container.scrollTop = startPos.current.scrollTop - walkY;
        };

        window.addEventListener('keydown', handleKeyDown);
        container.addEventListener('mousedown', handleMouseDown);
        window.addEventListener('mouseup', stopDragging);
        container.addEventListener('mouseleave', stopDragging);
        container.addEventListener('mousemove', handleMouseMove);

        return () => {
            window.removeEventListener('keydown', handleKeyDown);
            container.removeEventListener('mousedown', handleMouseDown);
            window.removeEventListener('mouseup', stopDragging);
            container.removeEventListener('mouseleave', stopDragging);
            container.removeEventListener('mousemove', handleMouseMove);
        };
    }, [zoom]);

    const selectedTerritory = useMemo(() => 
        mapPaths.find(t => t.id === selectedId), 
    [selectedId, mapPaths]);

    const hoveredTerritory = useMemo(() => 
        mapPaths.find(t => t.id === hoveredId), 
    [hoveredId, mapPaths]);

    const assignment = useMemo(() => 
        selectedId ? territoryAssignments.find(a => a.territoryId === selectedId) : null, 
    [territoryAssignments, selectedId]);

    const ambassador = useMemo(() => 
        assignment ? getUserById(assignment.userId) : null, 
    [assignment, getUserById]);

    const filteredUsers = useMemo(() => {
        if (!searchTerm.trim()) return [];
        return users.filter(u => 
            u.username.toLowerCase().includes(searchTerm.toLowerCase())
        ).slice(0, 5);
    }, [users, searchTerm]);

    const handleAssign = (userId: string) => {
        if (selectedId) {
            assignTerritory(selectedId, userId);
            setSearchTerm('');
        }
    };

    return (
        <div className="container mx-auto px-4 h-[calc(100vh-8rem)]">
            <div className="flex flex-col lg:flex-row h-full gap-4">

                {/* Mappa Main View */}
