                    <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-white z-20 shadow-sm">
                        <div className="flex items-center gap-3">
                            <div className="w-2 h-2 bg-primary rounded-full animate-pulse"></div>
                            <div>
                                <h1 className="text-lg font-black text-gray-900 tracking-tighter uppercase italic">Global Interface</h1>
                                <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">
                                    {zoom > 1 ? 'Drag per spostarti • Frecce per navigare' : 'Seleziona un settore sulla mappa'}
                                </p>
                            </div>
                        </div>
                        <div className="flex items-center gap-2">
                            <div className="bg-gray-100 px-3 py-1 rounded-full text-[10px] font-black text-gray-500 uppercase tracking-tighter border border-gray-200">
                                Magnification: x{zoom}
                            </div>
                            {hoveredTerritory && (
                                <div className="bg-primary text-white px-3 py-1 rounded text-[10px] font-black uppercase tracking-wider animate-in fade-in zoom-in duration-150 border border-orange-600 shadow-sm">
                                    {hoveredTerritory.name}
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Floating Controls */}
                    <div className="absolute bottom-6 right-6 z-30 flex flex-col gap-1 shadow-2xl">
                        <button onClick={() => setZoom(z => Math.min(z + 1, 15))} className="w-12 h-12 bg-white border border-gray-200 rounded-t-xl flex items-center justify-center text-gray-800 hover:text-primary transition-all active:scale-95 shadow-sm" title="Zoom In"><PlusIcon className="w-6 h-6" /></button>
                        <button onClick={() => setZoom(z => Math.max(z - 1, 1))} className="w-12 h-12 bg-white border border-gray-200 flex items-center justify-center text-gray-800 hover:text-primary transition-all active:scale-95 shadow-sm" title="Zoom Out"><div className="w-5 h-0.5 bg-current rounded-full" /></button>
                        <button onClick={() => setZoom(1)} className="w-12 h-12 bg-primary text-white rounded-b-xl flex items-center justify-center hover:bg-orange-600 transition-all font-black text-[10px] shadow-sm">RE-FIT</button>
                    </div>

                    {/* SVG Interaction Layer */}
                    <div 
                        ref={scrollContainerRef}
                        className={`flex-1 bg-[#f1f5f9] relative overflow-auto custom-scrollbar p-12 transition-colors ${zoom > 1 ? 'cursor-grab' : 'cursor-default'}`}
                    >
                        {isLoading ? (
                            <div className="absolute inset-0 flex flex-col items-center justify-center bg-white/90 z-10">
                                <div className="w-12 h-12 border-4 border-primary border-t-transparent rounded-full animate-spin mb-4"></div>
                                <p className="text-xs font-black text-gray-400 uppercase tracking-[0.4em]">Calibrazione Orbita...</p>
                            </div>
                        ) : error ? (
                            <div className="absolute inset-0 flex flex-col items-center justify-center text-red-500 font-bold bg-white/80 z-10 p-8 text-center">
                                <span className="text-4xl mb-4">⚠️</span>
                                <p className="uppercase tracking-widest text-sm">{error}</p>
                            </div>
                        ) : (
                            <div 
                                className="transition-all duration-300 ease-out origin-top-left mx-auto"
                                style={{ 
                                    width: `${zoom * 100}%`,
                                    minWidth: '100%',
                                    aspectRatio: '1000 / 600',
                                }}
                            >
                                <svg 
                                    viewBox={viewBox} 
                                    className="w-full h-full block"
                                    preserveAspectRatio="xMidYMid meet"
                                >
                                    {mapPaths.map((territory, idx) => {
                                        const isAssigned = territoryAssignments.some(a => a.territoryId === territory.id);
                                        const isSelected = selectedId === territory.id;

                                        return (
                                            <path
                                                key={`${territory.id}-${idx}`}
                                                d={territory.d}
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    setSelectedId(territory.id);
                                                }}
                                                onMouseEnter={() => setHoveredId(territory.id)}
                                                onMouseLeave={() => setHoveredId(null)}
                                                vectorEffect="non-scaling-stroke"
                                                className={`transition-all duration-150 outline-none cursor-pointer ${
                                                    isSelected 
                                                        ? 'fill-primary stroke-gray-900 stroke-[2.5px]' 
                                                        : isAssigned 
                                                            ? 'fill-orange-400 stroke-gray-900 stroke-[1.2px] hover:fill-orange-500' 
                                                            : 'fill-white stroke-gray-300 stroke-[0.5px] hover:fill-gray-100 hover:stroke-gray-500'
                                                }`}
                                            >
                                                <title>{territory.name}</title>
                                            </path>
                                        );
                                    })}
                                </svg>
                            </div>
                        )}
                    </div>
                </div>

                {/* Sidebar Info */}
                <aside className="w-full lg:w-[400px] shrink-0 flex flex-col gap-4">
                    <div className="bg-white rounded-xl border border-gray-200 shadow-sm p-6 flex flex-col flex-1 overflow-hidden">
                        {selectedTerritory ? (
                            <div className="space-y-6 animate-in slide-in-from-right-4 duration-300 flex flex-col h-full">
                                <div className="flex items-center gap-5">
                                    <div className="relative shrink-0">
                                        <img 
                                            src={getFlagUrl(selectedTerritory.id)} 
                                            alt={selectedTerritory.id} 
                                            className="w-24 h-16 rounded-lg shadow-xl border-2 border-white object-cover transition-transform hover:scale-105"
                                            onError={(e) => (e.currentTarget.style.display = 'none')}
                                        />
                                        <div className="absolute -bottom-2 -right-2 bg-gray-900 text-white px-2 py-1 rounded-md text-[9px] font-black uppercase shadow-lg">
                                            {selectedTerritory.id.length <= 3 ? selectedTerritory.id : 'ISO'}
                                        </div>
                                    </div>
                                    <div className="min-w-0">
                                        <h2 className="text-3xl font-black text-gray-900 tracking-tighter truncate leading-none uppercase italic">
                                            {selectedTerritory.name}
