                                                <UserAvatar user={ambassador} className="w-16 h-16 border-2 border-primary shadow-lg" />
                                                <div className="min-w-0">
                                                    <Link to={`/u/${ambassador.username}`} className="font-black text-2xl hover:text-primary transition-colors block truncate tracking-tighter">
                                                        u/{ambassador.username}
                                                    </Link>
                                                    <div className="flex items-center gap-1.5 mt-1">
                                                        <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
                                                        <p className="text-[9px] text-gray-400 font-black uppercase tracking-widest">Sede Assegnata</p>
                                                    </div>
                                                </div>
                                            </div>

                                            <div className="flex gap-2 relative z-10">
                                                <Link to={`/u/${ambassador.username}`} className="flex-1 bg-white text-gray-900 font-black py-3 rounded-xl text-[10px] text-center hover:bg-primary hover:text-white transition-all uppercase tracking-widest">Dossier Profilo</Link>
                                                <Link to={`/messages/${ambassador.username}`} className="px-4 bg-primary text-white rounded-xl hover:bg-orange-600 transition-all flex items-center justify-center shadow-lg">
                                                    <MessageIcon className="w-5 h-5" />
                                                </Link>
                                            </div>
                                        </div>
                                    ) : (
                                        <div className="bg-gray-50 border-2 border-dashed border-gray-200 rounded-2xl p-10 text-center group hover:border-primary/30 transition-colors">
                                            <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center mx-auto mb-4 border border-gray-100 shadow-sm text-gray-300 group-hover:text-primary transition-colors">
                                                <PlusIcon className="w-6 h-6" />
                                            </div>
                                            <p className="text-[12px] font-black text-gray-400 uppercase tracking-widest">Nessuna Nomina</p>
                                            <p className="text-[10px] text-gray-400 mt-2 font-medium">Sede diplomatica attualmente vacante.</p>
                                        </div>
                                    )}
                                </div>

                                {currentUser && isAdmin(currentUser.id) && (
                                    <div className="pt-6 mt-auto border-t border-gray-100">
                                        <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest mb-3">Assegnazione Incarichi Admin</label>
