                                                        >
                                                            <UserAvatar user={user} className="w-8 h-8 group-hover/u:border-white transition-all shadow-sm" />
                                                            <span className="font-bold text-sm">u/{user.username}</span>
                                                        </button>
                                                    ))}
                                                </div>
                                            )}
                                        </div>
                                        {ambassador && (
                                            <button 
                                                onClick={() => handleAssign('')}
                                                className="w-full mt-4 text-[10px] font-black text-red-500 hover:text-red-700 uppercase py-3 border-2 border-transparent hover:border-red-50 rounded-xl transition-all tracking-widest"
                                            >
                                                Revoca Ambasciatore
                                            </button>
                                        )}
                                    </div>
                                )}
                            </div>
                        ) : (
                            <div className="flex-1 flex flex-col items-center justify-center text-center p-12 opacity-50 select-none">
                                <div className="w-24 h-24 bg-gray-50 rounded-full flex items-center justify-center mb-8 border-2 border-gray-100 shadow-inner">
                                    <svg className="w-12 h-12 text-gray-200" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 20l-5.447-2.724A2 2 0 013 15.487V6a2 2 0 011.106-1.789l5.447-2.724a2 2 0 011.894 0l5.447 2.724A2 2 0 0118 6v9.487a2 2 0 01-1.106 1.789L11.447 20a2 2 0 01-1.894 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 3v17M13 3v17" /></svg>
