            // Sorgente garantita via CDN jsDelivr (CORS-friendly)
            const response = await fetch('https://cdn.jsdelivr.net/npm/@amcharts/amcharts4-geodata@4.1.19/dist/svg/worldLow.svg');
            if (!response.ok) throw new Error(`HTTP Error: ${response.status}`);

            const svgText = await response.text();
            const parser = new DOMParser();
            const doc = parser.parseFromString(svgText, 'image/svg+xml');
            const svgEl = doc.querySelector('svg');

            if (svgEl && svgEl.getAttribute('viewBox')) {
                setViewBox(svgEl.getAttribute('viewBox')!);
            }

            const paths = Array.from(doc.querySelectorAll('path'));
            const extractedPaths: MapPath[] = paths.map((p, index) => {
                const attrId = p.getAttribute('id') || '';
                // Alcuni SVG usano "title", altri "name", altri "aria-label"
                const attrTitle = p.getAttribute('title') || p.getAttribute('name') || p.getAttribute('aria-label') || '';

                let finalName = attrTitle;

                // Conversione ISO 3166-1 alpha-2 se disponibile
                if (attrId && attrId.length === 2) {
                    try {
                        const translated = regionNames.of(attrId.toUpperCase());
                        if (translated) finalName = translated;
                    } catch (e) {
                        finalName = attrTitle || attrId;
                    }
                }

                // Fallback di emergenza per nomi vuoti o tecnici (es: p-90)
                if (!finalName || /^[pP]-\d+$/.test(finalName) || !isNaN(Number(finalName))) {
                    finalName = attrTitle || `Territorio ${attrId || index + 1}`;
                }

                return {
                    id: attrId || `area-${index}`,
                    d: p.getAttribute('d') || '',
                    name: finalName
                };
            }).filter(p => p.d);

            setMapPaths(extractedPaths);
            setIsLoading(false);
        } catch (err) {
            console.error('Map Load Fail:', err);
            setError('Impossibile caricare i dati SVG dalla rete. Verifica la connessione.');
            setIsLoading(false);
        }
    };

    useEffect(() => {
        fetchMap();
    }, [regionNames]);

    // Navigazione: Drag & Keys
    useEffect(() => {
        const container = scrollContainerRef.current;
        if (!container) return;

        const handleKeyDown = (e: KeyboardEvent) => {
            if (document.activeElement?.tagName === 'INPUT') return;
            const step = 80;
            if (e.key === 'ArrowUp') container.scrollBy(0, -step);
