    const regionNames = useMemo(() => new Intl.DisplayNames(['it'], { type: 'region' }), []);

    const fetchMap = async () => {
        setIsLoading(true);
        setError(null);
        try {
            // Puntiamo ora al file locale caricato in Assets/Images/
            // Utilizziamo un fallback al CDN se il file locale non è ancora servito correttamente
            let response = await fetch('/Assets/Images/worldMap.svg');

            // Se il file locale è vuoto o non trovato (es. 404), torniamo al CDN garantito per non rompere l'app
            if (!response.ok) {
                response = await fetch('https://cdn.jsdelivr.net/npm/@amcharts/amcharts4-geodata@4.1.19/dist/svg/worldLow.svg');
            }

            if (!response.ok) throw new Error(`Errore caricamento: ${response.status}`);

            const svgText = await response.text();
            const parser = new DOMParser();
            const doc = parser.parseFromString(svgText, 'image/svg+xml');
            const svgEl = doc.querySelector('svg');

            if (svgEl && svgEl.getAttribute('viewBox')) {
                setViewBox(svgEl.getAttribute('viewBox')!);
            }

            const paths = Array.from(doc.querySelectorAll('path'));
            const extractedPaths: MapPath[] = paths.map((p, index) => {
                const attrId = p.getAttribute('id') || '';
                const attrTitle = p.getAttribute('title') || p.getAttribute('name') || p.getAttribute('aria-label') || '';

                let finalName = attrTitle;

                if (attrId && attrId.length === 2) {
                    try {
                        const translated = regionNames.of(attrId.toUpperCase());
                        if (translated) finalName = translated;
                    } catch (e) {
                        finalName = attrTitle || attrId;
                    }
                }

                if (!finalName || /^[pP]-\d+$/.test(finalName) || !isNaN(Number(finalName))) {
                    finalName = attrTitle || `Territorio ${attrId || index + 1}`;
                }

                return {
                    id: attrId || `area-${index}`,
                    d: p.getAttribute('d') || '',
                    name: finalName
                };
            }).filter(p => p.d);

            setMapPaths(extractedPaths);
            setIsLoading(false);
